procedure.text:
create procedure [LeadUtmBinding] (@source nvarchar(2000), @medium nvarchar(2000), @campaign nvarchar(2000)) as begin UPDATE Lead SET Lead.MarketingGroup = (SELECT TOP 1 mg.Id FROM MarketingGroup mg LEFT JOIN MarketingTag mt ON mt.MarketingObject = mg.Id WHERE mt.Name = Lead.UtmSource) WHERE (@source = '' OR Lead.UtmSource = @source) AND (@medium = '' OR Lead.UtmMedium = @medium) AND (@campaign = '' OR Lead.UtmCampaign = @campaign);
UPDATE Lead SET Lead.MarketingActivity = (SELECT TOP 1 ma.Id FROM MarketingActivity ma LEFT JOIN MarketingTag mt ON mt.MarketingObject = ma.Id WHERE mt.Name = Lead.UtmMedium AND ma.MarketingGroup = Lead.MarketingGroup) WHERE (@source = '' OR Lead.UtmSource = @source) AND (@medium = '' OR Lead.UtmMedium = @medium) AND (@campaign = '' OR Lead.UtmCampaign = @campaign);
UPDATE Lead SET Lead.MarketingEffect = (SELECT TOP 1 me.Id FROM MarketingEffect me LEFT JOIN MarketingTag mt ON mt.MarketingObject = me.Id WHERE mt.Name = Lead.UtmCampaign AND me.MarketingActivity = Lead.MarketingActivity) WHERE (@source = '' OR Lead.UtmSource = @source) AND (@medium = '' OR Lead.UtmMedium = @medium) AND (@campaign = '' OR Lead.UtmCampaign = @campaign); end

CREATE procedure [MarketingGroupRecalc] (@group bigint) as BEGIN UPDATE mb SET DirtyLeadCount = (SELECT COUNT(Id) FROM Lead WHERE MarketingEffect = mb.Id), CleanLeadCount = (SELECT COUNT(Id) FROM Lead WHERE MarketingEffect = mb.Id AND IsDeleted <> 1 AND Status <> 4), AcceptedLeadCount = (SELECT COUNT(Id) FROM Lead WHERE MarketingEffect = mb.Id AND IsDeleted <> 1 AND Status in (1,2,3)), QualifiedLeadCount = (SELECT COUNT(Id) FROM Lead WHERE MarketingEffect = mb.Id AND IsDeleted <> 1 AND Status in (2)) FROM MarketingEffect me LEFT JOIN MarketingBase mb ON mb.Id = me.Id LEFT JOIN MarketingActivity ma ON ma.Id = me.MarketingActivity WHERE ma.MarketingGroup = @group;
UPDATE mb SET DirtyLeadCount = (SELECT COUNT(Id) FROM Lead WHERE MarketingActivity = mb.Id), CleanLeadCount = (SELECT COUNT(Id) FROM Lead WHERE MarketingActivity = mb.Id AND IsDeleted <> 1 AND Status <> 4), AcceptedLeadCount = (SELECT COUNT(Id) FROM Lead WHERE MarketingActivity = mb.Id AND IsDeleted <> 1 AND Status in (1,2,3)), QualifiedLeadCount = (SELECT COUNT(Id) FROM Lead WHERE MarketingActivity = mb.Id AND IsDeleted <> 1 AND Status in (2)) FROM MarketingActivity ma LEFT JOIN MarketingBase mb ON mb.Id = ma.Id WHERE ma.MarketingGroup = @group;
UPDATE mb SET DirtyLeadCount = (SELECT COUNT(Id) FROM Lead WHERE MarketingGroup = mb.Id), CleanLeadCount = (SELECT COUNT(Id) FROM Lead WHERE MarketingGroup = mb.Id AND IsDeleted <> 1 AND Status <> 4), AcceptedLeadCount = (SELECT COUNT(Id) FROM Lead WHERE MarketingGroup = mb.Id AND IsDeleted <> 1 AND Status in (1,2,3)), QualifiedLeadCount = (SELECT COUNT(Id) FROM Lead WHERE MarketingGroup = mb.Id AND IsDeleted <> 1 AND Status in (2)) FROM MarketingBase mb WHERE mb.Id = @group; END

create procedure [UpdateCategoryPermissions]
AS begin
declare @insCounter bigint, @insStartId bigint, @insEndId bigint; declare @usermask bigint set @usermask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55
declare @PermissionRoleTypeResponsible uniqueidentifier = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15';
declare @CRMContractorCreateElementPermissionId uniqueidentifier= '44ED88D4-A466-4fed-B194-B8288560CB48'; declare @CRMContractorIssuancePermissionId uniqueidentifier= '1CD25727-7CE6-443c-84BD-7975822C79E6'; declare @ViewContractorPermissionId uniqueidentifier= '9219C9AB-7E68-47B1-8939-FF6FC4439DA0'; declare @EditContractorPermissionId uniqueidentifier= '8C932B94-2F9C-488E-A36F-949A11C9741E'; declare @FullContractorPermissionId uniqueidentifier= 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5';
declare @CRMContactCreateElementPermissionId uniqueidentifier= 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5'; declare @CRMContactIssuancePermissionId uniqueidentifier= '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1'; declare @ViewContactPermissionId uniqueidentifier= '3626682F-B657-419E-9A8E-392C14ABE455'; declare @EditContactPermissionId uniqueidentifier= 'ABC752AD-3623-4F14-A47F-121999890D2C'; declare @CRMContactFullAccessPermissionId uniqueidentifier= '76B481D5-2E07-4417-9098-A57DE879FA56';
declare @CRMSaleIssuancePermissionId uniqueidentifier= 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA'; declare @ViewSalePermissionId uniqueidentifier= 'AAE16346-B0E6-4949-ACAB-0914C573DE55'; declare @EditSalePermissionId uniqueidentifier= 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74'; declare @CRMSaleCreateElementPermissionId uniqueidentifier= '7DB77821-D6D3-4dd2-AD1B-798330506ADC'; declare @FullSalePermissionId uniqueidentifier= 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';
declare @CRMInpaymentCreateElementPermissionId uniqueidentifier= 'D130BB5F-6A26-4e37-B62C-F3B443E3BF53'; declare @ViewInpaymentPermissionId uniqueidentifier= '837FF0F3-03A7-4A17-86EA-A72B3AB4886B'; declare @EditInpaymentPermissionId uniqueidentifier= 'E23802D7-F3B5-431E-A72E-7133C3C9343F'; declare @CRMInpaymentIssuanceElementPermissionId uniqueidentifier= 'ACF5606C-B566-426b-BAEC-E74061095BEB'; declare @CRMInpaymentFullAccessPermissionId uniqueidentifier= 'A27A46F9-BCD8-4e82-AE49-E58675DE52D7';
declare @CRMRelationshipCreateElementPermissionId uniqueidentifier= 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2'; declare @ViewRelationshipPermissionId uniqueidentifier= '186D4CC4-6924-4848-93AC-6D8DE389CB08'; declare @EditRelationshipPermissionId uniqueidentifier= '0B980531-D097-4EC1-8616-56E6AB15770E'; declare @CRMRelationshipIssuanceElementPermissionId uniqueidentifier= '679876A7-8882-43d4-8FC2-3E7C9DB58ADB'; declare @CRMRelationshipFullAccessPermissionId uniqueidentifier= '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';
declare @ViewLeadPermissionId uniqueidentifier= 'C660E4B4-03BF-4315-9600-5086E47653B4'; declare @EditLeadPermissionId uniqueidentifier= 'AE298CD3-A16A-4B55-ACFC-545E4A0EBD48'; declare @CRMLeadCreateElementPermissionId uniqueidentifier= '643FE44B-8192-4615-B853-106CD6F09EDE'; declare @CRMLeadFullAccessPermissionId uniqueidentifier= '90BE803C-7857-4F2D-A8B4-129264504101'; declare @CRMLeadIssuanceElementPermissionId uniqueidentifier= 'E70A9AD1-80B2-4435-80E9-EF8E14B974CE';
declare @PermissionRoleTypeInforms uniqueidentifier = '21888C0C-8BCA-4B26-AF13-4C497EECCED6'; declare @PermissionRoleAuthor uniqueidentifier = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92';
declare @NullUid uniqueidentifier = '00000000-0000-0000-0000-000000000000'; declare @PermissionRoleTypeParticipantWork uniqueidentifier = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386'; declare @adminUid uniqueidentifier='F0E949BF-4DA4-4C02-B04C-CA61964B4FE8'; declare @adminUser bigint=0; declare @defaultCategory bigint=0; declare @defaultTemplLeadCategory bigint=0; declare @defaultTemplCategory bigint=0;
select @adminUser=Id from [User] where Uid=@adminUid; select @defaultCategory=Id, @defaultTemplCategory=CONTAINERCONTRACTORPERMISSIO, @defaultTemplLeadCategory=CONTAINERLEADPERMISSION from Category where Uid='B53287AB-211B-4498-A054-2776C4D270AD'
truncate table ContractorPersonPermissionDel truncate table ContractorPersonPermissionUpd truncate table ContactPersonPermissionDel truncate table ContactPersonPermissionUpd truncate table SalePersonPermissionUpd truncate table SalePersonPermissionDel truncate table LeadPersonPermissionUpd truncate table LeadPersonPermissionDel truncate table RelationshipPersonPermissionDel; truncate table RelationshipPersonPermissionUpd;
-- делаем копию рабочей таблицы контрагентов truncate table log_cont
truncate table ContractorPersonPermTmp INSERT INTO [ContractorPersonPermTmp] ([Id] ,[Uid] ,[PermissionId] ,[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[InheritedFromNumber]) select [Id], [Uid] ,[PermissionId] ,[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId]a ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[InheritedFromNumber] from ContractorPersonPermission where [User] is not null or [Group] is not null or [OrganizationItemPosition] is not null or OrganizationItemEmployee is not null;
-- Забрать привилегию из контрагента insert into ContractorPersonPermissionDel(ContractorId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contractor,UserSecuritySetCacheId,OrganizationItemPosition,Child) select cc.Id as ContractorId,cc.PermissionId,cc.[User],cc.[Group],cc.PermissionRole,cc.OrganizationItemEmployee,cc.Contractor,cc.UserSecuritySetCacheId,cc.OrganizationItemPosition, cc.ch from ( select *, (select count(1) from TemplateContractorPermission t where DelPermission is not null and DelPermission = 1 and t.PermissionId=c.PermissionId and t.UserSecuritySetCacheId=c.ussc and t.PermissionRole=c.PermissionRole ) ch from (select *, case PermissionRole when @PermissionRoleAuthor then (@adminUser|@usermask) when @PermissionRoleTypeResponsible then (@adminUser|@usermask) else UserSecuritySetCacheId end ussc from ContractorPersonPermTmp) c where c.InheritedFromNumber > 0 ) cc where ch > 0
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into ContractorPersonPermissionDel ([ContractorId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Contractor],[Child]) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Contractor] ,(select count(1) from TemplateContractorPermission t where delpermission is not null and delpermission = 1 and c.PermissionId=t.permissionId and c.PermissionRole=t.PermissionRole and [User]=@adminUser) from ContractorPersonPermTmp c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeParticipantWork and exists ( select [ContractorId] from ContractorPersonPermissionDel t where PermissionRole =@PermissionRoleTypeParticipantWork and c.PermissionId=t.permissionId and c.Contractor=t.Contractor )
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into ContractorPersonPermissionDel ([ContractorId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Contractor],[Child]) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Contractor] ,(select count(1) from TemplateContractorPermission t where delpermission is not null and delpermission = 1 and c.PermissionId=t.permissionId and c.PermissionRole=t.PermissionRole and [User]=@adminUser) from ContractorPersonPermTmp c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeInforms and exists ( select [ContractorId] from ContractorPersonPermissionDel t where PermissionRole =@PermissionRoleTypeInforms and c.PermissionId=t.permissionId and c.Contractor=t.Contractor )
update c set c.InheritedFromNumber=c.InheritedFromNumber-ct.Child from ContractorPersonPermTmp c join ContractorPersonPermissionDel ct on ct.ContractorId=c.Id where ct.ContractorId=c.Id
-- Добавить номера измененных контрагентов в темповую таблицу для возврата insert into CheckContractorCategTmp (Id) select Contractor from ContractorPersonPermissionDel
delete from ContractorPersonPermissionDel; insert into ContractorPersonPermissionDel(ContractorId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contractor,UserSecuritySetCacheId,OrganizationItemPosition,Child,InheritedFromNumber) select Id ContractorId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contractor,UserSecuritySetCacheId,OrganizationItemPosition,1,InheritedFromNumber from ContractorPersonPermTmp where InheritedFromNumber<=0
-- Грохнуть пустые пермишены в контрагенте
delete from ContractorPersonPermTmp where InheritedFromNumber<=0
-- Добавить привилегию в контагента insert into ContractorPersonPermissionUpd([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contractor,UserSecuritySetCacheId,OrganizationItemPosition,Ins,Child) select - 1 as [Id],cc.PermissionId,cc.[User],cc.[Group],cc.PermissionRole,cc.OrganizationItemEmployee,cc.Contractor Contractor,cc.UserSecuritySetCacheId,cc.OrganizationItemPosition,0 Ins, cc.ch from ( select c.*, (select count(1) from TemplateContractorPermission t where DelPermission != 1 and AddPermission = 1 and t.PermissionId=c.PermissionId and t.UserSecuritySetCacheId=c.ussc and t.PermissionRole=c.PermissionRole ) ch from (select *, case PermissionRole when @PermissionRoleAuthor then (@adminUser|@usermask) when @PermissionRoleTypeResponsible then (@adminUser|@usermask) else UserSecuritySetCacheId end ussc from ContractorPersonPermTmp) c inner join Contractor ca on ca.id = c.Contractor where c.InheritedFromNumber > 0 and ca.InheritPermissions=1 ) cc where ch > 0
select @insCounter=isnull(max([Id]),0) from ContractorPersonPermissionUpd
/*Добавить пермишены реальных пользователей для исполнителей*/ insert into ContractorPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,0 [Ins],c.[Child] from [M_Contractor_ParticipantWork] m left join ContractorPersonPermissionUpd c on m.Parent=c.Contractor where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and [Ins]=0 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Contractor],[Ins],c.[Child]
select @insCounter=isnull(max([Id]),0) from ContractorPersonPermissionUpd
insert into ContractorPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,0 [Ins],c.[Child] from [M_Contractor_Informs] m left join ContractorPersonPermissionUpd c on m.Parent=c.Contractor where PermissionRole in (@PermissionRoleTypeInforms) and [User]=@adminUser and [Ins]=0 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Contractor],c.[Child]
-- Добавить привилегию в контагента 1
update c set c.InheritedFromNumber=c.InheritedFromNumber+t.Child from ContractorPersonPermTmp c join ContractorPersonPermissionUpd t on t.PermissionId=c.PermissionId and t.UserSecuritySetCacheId=c.UserSecuritySetCacheId
-- Добавить недостающие привилегии в контрагента insert into ContractorPersonPermissionUpd (id,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contractor,UserSecuritySetCacheId,OrganizationItemPosition,Ins,Child) select ROW_NUMBER() over (order by c.[Id]) -1,t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition,1,count(1) as Child from Contractor c left join M_Contractor_Categories cc on c.Id=ContractorId -- вытащили категорию в которые входит контрагент left join TemplateContractorPermission t on AddPermission = 1 and DelPermission!=1 -- взяли пермишены которые надо обновить из контейнера left outer join ContractorPersonPermTmp cp on cp.Contractor=c.Id and cp.PermissionId=t.PermissionId and case cp.PermissionRole when @PermissionRoleAuthor then (@adminUser|@usermask) when @PermissionRoleTypeResponsible then (@adminUser|@usermask) ELSE cp.userSecuritySetCacheId end=t.userSecuritySetCacheId and cp.PermissionRole=t.PermissionRole and cp.InheritedFromNumber > 0 left join Category ca on ca.ContainerContractorPermissio=t.ContainerContractor -- вытащили категорию в которую входит пермишен из контейнера where (cc.CategoryId =ca.Id or (cc.CategoryId is null and t.containercontractor=@defaultTemplCategory) ) -- соединили категории из контейнера и из контрагента and c.InheritPermissions=1 and cp.Contractor is null group by t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition
select @insCounter=isnull(max([Id]),0) from ContractorPersonPermissionUpd
/*Добавить пермишены реальных пользователей для исполнителей*/ insert into ContractorPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,1 [Ins],c.[Child] from [M_Contractor_ParticipantWork] m left join ContractorPersonPermissionUpd c on m.Parent=c.Contractor where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and [Ins]=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Contractor],[Ins],c.[Child]
select @insCounter=isnull(max([Id]),0) from ContractorPersonPermissionUpd
insert into ContractorPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,1 [Ins],c.[Child] from [M_Contractor_Informs] m left join ContractorPersonPermissionUpd c on m.Parent=c.Contractor where PermissionRole in (@PermissionRoleTypeInforms) and [User]=@adminUser and [Ins]=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Contractor],c.[Child]
-- Добавить номера измененных контрагентов в темповую таблицу для возврата insert into CheckContractorCategTmp (Id) select Contractor from ContractorPersonPermissionUpd
select @insCounter=count(1) from ContractorPersonPermissionUpd EXECUTE [G_GenId] 'ContractorPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into ContractorPersonPermTmp ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contractor,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id]-1 as Id, t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Contractor,t.UserSecuritySetCacheId,NEWID() as Uid,Child as InheritedFromNumber,t.OrganizationItemPosition from ContractorPersonPermissionUpd t where Ins=1
/*Перезаписать реальных пользователей в ответственных */ update ContractorPersonPermTmp set [User]= (select (case when Responsible is not null then Responsible else @adminUser end) from Contractor con where con.[Id]=Contractor), [UserSecuritySetCacheId]= (select ((case when Responsible is not null then Responsible else @adminUser end)|@usermask) from Contractor con where con.[Id]=Contractor) where PermissionRole=@PermissionRoleTypeResponsible
/*Перезаписать реальных пользователей в ответственных */ update ContractorPersonPermTmp set [User]= (select [CreationAuthor] from Contractor con where con.[Id]=Contractor), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Contractor con where con.[Id]=Contractor) where PermissionRole=@PermissionRoleAuthor
-- делаем копию прав контактов
truncate table [ContactPersonPermTmp];
INSERT INTO [ContactPersonPermTmp] ([Id],[Uid] ,[PermissionId] ,[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contact] ,[InheritedFromNumber]) select [Id], [Uid] ,[PermissionId] ,[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contact] ,[InheritedFromNumber] from [ContactPersonPermission]
-- Забрать привилегию из контактов insert into ContactPersonPermissionDel(ContactId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contact,UserSecuritySetCacheId,InheritedFromNumber,OrganizationItemPosition,Child) select cc.Id as ContactId,cc.PermissionId,cc.[User],cc.[Group],cc.PermissionRole,cc.OrganizationItemEmployee,cc.Contact,cc.UserSecuritySetCacheId,cc.InheritedFromNumber,cc.OrganizationItemPosition, cc.ch from ( select c.*, (select count(1) from ContractorPersonPermissionDel t where c.PermissionId= CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @CRMContactFullAccessPermissionId
ELSE t.PermissionId END and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then (con.CreationAuthor|@usermask) when @PermissionRoleTypeResponsible then (contr.Responsible|@usermask) ELSE t.userSecuritySetCacheId end and c.PermissionRole=t.PermissionRole ) ch from ContactPersonPermTmp c inner join Contact con on c.Contact=con.Id inner join Contractor contr on con.Contractor = c.id where c.InheritedFromNumber > 0 ) cc where ch > 0
update c set c.InheritedFromNumber=c.InheritedFromNumber-1 from ContactPersonPermTmp c join ContactPersonPermissionDel ct on ct.ContactId=c.Id where ct.ContactId=c.Id
-- Грохнуть пустые контакты delete from ContactPersonPermTmp where InheritedFromNumber=0
-- Добавить привилегии к контактам 1 insert into ContactPersonPermissionUpd (ContactId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contact,UserSecuritySetCacheId,OrganizationItemPosition,Ins) select c.Id, c.PermissionId,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Contact Contact,c.UserSecuritySetCacheId,c.OrganizationItemPosition,0 Ins from ContactPersonPermTmp c inner join Contact con on con.Id = c.Contact where c.InheritedFromNumber > 0 and con.InheritPermissions = 1 and exists (select 1 from ContractorPersonPermissionUpd t where CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @CRMContactFullAccessPermissionId ELSE t.PermissionId END = c.PermissionId and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then (con.CreationAuthor|@usermask) ELSE t.userSecuritySetCacheId end and c.PermissionRole=t.PermissionRole )
update c set c.InheritedFromNumber=c.InheritedFromNumber+1 from ContactPersonPermTmp c where c.Id in (select ct.ContactId from ContactPersonPermissionUpd ct )
-- Добавить недостающие привилегии к контактам insert into ContactPersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contact,UserSecuritySetCacheId,OrganizationItemPosition,Ins) select ROW_NUMBER() over (order by t.[Id]) - 1, CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @CRMContactFullAccessPermissionId ELSE t.PermissionId END ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Contact,t.UserSecuritySetCacheId,t.OrganizationItemPosition,1 Ins from Contact c left join ContractorPersonPermissionUpd t on t.Contractor=c.Contractor left outer join ContactPersonPermTmp cp on cp.Contact=c.Id and cp.InheritedFromNumber > 0 and CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @CRMContactFullAccessPermissionId ELSE t.PermissionId END = cp.PermissionId and cp.UserSecuritySetCacheId=case cp.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Contact] con where con.[Id]=cp.[Contact])|@usermask) ELSE t.userSecuritySetCacheId end and cp.PermissionRole=t.PermissionRole where t.Contractor is not null and cp.Contact is null and c.InheritPermissions=1
/*Перезаписать реальных пользователей в ответственных */ update ContactPersonPermissionUpd set [User]= (select (case when contr.Responsible is not null then contr.Responsible else @adminUser end) from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact), [UserSecuritySetCacheId]= (select ((case when contr.Responsible is not null then contr.Responsible else @adminUser end)|@usermask) from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact) where PermissionRole=@PermissionRoleTypeResponsible
/*Перезаписать реальных пользователей в ответственных */ update ContactPersonPermissionUpd set [User]= (select [CreationAuthor] from Contact con where con.[Id]=Contact), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Contact con where con.[Id]=Contact) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from ContactPersonPermissionUpd EXECUTE [G_GenId] 'ContactPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into ContactPersonPermTmp ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contact,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id]-1 as Id,t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Contact,t.UserSecuritySetCacheId,NEWID(),count(1) ,t.OrganizationItemPosition from ContactPersonPermissionUpd t where Ins=1 group by [Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contact,UserSecuritySetCacheId,Uid,OrganizationItemPosition
-- делаем копию прав сделок truncate table [SalePersonPermissionTmp] INSERT INTO [SalePersonPermissionTmp] ([Id],[Uid] ,[PermissionId] ,[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Sale] ,[InheritedFromNumber]) select [Id], [Uid] ,[PermissionId] ,[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Sale] ,[InheritedFromNumber] from [SalePersonPermission]
-- Забрать привилегию из Сделок
insert into salePersonPermissionDel(saleId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,sale,UserSecuritySetCacheId,InheritedFromNumber,OrganizationItemPosition,Child) select cc.Id as saleId,cc.PermissionId,cc.[User],cc.[Group],cc.PermissionRole,cc.OrganizationItemEmployee,cc.sale,cc.UserSecuritySetCacheId,cc.InheritedFromNumber,cc.OrganizationItemPosition, cc.ch from ( select c.*, (select count(1) from ContractorPersonPermissionDel t where c.PermissionId= CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMSaleCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMSaleIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewSalePermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditSalePermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @FullSalePermissionId
ELSE t.PermissionId END and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then (sale.Author|@usermask) when @PermissionRoleTypeResponsible then (sale.Responsible|@usermask) ELSE t.userSecuritySetCacheId end and c.PermissionRole=t.PermissionRole ) ch from [SalePersonPermissionTmp] c inner join [Sale] sale on c.Sale=sale.Id where c.InheritedFromNumber > 0 ) cc where ch > 0
update c set c.InheritedFromNumber=c.InheritedFromNumber-1 from SalePersonPermissionTmp c join SalePersonPermissionDel ct on ct.SaleId=c.Id where ct.SaleId=c.Id
-- Грохнуть пустые привилегии сделок delete from SalePersonPermissionTmp where InheritedFromNumber<=0
-- Добавить привилегии к сделкам
insert into SalePersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Sale,UserSecuritySetCacheId,OrganizationItemPosition,Ins) select - 1 as [Id],c.PermissionId,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Sale Sale,UserSecuritySetCacheId,OrganizationItemPosition,0 Ins from SalePersonPermissionTmp c inner join Sale sale on sale.Id = c.Sale where c.InheritedFromNumber > 0 and sale.InheritPermissions=1 and exists (select 1 from ContractorPersonPermissionUpd t where CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMSaleCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMSaleIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewSalePermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditSalePermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @FullSalePermissionId ELSE t.PermissionId END =c.PermissionId and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then (sale.[Author]|@usermask) when @PermissionRoleTypeResponsible then (sale.Responsible|@usermask) ELSE t.userSecuritySetCacheId end and c.PermissionRole=t.PermissionRole )
update c set c.InheritedFromNumber=1 from SalePersonPermissionTmp c join SalePersonPermissionUpd ct on ct.Sale=c.Id where ct.Sale=c.Id
-- Добавить недостающие привилегии к сделкам insert into SalePersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Sale,UserSecuritySetCacheId,OrganizationItemPosition,Ins) select ROW_NUMBER() over (order by t.[Id]) -1, CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMSaleCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMSaleIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewSalePermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditSalePermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @FullSalePermissionId ELSE t.PermissionId END ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Sale,t.UserSecuritySetCacheId,t.OrganizationItemPosition,1 Ins from Sale c left join ContractorPersonPermissionUpd t on t.Contractor=c.Contractor left outer join SalePersonPermissionTmp cp on cp.Sale=c.Id and cp.InheritedFromNumber > 0 and CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMSaleCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMSaleIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewSalePermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditSalePermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @FullSalePermissionId ELSE t.PermissionId END = cp.PermissionId and cp.UserSecuritySetCacheId=t.UserSecuritySetCacheId and cp.PermissionRole=t.PermissionRole where t.Contractor is not null and c.InheritPermissions=1 and cp.Sale is null
/*Перезаписать реальных пользователей в ответственных */ update SalePersonPermissionUpd set [User]= (select (case when con.Responsible is not null then con.Responsible else @adminUser end) from Sale con where con.[Id]=Sale), [UserSecuritySetCacheId]= (select ((case when con.Responsible is not null then con.Responsible else @adminUser end)|@usermask) from Sale con where con.[Id]=Sale)
where PermissionRole=@PermissionRoleTypeResponsible
/*Перезаписать реальных пользователей в ответственных */ update SalePersonPermissionUpd set [User]= (select [Author] from Sale s where s.[Id]=Sale), [UserSecuritySetCacheId]= (select (Author|@usermask) from Sale s where s.[Id]=Sale) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from SalePersonPermissionUpd EXECUTE [G_GenId] 'SalePersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into SalePersonPermissionTmp ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Sale,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id]-1 as Id,t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Sale,t.UserSecuritySetCacheId,NEWID(),count(1) ,t.OrganizationItemPosition from SalePersonPermissionUpd t where Ins=1 group by [Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Sale,UserSecuritySetCacheId,Uid,OrganizationItemPosition
-- делаем копию прав лидов
truncate table [LeadPersonPermissionTmp] INSERT INTO [LeadPersonPermissionTmp] ([Id],[Uid] ,[PermissionId] ,[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[InheritedFromNumber])
select [Id], [Uid] ,[PermissionId] ,[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[InheritedFromNumber] from [LeadPersonPermission] where [User] is not null or [Group] is not null or [OrganizationItemPosition] is not null or OrganizationItemEmployee is not null;
-- Забрать привилегию у лида insert into LeadPersonPermissionDel(LeadId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Lead,UserSecuritySetCacheId,InheritedFromNumber,OrganizationItemPosition,Child) select cc.Id as LeadId,cc.PermissionId,cc.[User],cc.[Group],cc.PermissionRole,cc.OrganizationItemEmployee,cc.Lead,cc.UserSecuritySetCacheId,cc.InheritedFromNumber,cc.OrganizationItemPosition, cc.ch from ( select *, (select count(1) from TemplateLeadPermission t where DelPermission is not null and DelPermission = 1 and t.PermissionId=c.PermissionId and t.UserSecuritySetCacheId=c.ussc and t.PermissionRole=c.PermissionRole ) ch from (select *, case PermissionRole when @PermissionRoleAuthor then (@adminUser|@usermask) when @PermissionRoleTypeResponsible then (@adminUser|@usermask) else UserSecuritySetCacheId end ussc from LeadPersonPermission) c where c.InheritedFromNumber > 0 ) cc where ch > 0
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into LeadPersonPermissionDel ([LeadId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Lead],[Child]) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Lead] ,(select count(1) from TemplateLeadPermission t where delpermission is not null and delpermission = 1 and c.PermissionId=t.permissionId and c.PermissionRole=t.PermissionRole and [User]=@adminUser) from LeadPersonPermissionTmp c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeParticipantWork and exists ( select [LeadId] from LeadPersonPermissionDel t where PermissionRole =@PermissionRoleTypeParticipantWork and c.PermissionId=t.permissionId and c.Lead=t.Lead )
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into LeadPersonPermissionDel ([LeadId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Lead],[Child]) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Lead] ,(select count(1) from TemplateLeadPermission t where delpermission is not null and delpermission = 1 and c.PermissionId=t.permissionId and c.PermissionRole=t.PermissionRole and [User]=@adminUser) from LeadPersonPermissionTmp c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeInforms and exists ( select [LeadId] from LeadPersonPermissionDel t where PermissionRole =@PermissionRoleTypeInforms and c.PermissionId=t.permissionId and c.Lead=t.Lead )
update c set c.InheritedFromNumber=c.InheritedFromNumber-ct.Child from LeadPersonPermissionTmp c join LeadPersonPermissionDel ct on ct.LeadId=c.Id where ct.LeadId=c.Id
-- Грохнуть пустые привилегии у лида
delete from LeadPersonPermissionDel; insert into LeadPersonPermissionDel(LeadId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Lead,UserSecuritySetCacheId,OrganizationItemPosition,Child,InheritedFromNumber) select Id LeadId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Lead,UserSecuritySetCacheId,OrganizationItemPosition,1,InheritedFromNumber from LeadPersonPermissionTmp where InheritedFromNumber<=0
delete from LeadPersonPermissionTmp where InheritedFromNumber<=0
-- Добавить привилегию в лида insert into LeadPersonPermissionUpd (LeadId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Lead,UserSecuritySetCacheId,t.OrganizationItemPosition,Ins,Child) select [Id],cc.PermissionId,cc.[User],cc.[Group],cc.PermissionRole,cc.OrganizationItemEmployee,cc.Lead Lead,cc.UserSecuritySetCacheId,cc.OrganizationItemPosition,0 Ins, cc.ch from ( select c.*, (select count(1) from TemplateLeadPermission t where AddPermission = 1 and DelPermission != 1 and t.PermissionId=c.PermissionId and t.UserSecuritySetCacheId=c.ussc and t.PermissionRole=c.PermissionRole ) ch from (select *, case PermissionRole when @PermissionRoleAuthor then (@adminUser|@usermask) when @PermissionRoleTypeResponsible then (@adminUser|@usermask) else UserSecuritySetCacheId end ussc from LeadPersonPermissionTmp) c inner join Lead ca on ca.id=c.Lead where c.InheritedFromNumber > 0 and ca.InheritPermissions = 1 ) cc where ch > 0
select @insCounter=isnull(max([Id]),0) from LeadPersonPermissionUpd
/*Добавить пермишены реальных пользователей для исполнителей*/ insert into LeadPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,0 [Ins],c.[Child] from [M_Lead_ParticipantWork] m left join LeadPersonPermissionUpd c on m.Parent=c.Lead where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and [Ins]=0 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Lead],[Ins],c.[Child]
select @insCounter=isnull(max([Id]),0) from LeadPersonPermissionUpd
insert into LeadPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,0 [Ins],c.[Child] from [M_Lead_Informs] m left join LeadPersonPermissionUpd c on m.Parent=c.Lead where PermissionRole in (@PermissionRoleTypeInforms) and [User]=@adminUser and [Ins]=0 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Lead],c.[Child]
update c set InheritedFromNumber=InheritedFromNumber+(select child from LeadPersonPermissionUpd ct where LeadId=c.Id) from LeadPersonPermissionTmp c where id in (select LeadId from LeadPersonPermissionUpd )
-- Добавить недостающие привилегии в лида
insert into LeadPersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Lead,UserSecuritySetCacheId,OrganizationItemPosition,Ins,Child) select ROW_NUMBER() over (order by c.[Id]) - 1, t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition,1,count(1) as Child from Lead c left join M_Lead_Categories cc on c.Id=LeadId -- вытащили категорию в которые входит контрагент left join TemplateLeadPermission t on AddPermission = 1 and DelPermission!=1 -- взяди мермишены которые надо обновить из контейнера left outer join LeadPersonPermissionTmp cp on cp.Lead=c.Id and cp.PermissionId=t.PermissionId and case cp.PermissionRole when @PermissionRoleAuthor then (@adminUser|@usermask) when @PermissionRoleTypeResponsible then (@adminUser|@usermask) ELSE cp.userSecuritySetCacheId end=t.userSecuritySetCacheId and cp.PermissionRole=t.PermissionRole and cp.InheritedFromNumber > 0 left join Category ca on ca.ContainerLeadPermission=t.ContainerLead -- выьащили категорию в которую входит пермишен из контейнера where (cc.CategoryId =ca.Id or (cc.CategoryId is null and t.CONTAINERLEAD=@defaultTemplLeadCategory) ) -- соединили категории из контейнера и из контрагента and c.InheritPermissions=1 and cp.Lead is null group by t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition
select @insCounter=isnull(max([Id]),0) from LeadPersonPermissionUpd
/*Добавить пермишены реальных пользователей для исполнителей*/ insert into LeadPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,1 [Ins],c.[Child] from [M_Lead_ParticipantWork] m left join LeadPersonPermissionUpd c on m.Parent=c.Lead where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and [Ins]=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Lead],[Ins],c.[Child]
select @insCounter=isnull(max([Id]),0) from LeadPersonPermissionUpd
insert into LeadPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,1 [Ins],c.[Child] from [M_Lead_Informs] m left join LeadPersonPermissionUpd c on m.Parent=c.Lead where PermissionRole in (@PermissionRoleTypeInforms) and [User]=@adminUser and [Ins]=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Lead],c.[Child]
