set @insStartId=0; select @insCounter=count(1) from LeadPersonPermissionUpd EXECUTE [G_GenId] 'LeadPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into LeadPersonPermissionTmp ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Lead,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id]-1 as Id, t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Lead,t.UserSecuritySetCacheId,NEWID(),Child as InheritedFromNumber ,t.OrganizationItemPosition from LeadPersonPermissionUpd t where Ins=1
/*Перезаписать реальных пользователей в ответственных */ update LeadPersonPermissionTmp set [User]= (select (case when con.Responsible is not null then con.Responsible else @adminUser end) from Lead con where con.[Id]=Lead), [UserSecuritySetCacheId]= (select ((case when con.Responsible is not null then con.Responsible else @adminUser end)|@usermask) from Lead con where con.[Id]=Lead) where PermissionRole=@PermissionRoleTypeResponsible
/*Перезаписать реальных пользователей в ответственных */ update LeadPersonPermissionTmp set [User]= (select [CreationAuthor] from Lead con where con.[Id]=Lead), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Lead con where con.[Id]=Lead) where PermissionRole=@PermissionRoleAuthor
truncate table RelationshipPersPermTmp INSERT INTO RelationshipPersPermTmp (Id ,Uid ,PermissionId ,[User] ,[Group] ,OrganizationItemPosition ,UserSecuritySetCacheId ,PermissionRole ,OrganizationItemEmployee ,Relationship ,InheritedFromNumber)
select Id, Uid ,PermissionId ,[User] ,[Group] ,OrganizationItemPosition ,UserSecuritySetCacheId ,PermissionRole ,OrganizationItemEmployee ,Relationship ,InheritedFromNumber from RelationshipPersonPermission where [User] is not null or [Group] is not null or [OrganizationItemPosition] is not null and OrganizationItemEmployee is not null;
-- Забрать привилегию у взаимоотношения из лида insert into RelationshipPersonPermissionDel (RelationshipId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,InheritedFromNumber,OrganizationItemPosition) select c.Id as RelationshipId,c.PermissionId,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Relationship,c.UserSecuritySetCacheId,c.InheritedFromNumber,c.OrganizationItemPosition from ( select c.*, case PermissionRole when @PermissionRoleAuthor then (r.CreationAuthor|@usermask) when @PermissionRoleTypeResponsible then (l.Responsible|@usermask) else UserSecuritySetCacheId end ussc from RelationshipPersPermTmp c inner join Relationship r on r.id=c.Relationship inner join Lead l on l.Id=r.Lead where c.InheritedFromNumber > 0 and r.Lead is not null ) c where exists ( SELECT 1 FROM (select distinct CASE WHEN PERMISSIONID = @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN PERMISSIONID=@CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipFullAccessPermissionId WHEN PERMISSIONID=@ViewLeadPermissionId THEN @ViewRelationshipPermissionId WHEN PERMISSIONID=@EditLeadPermissionId THEN @EditRelationshipPermissionId WHEN PERMISSIONID=@CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE PERMISSIONID end as permissionid, USERSECURITYSETCACHEID, PermissionRole from LeadPersonPermissionDel) t WHERE t.permissionid = c.PermissionId AND c.UserSecuritySetCacheId=t.USERSECURITYSETCACHEID AND c.PermissionRole =t.PERMISSIONROLE )
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into RelationshipPersonPermissionDel ([RelationshipId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship]) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship] from RelationshipPersPermTmp c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeParticipantWork and exists ( select [RelationshipId] from RelationshipPersonPermissionDel t where PermissionRole =@PermissionRoleTypeParticipantWork and c.PermissionId=t.permissionId and c.Relationship=t.Relationship )
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into RelationshipPersonPermissionDel ([RelationshipId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship]) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship]
from RelationshipPersPermTmp c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeInforms and exists ( select [RelationshipId] from RelationshipPersonPermissionDel t where PermissionRole =@PermissionRoleTypeInforms and c.PermissionId=t.permissionId and c.Relationship=t.Relationship )
update c set c.InheritedFromNumber=c.InheritedFromNumber-1 from RelationshipPersPermTmp c join RelationshipPersonPermissionDel ct on ct.RelationshipId=c.Id where ct.RelationshipId=c.Id
-- Грохнуть пустые привилегии сделок
delete from RelationshipPersPermTmp where InheritedFromNumber=0 truncate table RelationshipPersonPermissionDel
-- Забрать привилегию у взаимоотношения из контрагента insert into RelationshipPersonPermissionDel(RelationshipId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,InheritedFromNumber,OrganizationItemPosition) select c.Id as RelationshipId,c.PermissionId,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,Relationship,c.UserSecuritySetCacheId,c.InheritedFromNumber,c.OrganizationItemPosition from RelationshipPersPermTmp c inner join Relationship r on r.Id = c.Relationship inner join Contractor con on con.Id = r.Contractor where c.InheritedFromNumber > 0 and r.Contractor is not null and exists (select 1 from ContractorPersonPermissionDel t where CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END =c.PermissionId and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then (r.CreationAuthor|@usermask) when @PermissionRoleTypeResponsible then (con.Responsible|@usermask) ELSE t.userSecuritySetCacheId end and c.PermissionRole=t.PermissionRole )
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into RelationshipPersonPermissionDel ([RelationshipId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship]) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship] from RelationshipPersPermTmp c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeParticipantWork and exists ( select [RelationshipId] from RelationshipPersonPermissionDel t where PermissionRole =@PermissionRoleTypeParticipantWork and c.PermissionId=t.permissionId and c.Relationship=t.Relationship )
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into RelationshipPersonPermissionDel ([RelationshipId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship]) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship]
from RelationshipPersPermTmp c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeInforms and exists ( select [RelationshipId] from RelationshipPersonPermissionDel t where PermissionRole =@PermissionRoleTypeInforms and c.PermissionId=t.permissionId and c.Relationship=t.Relationship )
update c set c.InheritedFromNumber=c.InheritedFromNumber-1 from RelationshipPersPermTmp c join RelationshipPersonPermissionDel ct on ct.RelationshipId=c.Id where ct.RelationshipId=c.Id
-- Грохнуть пустые привилегии сделок
delete from RelationshipPersPermTmp where InheritedFromNumber=0
truncate table RelationshipPersonPermissionDel -- Забрать привилегию у взаимоотношения из контрагента insert into RelationshipPersonPermissionDel (RelationshipId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,InheritedFromNumber,OrganizationItemPosition) select c.Id as RelationshipId,c.PermissionId,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,Relationship,c.UserSecuritySetCacheId,c.InheritedFromNumber,c.OrganizationItemPosition from RelationshipPersPermTmp c inner join Relationship r on r.Id = c.Relationship where c.InheritedFromNumber > 0 and r.Contact is not null and exists (select 1 from ContactPersonPermissionDel t where CASE WHEN t.PermissionId= @CRMContactCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContactIssuancePermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewContactPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContactPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMContactFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END = c.PermissionId and c.UserSecuritySetCacheId=t.userSecuritySetCacheId and c.PermissionRole=t.PermissionRole)
update c set c.InheritedFromNumber=0 from RelationshipPersPermTmp c join RelationshipPersonPermissionDel ct on ct.RelationshipId=c.Id where ct.RelationshipId=c.Id
