delete from RelationshipPersPermTmp where InheritedFromNumber=0 truncate table RelationshipPersonPermissionDel
-- Добавить привилегии к взаимоотношениям из сделок
update c set c.InheritedFromNumber=c.InheritedFromNumber+1 from ( SELECT InheritedFromNumber, PermissionId , PermissionRole , CASE t.PermissionRole WHEN @PermissionRoleAuthor THEN (ca.[creationauthor]|@usermask) WHEN @PermissionRoleTypeResponsible THEN (l.Responsible|@usermask) ELSE t.USERSECURITYSETCACHEID END AS USERSECURITYSETCACHEID FROM RelationshipPersPermTmp t INNER JOIN Relationship ca ON ca.Id=t.Relationship INNER JOIN [Lead] l ON l.Id=ca.[Lead] WHERE ca.InheritPermissions =1 AND ca.Lead IS NOT NULL AND t.InheritedFromNumber > 0 ) c WHERE EXISTS ( SELECT 1 FROM (select distinct CASE WHEN PERMISSIONID = @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN PERMISSIONID=@CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipFullAccessPermissionId WHEN PERMISSIONID=@ViewLeadPermissionId THEN @ViewRelationshipPermissionId WHEN PERMISSIONID=@EditLeadPermissionId THEN @EditRelationshipPermissionId WHEN PERMISSIONID=@CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE PERMISSIONID end as permissionid, USERSECURITYSETCACHEID, PermissionRole from LeadPersonPermissionUpd) t WHERE t.permissionid = c.PermissionId AND c.UserSecuritySetCacheId=t.USERSECURITYSETCACHEID AND c.PermissionRole =t.PERMISSIONROLE )
-- Добавить недостающие привилегии к сделкам select @insCounter=isnull(max([Id]),0) from RelationshipPersonPermissionUpd insert into RelationshipPersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,OrganizationItemPosition,Ins)
select ROW_NUMBER() over (order by t.[Id]) +@insCounter, CASE WHEN t.PermissionId= @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewLeadPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditLeadPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Relationship,t.UserSecuritySetCacheId,t.OrganizationItemPosition,1 Ins from Relationship c left join LeadPersonPermissionUpd t on t.Lead=c.Lead left outer join RelationshipPersPermTmp cp on cp.Relationship=c.Id and cp.InheritedFromNumber > 0 and CASE WHEN t.PermissionId= @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewLeadPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditLeadPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END = cp.PermissionId and cp.UserSecuritySetCacheId=t.UserSecuritySetCacheId and cp.PermissionRole=t.PermissionRole where t.Lead is not null and c.InheritPermissions=1 and cp.Relationship is null and c.Lead is not null
/*Перезаписать реальных пользователей в ответственных */ update RelationshipPersonPermissionUpd set [User]= (select [CreationAuthor] from Relationship con where con.[Id]=Contact), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Relationship con where con.[Id]=Contact) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from RelationshipPersonPermissionUpd EXECUTE [G_GenId] 'RelationshipPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into RelationshipPersPermTmp ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id]-1 as Id,t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Relationship,t.UserSecuritySetCacheId,NEWID(),1 ,t.OrganizationItemPosition from RelationshipPersonPermissionUpd t where Ins=1
truncate table RelationshipPersonPermissionUpd;
insert into log_cont( dt,comm)values(GETDATE ( ),'-- Добавить привилегии к взаимоотношениям контрагентов')
update c set c.InheritedFromNumber=c.InheritedFromNumber+1 from ( SELECT InheritedFromNumber, PermissionId , PermissionRole , CASE t.PermissionRole WHEN @PermissionRoleAuthor THEN (ca.[creationauthor]|@usermask) WHEN @PermissionRoleTypeResponsible THEN (con.Responsible|@usermask) ELSE t.USERSECURITYSETCACHEID END AS USERSECURITYSETCACHEID FROM RelationshipPersPermTmp t INNER JOIN Relationship ca ON ca.Id=t.Relationship INNER JOIN [Contractor] con ON con.Id=ca.[Contractor] WHERE ca.InheritPermissions =1 AND ca.Contractor IS NOT NULL AND t.InheritedFromNumber > 0 ) c WHERE EXISTS ( SELECT 1 FROM (select distinct CASE WHEN PERMISSIONID = @CRMContractorCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN PERMISSIONID=@CRMContractorIssuancePermissionId THEN @CRMRelationshipFullAccessPermissionId WHEN PERMISSIONID=@ViewContractorPermissionId THEN @ViewRelationshipPermissionId WHEN PERMISSIONID=@EditContractorPermissionId THEN @EditRelationshipPermissionId WHEN PERMISSIONID=@FullContractorPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE PERMISSIONID end as permissionid, USERSECURITYSETCACHEID, PermissionRole from ContractorPersonPermissionUpd) t WHERE t.permissionid = c.PermissionId AND c.UserSecuritySetCacheId=t.USERSECURITYSETCACHEID AND c.PermissionRole =t.PERMISSIONROLE )
-- Добавить недостающие привилегии к сделкам select @insCounter=isnull(max([Id]),0) from RelationshipPersonPermissionUpd insert into RelationshipPersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,OrganizationItemPosition,Ins) select ROW_NUMBER() over (order by t.[Id]) +@insCounter, CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Relationship,t.UserSecuritySetCacheId,t.OrganizationItemPosition,1 Ins from Relationship c left join ContractorPersonPermissionUpd t on t.Contractor=c.Contractor left outer join RelationshipPersPermTmp cp on cp.Relationship=c.Id and cp.InheritedFromNumber > 0 and CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END =cp.PermissionId and cp.UserSecuritySetCacheId=t.UserSecuritySetCacheId and cp.PermissionRole=t.PermissionRole where t.Contractor is not null and c.InheritPermissions=1 and cp.Relationship is null and c.Contractor is not null and t.PermissionRole= case when t.PermissionRole=@PermissionRoleTypeParticipantWork and t.[User]!=@adminUser then @NullUid when t.PermissionRole=@PermissionRoleTypeInforms and t.[User]!=@adminUser then @NullUid else t.PermissionRole end
select @insCounter=isnull(max([Id]),0) from RelationshipPersonPermissionUpd /*Добавить пермишены реальных пользователей для исполнителей*/ insert into RelationshipPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,[Ins]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[UserID] [User] ,[Group] ,[OrganizationItemPosition] ,m.[UserID]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,1 [Ins] from [RelationshipUser] m left join RelationshipPersonPermissionUpd c on m.RelationshipID=c.Relationship where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and m.[Status]=0 and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]
select @insCounter=isnull(max([Id]),0) from RelationshipPersonPermissionUpd
/*Добавить пермишены реальных пользователей для исполнителей*/ insert into RelationshipPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,[Ins]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[UserID] [User] ,[Group] ,[OrganizationItemPosition] ,m.[UserID]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,1 [Ins] from [RelationshipUser] m left join RelationshipPersonPermissionUpd c on m.RelationshipID=c.Relationship where PermissionRole =@PermissionRoleTypeInforms and [User]=@adminUser and m.[Status]=1 and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]
