-- Добавить привилегии к взаимоотношениям контрагентов update c set c.InheritedFromNumber=c.InheritedFromNumber+1 from ( SELECT InheritedFromNumber, PermissionId , PermissionRole , CASE t.PermissionRole WHEN @PermissionRoleAuthor THEN (ca.[creationauthor]|@usermask) WHEN @PermissionRoleTypeResponsible THEN (contr.Responsible|@usermask) ELSE t.USERSECURITYSETCACHEID END AS USERSECURITYSETCACHEID FROM RelationshipPersPermTmp t INNER JOIN Relationship ca ON ca.Id=t.Relationship INNER JOIN [Contact] con ON con.Id=ca.[Contact] LEFT JOIN [Contractor] contr ON contr.Id=con.[Contractor] WHERE ca.InheritPermissions =1 AND ca.Contact IS NOT NULL AND t.InheritedFromNumber > 0 ) c WHERE EXISTS ( SELECT 1 FROM (select distinct CASE WHEN PERMISSIONID = @CRMContactCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN PERMISSIONID=@CRMContactIssuancePermissionId THEN @CRMRelationshipFullAccessPermissionId WHEN PERMISSIONID=@ViewContactPermissionId THEN @ViewRelationshipPermissionId WHEN PERMISSIONID=@EditContactPermissionId THEN @EditRelationshipPermissionId WHEN PERMISSIONID=@CRMContactFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE PERMISSIONID end as permissionid, USERSECURITYSETCACHEID, PermissionRole from ContactPersonPermissionUpd) t WHERE t.permissionid = c.PermissionId AND c.UserSecuritySetCacheId=t.USERSECURITYSETCACHEID AND c.PermissionRole =t.PERMISSIONROLE )
-- Добавить недостающие привилегии к сделкам select @insCounter=isnull(max([Id]),0) from RelationshipPersonPermissionUpd insert into RelationshipPersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,OrganizationItemPosition,Ins)
select ROW_NUMBER() over (order by t.[Id]) +@insCounter, CASE WHEN t.PermissionId= @CRMContactCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContactIssuancePermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewContactPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContactPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMContactFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Relationship,t.UserSecuritySetCacheId,t.OrganizationItemPosition,1 Ins from Relationship c left join ContactPersonPermissionUpd t on t.Contact=c.Contact left outer join RelationshipPersPermTmp cp on cp.Relationship=c.Id and cp.InheritedFromNumber > 0 and CASE WHEN t.PermissionId= @CRMContactCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContactIssuancePermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewContactPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContactPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMContactFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END = cp.PermissionId and cp.UserSecuritySetCacheId=t.UserSecuritySetCacheId and cp.PermissionRole=t.PermissionRole where t.Contact is not null and c.InheritPermissions=1 and cp.Relationship is null and c.Contact is not null
/*Перезаписать реальных пользователей в ответственных */ update RelationshipPersonPermissionUpd set [User]= (select [CreationAuthor] from Relationship con where con.[Id]=Contact), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Relationship con where con.[Id]=Contact) where PermissionRole=@PermissionRoleAuthor
