create procedure [UpdateContractorSlavePerm] AS begin
declare @insCounter bigint, @insStartId bigint, @insEndId bigint;
declare @CRMContractorCreateElementPermissionId uniqueidentifier= '44ED88D4-A466-4fed-B194-B8288560CB48'; declare @CRMContractorIssuancePermissionId uniqueidentifier= '1CD25727-7CE6-443c-84BD-7975822C79E6'; declare @ViewContractorPermissionId uniqueidentifier= '9219C9AB-7E68-47B1-8939-FF6FC4439DA0'; declare @EditContractorPermissionId uniqueidentifier= '8C932B94-2F9C-488E-A36F-949A11C9741E'; declare @FullContractorPermissionId uniqueidentifier= 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5';
declare @CRMContactCreateElementPermissionId uniqueidentifier= 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5'; declare @CRMContactIssuancePermissionId uniqueidentifier= '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1'; declare @ViewContactPermissionId uniqueidentifier= '3626682F-B657-419E-9A8E-392C14ABE455'; declare @EditContactPermissionId uniqueidentifier= 'ABC752AD-3623-4F14-A47F-121999890D2C'; declare @CRMContactFullAccessPermissionId uniqueidentifier= '76B481D5-2E07-4417-9098-A57DE879FA56';
declare @CRMSaleIssuancePermissionId uniqueidentifier= 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA'; declare @ViewSalePermissionId uniqueidentifier= 'AAE16346-B0E6-4949-ACAB-0914C573DE55'; declare @EditSalePermissionId uniqueidentifier= 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74'; declare @CRMSaleCreateElementPermissionId uniqueidentifier= '7DB77821-D6D3-4dd2-AD1B-798330506ADC'; declare @FullSalePermissionId uniqueidentifier= 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';
declare @CRMInpaymentCreateElementPermissionId uniqueidentifier= 'D130BB5F-6A26-4e37-B62C-F3B443E3BF53'; declare @ViewInpaymentPermissionId uniqueidentifier= '837FF0F3-03A7-4A17-86EA-A72B3AB4886B'; declare @EditInpaymentPermissionId uniqueidentifier= 'E23802D7-F3B5-431E-A72E-7133C3C9343F'; declare @CRMInpaymentIssuanceElementPermissionId uniqueidentifier= 'ACF5606C-B566-426b-BAEC-E74061095BEB'; declare @CRMInpaymentFullAccessPermissionId uniqueidentifier= 'A27A46F9-BCD8-4e82-AE49-E58675DE52D7';
declare @CRMRelationshipCreateElementPermissionId uniqueidentifier= 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2'; declare @ViewRelationshipPermissionId uniqueidentifier= '186D4CC4-6924-4848-93AC-6D8DE389CB08'; declare @EditRelationshipPermissionId uniqueidentifier= '0B980531-D097-4EC1-8616-56E6AB15770E'; declare @CRMRelationshipIssuanceElementPermissionId uniqueidentifier= '679876A7-8882-43d4-8FC2-3E7C9DB58ADB'; declare @CRMRelationshipFullAccessPermissionId uniqueidentifier= '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';
declare @ViewLeadPermissionId uniqueidentifier= 'C660E4B4-03BF-4315-9600-5086E47653B4'; declare @EditLeadPermissionId uniqueidentifier= 'AE298CD3-A16A-4B55-ACFC-545E4A0EBD48'; declare @CRMLeadCreateElementPermissionId uniqueidentifier= '643FE44B-8192-4615-B853-106CD6F09EDE'; declare @CRMLeadFullAccessPermissionId uniqueidentifier= '90BE803C-7857-4F2D-A8B4-129264504101'; declare @CRMLeadIssuanceElementPermissionId uniqueidentifier= 'E70A9AD1-80B2-4435-80E9-EF8E14B974CE';
declare @PermissionRoleAuthor uniqueidentifier = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92'; declare @usermask bigint = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55 declare @PermissionRoleTypeResponsible uniqueidentifier = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15';
declare @PermissionRoleTypeParticipantWork uniqueidentifier = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386'; declare @PermissionRoleTypeInforms uniqueidentifier = '21888C0C-8BCA-4B26-AF13-4C497EECCED6'; declare @adminUid uniqueidentifier='F0E949BF-4DA4-4C02-B04C-CA61964B4FE8'; declare @adminUser bigint=0; declare @NullUid uniqueidentifier = '00000000-0000-0000-0000-000000000000';
select @adminUser=Id from [User] where Uid=@adminUid;
truncate table ContractorPersonPermissionDel truncate table ContractorPersonPermissionUpd truncate table ContactPersonPermissionDel truncate table ContactPersonPermissionUpd truncate table SalePersonPermissionUpd truncate table SalePersonPermissionDel truncate table LeadPersonPermissionUpd truncate table LeadPersonPermissionDel truncate table RelationshipPersonPermissionDel; truncate table RelationshipPersonPermissionUpd;
-- делаем копию рабочей таблицы контрагентов truncate table log_cont
truncate table ContractorPersonPermTmp
truncate table ContractorPersonPermTmp
INSERT INTO [ContractorPersonPermTmp] ([Id] ,[Uid] ,[PermissionId] ,[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[InheritedFromNumber]) select [Id], [Uid] ,[PermissionId] ,[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId]a ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[InheritedFromNumber] from ContractorPersonPermission
insert into ContractorPersonPermissionUpd (PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contractor,UserSecuritySetCacheId,OrganizationItemPosition,Ins,Child) select t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,t.Contractor,t.UserSecuritySetCacheId ,t.OrganizationItemPosition,1,1 as Child from ContractorPersonPermission t where Contractor in (select Id from Contractor where InheritPermissions is null) ;
-- делаем копию прав контактов
truncate table [ContactPersonPermTmp]
INSERT INTO [ContactPersonPermTmp] ([Id],[Uid] ,[PermissionId] ,[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contact] ,[InheritedFromNumber]) select [Id] ,[Uid] ,[PermissionId] ,[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contact] ,[InheritedFromNumber] from [ContactPersonPermission]
-- Забрать привилегию из контактов insert into ContactPersonPermissionDel(ContactId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contact,UserSecuritySetCacheId,InheritedFromNumber,OrganizationItemPosition,Child) select c.Id as ContactId,c.PermissionId,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,Contact,c.UserSecuritySetCacheId,c.InheritedFromNumber,c.OrganizationItemPosition, (select count(1) from ContractorPersonPermissionDel t where c.PermissionId= CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @CRMContactFullAccessPermissionId ELSE t.PermissionId END and c.UserSecuritySetCacheId=t.userSecuritySetCacheId) from ContactPersonPermTmp c where c.InheritedFromNumber > 0 and exists (select 1 from ContractorPersonPermissionDel t where c.PermissionId= CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @CRMContactFullAccessPermissionId ELSE t.PermissionId END and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Contact] con where con.[Id]=c.[Contact])|@usermask) when @PermissionRoleTypeResponsible then (select (contr.Responsible|@usermask) from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact) ELSE t.userSecuritySetCacheId end and c.PermissionRole=t.PermissionRole )
update c set c.InheritedFromNumber=c.InheritedFromNumber-1 from ContactPersonPermTmp c join ContactPersonPermissionDel ct on ct.ContactId=c.Id where ct.ContactId=c.Id
-- Грохнуть пустые контакты delete from ContactPersonPermTmp where InheritedFromNumber=0
-- Добавить привилегии к контактам 1
insert into ContactPersonPermissionUpd (ContactId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contact,UserSecuritySetCacheId,OrganizationItemPosition,Ins) select Id, c.PermissionId,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Contact Contact,c.UserSecuritySetCacheId,c.OrganizationItemPosition,0 Ins from ContactPersonPermTmp c where c.InheritedFromNumber > 0 and exists (select 1 from ContractorPersonPermissionUpd t where CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @CRMContactFullAccessPermissionId ELSE t.PermissionId END =c.PermissionId and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Contact] con where con.[Id]=c.[Contact])|@usermask) when @PermissionRoleTypeResponsible then (select (contr.Responsible|@usermask) from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact) ELSE t.userSecuritySetCacheId end and c.PermissionRole=t.PermissionRole ) and c.Contact in (select id from Contact ca where ca.InheritPermissions=1 )
update c set c.InheritedFromNumber=1 from ContactPersonPermTmp c where c.Id in (select ct.ContactId from ContactPersonPermissionUpd ct )
-- Добавить недостающие привилегии к контактам
insert into ContactPersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contact,UserSecuritySetCacheId,OrganizationItemPosition,Ins) select ROW_NUMBER() over (order by t.[Id]) - 1, CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @CRMContactFullAccessPermissionId ELSE t.PermissionId END ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Contact,t.UserSecuritySetCacheId,t.OrganizationItemPosition,1 Ins from Contact c left join ContractorPersonPermissionUpd t on t.Contractor=c.Contractor --and t.Contractor is not null left outer join ContactPersonPermTmp cp on cp.Contact=c.Id and cp.InheritedFromNumber > 0 and CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @CRMContactFullAccessPermissionId ELSE t.PermissionId END =cp.PermissionId and cp.UserSecuritySetCacheId=t.UserSecuritySetCacheId and cp.PermissionRole=t.PermissionRole where t.Contractor is not null and cp.Contact is null and c.InheritPermissions=1
/*Перезаписать реальных пользователей в ответственных */ update ContactPersonPermissionUpd set [User]= (select contr.Responsible from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact), [UserSecuritySetCacheId]= (select (contr.Responsible|@usermask) from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact)
where PermissionRole=@PermissionRoleTypeResponsible
/*Перезаписать реальных пользователей в ответственных */ update ContactPersonPermissionUpd set [User]= (select [CreationAuthor] from Contact con where con.[Id]=Contact), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Contact con where con.[Id]=Contact) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from ContactPersonPermissionUpd EXECUTE [G_GenId] 'ContactPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into ContactPersonPermTmp ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contact,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id]-1 as Id,t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Contact,t.UserSecuritySetCacheId,NEWID(),1 ,t.OrganizationItemPosition from ContactPersonPermissionUpd t where Ins=1
