-- Забрать привилегию из Сделок insert into salePersonPermissionDel(saleId,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,sale,UserSecuritySetCacheId,InheritedFromNumber,OrganizationItemPosition,Child) select c.Id as saleId,c.PermissionId,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,sale,c.UserSecuritySetCacheId,c.InheritedFromNumber,c.OrganizationItemPosition, (select count(1) from ContractorPersonPermissionDel t where c.PermissionId= CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMSaleCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMSaleIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewSalePermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditSalePermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @FullSalePermissionId ELSE t.PermissionId END and c.UserSecuritySetCacheId=t.userSecuritySetCacheId) from [SalePersonPermissionTmp] c where c.InheritedFromNumber > 0 and exists (select 1 from ContractorPersonPermissionDel t where c.PermissionId= CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMSaleCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMSaleIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewSalePermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditSalePermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @FullSalePermissionId ELSE t.PermissionId END and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then ((select [Author] from [Sale] con where con.[Id]=c.[Sale])|@usermask) when @PermissionRoleTypeResponsible then (select (Responsible|@usermask) from Sale con where con.[Id]=Sale) ELSE t.userSecuritySetCacheId end and c.PermissionRole=t.PermissionRole )
update c set c.InheritedFromNumber=c.InheritedFromNumber-1 from SalePersonPermissionTmp c join SalePersonPermissionDel ct on ct.SaleId=c.Id where ct.SaleId=c.Id
