-- Добавить недостающие привилегии к сделкам
insert into RelationshipPersonPermissionUpd([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,OrganizationItemPosition,Ins) select ROW_NUMBER() over (order by t.[Id]) -1, CASE WHEN t.PermissionId= @CRMContactCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContactIssuancePermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewContactPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContactPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMContactFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Relationship,t.UserSecuritySetCacheId,t.OrganizationItemPosition,1 Ins from Relationship c left join ContactPersonPermissionUpd t on t.Contact=c.Contact left outer join RelationshipPersPermTmp cp on cp.Relationship=c.Id and cp.InheritedFromNumber > 0 and CASE WHEN t.PermissionId= @CRMContactCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContactIssuancePermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewContactPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContactPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMContactFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END = cp.PermissionId and cp.UserSecuritySetCacheId=t.UserSecuritySetCacheId and cp.PermissionRole=t.PermissionRole where t.Contact is not null and c.InheritPermissions=1 and cp.Relationship is null and c.Contact is not null
/*Перезаписать реальных пользователей в ответственных */ update RelationshipPersonPermissionUpd set [User]= (select [CreationAuthor] from Relationship con where con.[Id]=Contact), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Relationship con where con.[Id]=Contact) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from RelationshipPersonPermissionUpd EXECUTE [G_GenId] 'RelationshipPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into RelationshipPersPermTmp ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id,t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Relationship,t.UserSecuritySetCacheId,NEWID(),1 ,t.OrganizationItemPosition from RelationshipPersonPermissionUpd t where Ins=1
truncate table RelationshipPersonPermissionUpd
truncate table ContactPersonPermissionUpd; truncate table ContactPersonPermissionDel; truncate table ContractorPersonPermissionDel; truncate table ContractorPersonPermissionUpd; truncate table SalePersonPermissionDel; truncate table SalePersonPermissionUpd; truncate table LeadPersonPermissionDel; truncate table LeadPersonPermissionUpd; truncate table RelationshipPersonPermissionDel; truncate table RelationshipPersonPermissionUpd;
--делаем подмену
BEGIN TRANSACTION;
EXEC sp_rename 'ContractorPersonPermission','ContractorPersonPermTmp1'; EXEC sp_rename 'ContractorPersonPermTmp','ContractorPersonPermission' ; EXEC sp_rename 'ContractorPersonPermTmp1','ContractorPersonPermTmp'; truncate table ContractorPersonPermTmp
EXEC sp_rename 'ContactPersonPermission','ContactPersonPermTmp1'; EXEC sp_rename 'ContactPersonPermTmp','ContactPersonPermission' ; EXEC sp_rename 'ContactPersonPermTmp1','ContactPersonPermTmp'; truncate table ContactPersonPermTmp
EXEC sp_rename 'SalePersonPermission','SalePersonPermissionTmp1'; EXEC sp_rename 'SalePersonPermissionTmp','SalePersonPermission' ; EXEC sp_rename 'SalePersonPermissionTmp1','SalePersonPermissionTmp'; truncate table SalePersonPermissionTmp
EXEC sp_rename 'LeadPersonPermission','LeadPersonPermissionTmp1'; EXEC sp_rename 'LeadPersonPermissionTmp','LeadPersonPermission' ; EXEC sp_rename 'LeadPersonPermissionTmp1','LeadPersonPermissionTmp'; truncate table LeadPersonPermissionTmp
EXEC sp_rename 'RelationshipPersonPermission','RelationshipPersPermTmp1'; EXEC sp_rename 'RelationshipPersPermTmp','RelationshipPersonPermission' ; EXEC sp_rename 'RelationshipPersPermTmp1','RelationshipPersPermTmp'; truncate table RelationshipPersPermTmp
-- Удалить инфу об изменении delete from TemplateContractorPermission where delpermission =1 update TemplateContractorPermission set AddPermission=0 where AddPermission =1 delete from TemplateLeadPermission where delpermission =1 update TemplateLeadPermission set AddPermission=0 where AddPermission =1
COMMIT TRANSACTION;
END

CREATE procedure [AddUpdateContractorPermissions] ( @Uid uniqueidentifier -- это ID пермишена в контрагенте ) -- коприрование прав в подчиненные объекты при назначении прав в контрагенте as
declare @usermask bigint; declare @insCounter bigint, @insStartId bigint, @insEndId bigint; declare @categoryTmp bigint; declare @userPermission bigint;
declare @permissionId uniqueidentifier; declare @userP bigint; declare @groupP bigint; declare @OrganizationItemPosition bigint; declare @userSecuritySetCacheId bigint; declare @permissionRole uniqueidentifier; declare @organizationItemEmployee bigint; declare @Contractor bigint;
begin
-- получить дополнительные параметры select @permissionId=PermissionId, @userP=[User], @groupP= [Group], @OrganizationItemPosition=OrganizationItemPosition, @userSecuritySetCacheId=UserSecuritySetCacheId, @permissionRole=PermissionRole, @organizationItemEmployee=OrganizationItemEmployee, @Contractor=Contractor from ContractorPersonPermission cp where cp.Uid=@Uid
-- Сделать замену привилегий declare @permissionContactId uniqueidentifier; declare @permissionSaleId uniqueidentifier; declare @permissionRelationshipId uniqueidentifier;
declare @CRMContractorCreateElementPermissionId uniqueidentifier= '44ED88D4-A466-4fed-B194-B8288560CB48'; declare @CRMContractorIssuancePermissionId uniqueidentifier= '1CD25727-7CE6-443c-84BD-7975822C79E6'; declare @ViewContractorPermissionId uniqueidentifier= '9219C9AB-7E68-47B1-8939-FF6FC4439DA0'; declare @EditContractorPermissionId uniqueidentifier= '8C932B94-2F9C-488E-A36F-949A11C9741E'; declare @FullContractorPermissionId uniqueidentifier= 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5';
declare @CRMSaleIssuancePermissionId uniqueidentifier= 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA'; declare @ViewSalePermissionId uniqueidentifier= 'AAE16346-B0E6-4949-ACAB-0914C573DE55'; declare @EditSalePermissionId uniqueidentifier= 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74'; declare @CRMSaleCreateElementPermissionId uniqueidentifier= '7DB77821-D6D3-4dd2-AD1B-798330506ADC'; declare @FullSalePermissionId uniqueidentifier= 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';
declare @CRMContactCreateElementPermissionId uniqueidentifier= 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5'; declare @CRMContactIssuancePermissionId uniqueidentifier= '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1'; declare @ViewContactPermissionId uniqueidentifier= '3626682F-B657-419E-9A8E-392C14ABE455'; declare @EditContactPermissionId uniqueidentifier= 'ABC752AD-3623-4F14-A47F-121999890D2C'; declare @FullContactPermissionId uniqueidentifier= '76B481D5-2E07-4417-9098-A57DE879FA56';
declare @CRMInpaymentCreateElementPermissionId uniqueidentifier= 'D130BB5F-6A26-4e37-B62C-F3B443E3BF53'; declare @ViewInpaymentPermissionId uniqueidentifier = '837FF0F3-03A7-4A17-86EA-A72B3AB4886B'; declare @EditInpaymentPermissionId uniqueidentifier = 'E23802D7-F3B5-431E-A72E-7133C3C9343F'; declare @CRMInpaymentIssuanceElementPermissionId uniqueidentifier = 'ACF5606C-B566-426b-BAEC-E74061095BEB'; declare @CRMInpaymentFullAccessPermissionId uniqueidentifier = 'A27A46F9-BCD8-4e82-AE49-E58675DE52D7';
declare @CRMRelationshipCreateElementPermissionId uniqueidentifier= 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2'; declare @ViewRelationshipPermissionId uniqueidentifier = '186D4CC4-6924-4848-93AC-6D8DE389CB08'; declare @EditRelationshipPermissionId uniqueidentifier = '0B980531-D097-4EC1-8616-56E6AB15770E'; declare @CRMRelationshipIssuanceElementPermissionId uniqueidentifier = '679876A7-8882-43d4-8FC2-3E7C9DB58ADB'; declare @CRMRelationshipFullAccessPermissionId uniqueidentifier = '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';
declare @PermissionRoleTypeUser uniqueidentifier = 'ED43E50F-6085-47BD-9A28-E43246E476A8'; declare @PermissionRoleTypeInforms uniqueidentifier = '21888C0C-8BCA-4B26-AF13-4C497EECCED6'; declare @PermissionRoleTypeParticipantWork uniqueidentifier = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386'; declare @PermissionRoleTypeResponsible uniqueidentifier = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15';
set @usermask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55 declare @PermissionRoleAuthor uniqueidentifier = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92'; declare @NullUid uniqueidentifier = '00000000-0000-0000-0000-000000000000'; declare @adminUid uniqueidentifier='F0E949BF-4DA4-4C02-B04C-CA61964B4FE8'; declare @adminUser bigint=0; declare @countCrm bigint=0;
set @countCrm = 0; /*Если нет подчиненных элементов то и считать нечего*/ select @countCrm=sum(a) from ( select count(1) as a from Relationship c where c.contractor =@Contractor union all select count(1) from Sale c where c.contractor =@Contractor union all select count(1) from Relationship c left join Contact con on c.Contact=con.Id where con.contractor=@Contractor union all select count(1) from Relationship c left join Sale con on c.Sale=con.Id where con.contractor=@Contractor union all select count(1) from Contact c where c.contractor=@Contractor ) a;
IF (@countCrm=0) return;
BEGIN TRANSACTION;
select @adminUser=Id from [User] where Uid=@adminUid;
set @permissionContactId= CASE WHEN @permissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN @permissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN @permissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN @permissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN @permissionId= @FullContractorPermissionId THEN @FullContactPermissionId ELSE @permissionId END set @permissionSaleId= CASE WHEN @permissionId= @CRMContractorCreateElementPermissionId THEN @CRMSaleCreateElementPermissionId WHEN @permissionId= @CRMContractorIssuancePermissionId THEN @CRMSaleIssuancePermissionId WHEN @permissionId= @ViewContractorPermissionId THEN @ViewSalePermissionId WHEN @permissionId= @EditContractorPermissionId THEN @EditSalePermissionId WHEN @permissionId= @FullContractorPermissionId THEN @FullSalePermissionId
ELSE @permissionId END set @permissionRelationshipId= CASE WHEN @permissionId= @CRMContractorCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN @permissionId= @CRMContractorIssuancePermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN @permissionId= @ViewContractorPermissionId THEN @ViewRelationshipPermissionId WHEN @permissionId= @EditContractorPermissionId THEN @EditRelationshipPermissionId WHEN @permissionId= @FullContractorPermissionId THEN @CRMRelationshipFullAccessPermissionId
ELSE @permissionId END
-- Добавить привилегию в контакты
update c set InheritedFromNumber=1 from ContactPersonPermission c left join Contact cp on cp.Id=c.Contact where PermissionId=@permissionContactId
and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Contact] con where con.[Id]=c.[Contact])|@usermask) when @PermissionRoleTypeResponsible then (select (contr.Responsible|@usermask) from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact) ELSE @userSecuritySetCacheId end
and InheritedFromNumber > 0 and c.permissionRole=@permissionRole and cp.Contractor=@Contractor
-- Добавить недостающие привилегии в контакты
select (ROW_NUMBER() OVER (ORDER BY t.PermissionId))-1 as [Id],@permissionContactId as PermissionId,@userP [User],@groupP [Group],@permissionRole as PermissionRole,@organizationItemEmployee as OrganizationItemEmployee,c.Id as Contact,@userSecuritySetCacheId as UserSecuritySetCacheId,NEWID() as Uid,count(1) as InheritedFromNumber ,@OrganizationItemPosition as OrganizationItemPosition into #ContactPersonPermissionTmp from Contact c left join ContractorPersonPermission t on t.Contractor=c.Contractor left outer join ContactPersonPermission cp on cp.Contact=c.Id and cp.PermissionId=@permissionContactId and cp.UserSecuritySetCacheId=@userSecuritySetCacheId and cp.InheritedFromNumber > 0 and cp.PermissionRole=@permissionRole where t.Contractor is not null and cp.Contact is null and t.PermissionId=@permissionId and t.UserSecuritySetCacheId=@userSecuritySetCacheId and c.InheritPermissions=1 and c.Contractor=@Contractor and t.PermissionRole=@permissionRole group by t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition
/*Перезаписать реальных пользователей в ответственных */ update #ContactPersonPermissionTmp set [User]= (select contr.Responsible from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact), [UserSecuritySetCacheId]= (select (contr.Responsible|@usermask) from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact) where PermissionRole=@PermissionRoleTypeResponsible /*Перезаписать реальных пользователей в ответственных */ update #ContactPersonPermissionTmp set [User]= (select [CreationAuthor] from Contact con where con.[Id]=Contact), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Contact con where con.[Id]=Contact) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from #ContactPersonPermissionTmp EXECUTE [G_GenId] 'ContactPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into ContactPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contact,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId+[Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contact,UserSecuritySetCacheId,NEWID(),InheritedFromNumber,OrganizationItemPosition from #ContactPersonPermissionTmp
drop table #ContactPersonPermissionTmp; -- Добавить привилегию в сделки
update c set InheritedFromNumber=1 from SalePersonPermission c left join Sale s on s.id=c.Sale where s.Contractor=@Contractor and PermissionId=@permissionSaleId and c.UserSecuritySetCacheId= case c.PermissionRole when @PermissionRoleAuthor then ((select [Author] from [Sale] con where con.[Id]=c.[Sale])|@usermask) when @PermissionRoleTypeResponsible then ((select [Responsible] from [Sale] con where con.[Id]=c.[Sale])|@usermask) ELSE @userSecuritySetCacheId end and permissionRole=@permissionRole and InheritedFromNumber > 0
-- Добавить недостающие привилегии в сделки
select (ROW_NUMBER() OVER (ORDER BY t.PermissionId)) as Id,@permissionSaleId as PermissionId,@userP [User],@groupP as [Group],@permissionRole as PermissionRole,@organizationItemEmployee as OrganizationItemEmployee,c.Id as Sale,@userSecuritySetCacheId as UserSecuritySetCacheId,NEWID() as [Uid],1 as InheritedFromNumber ,@OrganizationItemPosition as OrganizationItemPosition into #SalePersonPermissionTmp from Sale c left join ContractorPersonPermission t on t.Contractor=c.Contractor left outer join SalePersonPermission cp on cp.Sale=c.Id and cp.PermissionId=@permissionSaleId and cp.UserSecuritySetCacheId=@userSecuritySetCacheId and cp.InheritedFromNumber > 0 and cp.PermissionRole=@permissionRole where t.Contractor is not null and cp.Sale is null and t.PermissionId=@permissionId and t.UserSecuritySetCacheId=@userSecuritySetCacheId and t.PermissionRole=@permissionRole and c.Contractor=@Contractor and c.InheritPermissions=1 group by t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition
/*Перезаписать реальных пользователей в ответственных */ update #SalePersonPermissionTmp set [User]= (select Responsible from Sale con where con.[Id]=Sale), [UserSecuritySetCacheId]= (select (Responsible|@usermask) from Sale con where con.[Id]=Sale) where PermissionRole=@PermissionRoleTypeResponsible /*Перезаписать реальных пользователей в ответственных */ update #SalePersonPermissionTmp set [User]= (select [Author] from Sale con where con.[Id]=Sale), [UserSecuritySetCacheId]= (select (Author|@usermask) from Sale con where con.[Id]=Sale) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from #SalePersonPermissionTmp EXECUTE [G_GenId] 'SalePersonPermission', @insCounter, @insStartId out, @insEndId out; insert into SalePersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Sale,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId+[Id]-1,PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Sale,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition from #SalePersonPermissionTmp
drop table #SalePersonPermissionTmp; -- Грохнуть все перпишенв у взаимоотношения
delete from RelationshipPersonPermission where id in (select c.id from RelationshipPersonPermission c left join Relationship r on r.Contractor=@Contractor and c.Relationship=r.Id where PermissionId=@permissionRelationshipId
and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Relationship] con where con.[Id]=c.[Relationship])|@usermask) when @PermissionRoleTypeResponsible then (select (Relationship|@usermask) from Relationship con where con.[Id]=Relationship) ELSE @userSecuritySetCacheId end and ( ((PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and [User]=@userP ) or (PermissionRole !=@PermissionRoleTypeParticipantWork and PermissionRole !=@PermissionRoleTypeInforms ))/*В случае с участниками берем только если пришел системный пользователь*/ and ((PermissionRole =@PermissionRoleTypeInforms and [User]=@adminUser and [User]=@userP ) or (PermissionRole !=@PermissionRoleTypeInforms and PermissionRole !=@PermissionRoleTypeParticipantWork )) ) and r.Contractor=@Contractor and r.InheritPermissions=1 and c.InheritedFromNumber > 0 )
-- добавить недостающие из контрагентов
select (ROW_NUMBER() OVER (ORDER BY t.PermissionId))-1 as Id,@permissionRelationshipId as PermissionId ,@userP as [User],@groupP as [Group], t.permissionRole as PermissionRole,@organizationItemEmployee as OrganizationItemEmployee,c.Id as Relationship,@userSecuritySetCacheId as UserSecuritySetCacheId,NEWID() as [Uid] ,count(1) as InheritedFromNumber,@OrganizationItemPosition as OrganizationItemPosition into #RelationshipPersPermTmp from Relationship c left join ContractorPersonPermission t on t.Contractor=c.Contractor left outer join RelationshipPersonPermission cp on cp.Relationship=c.Id and cp.PermissionId=@permissionRelationshipId and cp.UserSecuritySetCacheId=@userSecuritySetCacheId and cp.InheritedFromNumber > 0 and cp.PermissionRole=t.permissionRole where t.Contractor is not null and cp.Relationship is null and t.PermissionId=@permissionId and t.UserSecuritySetCacheId=@userSecuritySetCacheId and t.PermissionRole=@permissionRole and c.InheritPermissions=1 and c.Contractor=@Contractor and t.PermissionRole= case when t.PermissionRole=@PermissionRoleTypeParticipantWork and t.[User]!=@adminUser then @NullUid when t.PermissionRole=@PermissionRoleTypeInforms and t.[User]!=@adminUser then @NullUid else t.PermissionRole end group by t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition
select @insCounter=max([Id]) from #RelationshipPersPermTmp /*Добавить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersPermTmp ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,[InheritedFromNumber] ) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[UserID] [User] ,[Group] ,[OrganizationItemPosition] ,m.[UserID]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,1
from [RelationshipUser] m left join #RelationshipPersPermTmp c on m.RelationshipID=c.Relationship where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and m.[Status]=0 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]
select @insCounter=max([Id]) from #RelationshipPersPermTmp
/*Добавить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersPermTmp ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,[InheritedFromNumber] ) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[UserID] [User] ,[Group] ,[OrganizationItemPosition] ,m.[UserID]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,1 from [RelationshipUser] m left join #RelationshipPersPermTmp c on m.RelationshipID=c.Relationship where PermissionRole =@PermissionRoleTypeInforms and [User]=@adminUser and m.[Status]=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]
/*Перезаписать реальных пользователей в ответственных */ update #RelationshipPersPermTmp set [User]= (select [CreationAuthor] from Relationship con where con.[Id]=Relationship), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Relationship con where con.[Id]=Relationship) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from #RelationshipPersPermTmp EXECUTE [G_GenId] 'RelationshipPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into RelationshipPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId+[Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition from #RelationshipPersPermTmp
-- Добавить взаимоотношения из контактов
select (ROW_NUMBER() OVER (ORDER BY t.PermissionId))-1 as Id,@permissionRelationshipId as PermissionId ,@userP as [User],@groupP as [Group], t.permissionRole as PermissionRole,@organizationItemEmployee as OrganizationItemEmployee,c.Id as Relationship,@userSecuritySetCacheId as UserSecuritySetCacheId,NEWID() as [Uid] ,count(1) as InheritedFromNumber,@OrganizationItemPosition as OrganizationItemPosition into #RelationshipPersonPermissionContactTmp from Relationship c left join ContactPersonPermission t on t.Contact=c.Contact left outer join RelationshipPersonPermission cp on cp.Relationship=c.Id and cp.PermissionId=@permissionRelationshipId and cp.UserSecuritySetCacheId=@userSecuritySetCacheId and cp.InheritedFromNumber > 0 and cp.PermissionRole=t.permissionRole and cp.InheritedFromNumber > 0 left join Contact con on con.Contractor=@Contractor and c.Contact=con.Id where t.Contact is not null and cp.Relationship is null and t.PermissionId=@permissionContactId and t.UserSecuritySetCacheId=@userSecuritySetCacheId and t.PermissionRole=@permissionRole and c.InheritPermissions=1 and c.Contractor is null group by t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition
/*Перезаписать реальных пользователей в ответственных */ update #RelationshipPersonPermissionContactTmp set [User]= (select [CreationAuthor] from Relationship con where con.[Id]=Relationship), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Relationship con where con.[Id]=Relationship) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from #RelationshipPersonPermissionContactTmp EXECUTE [G_GenId] 'RelationshipPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into RelationshipPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId+[Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition from #RelationshipPersonPermissionContactTmp
drop table #RelationshipPersPermTmp;
COMMIT TRANSACTION; end

create procedure [DelUpdateContractorPermissions] ( @permissionId uniqueidentifier, @userSecuritySetCacheId bigint, -- это ID перпишена в контейнере @ContractorId bigint, -- это ID перпишена в контейнере @permissionRole uniqueidentifier ) as begin BEGIN TRANSACTION; declare @typemask bigint, @usermask bigint, @groupmask bigint, @organizationitemmask bigint; declare @permissionContactId uniqueidentifier; declare @permissionSaleId uniqueidentifier; declare @permissionInpaymentId uniqueidentifier; declare @permissionRelationshipId uniqueidentifier;
declare @CRMContractorCreateElementPermissionId uniqueidentifier= '44ED88D4-A466-4fed-B194-B8288560CB48'; declare @CRMContractorIssuancePermissionId uniqueidentifier= '1CD25727-7CE6-443c-84BD-7975822C79E6'; declare @ViewContractorPermissionId uniqueidentifier= '9219C9AB-7E68-47B1-8939-FF6FC4439DA0'; declare @EditContractorPermissionId uniqueidentifier= '8C932B94-2F9C-488E-A36F-949A11C9741E'; declare @FullContractorPermissionId uniqueidentifier= 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5';
declare @CRMSaleIssuancePermissionId uniqueidentifier= 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA'; declare @ViewSalePermissionId uniqueidentifier= 'AAE16346-B0E6-4949-ACAB-0914C573DE55'; declare @EditSalePermissionId uniqueidentifier= 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74'; declare @CRMSaleCreateElementPermissionId uniqueidentifier= '7DB77821-D6D3-4dd2-AD1B-798330506ADC'; declare @FullSalePermissionId uniqueidentifier= 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';
declare @CRMContactCreateElementPermissionId uniqueidentifier= 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5'; declare @CRMContactIssuancePermissionId uniqueidentifier= '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1'; declare @ViewContactPermissionId uniqueidentifier= '3626682F-B657-419E-9A8E-392C14ABE455'; declare @EditContactPermissionId uniqueidentifier= 'ABC752AD-3623-4F14-A47F-121999890D2C'; declare @FullContactPermissionId uniqueidentifier= '76B481D5-2E07-4417-9098-A57DE879FA56';
declare @CRMInpaymentCreateElementPermissionId uniqueidentifier= 'D130BB5F-6A26-4e37-B62C-F3B443E3BF53'; declare @ViewInpaymentPermissionId uniqueidentifier = '837FF0F3-03A7-4A17-86EA-A72B3AB4886B'; declare @EditInpaymentPermissionId uniqueidentifier = 'E23802D7-F3B5-431E-A72E-7133C3C9343F'; declare @CRMInpaymentIssuanceElementPermissionId uniqueidentifier = 'ACF5606C-B566-426b-BAEC-E74061095BEB'; declare @CRMInpaymentFullAccessPermissionId uniqueidentifier = 'A27A46F9-BCD8-4e82-AE49-E58675DE52D7';
declare @CRMRelationshipCreateElementPermissionId uniqueidentifier= 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2'; declare @ViewRelationshipPermissionId uniqueidentifier = '186D4CC4-6924-4848-93AC-6D8DE389CB08'; declare @EditRelationshipPermissionId uniqueidentifier = '0B980531-D097-4EC1-8616-56E6AB15770E'; declare @CRMRelationshipIssuanceElementPermissionId uniqueidentifier = '679876A7-8882-43d4-8FC2-3E7C9DB58ADB'; declare @CRMRelationshipFullAccessPermissionId uniqueidentifier = '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30'; set @usermask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55 declare @PermissionRoleAuthor uniqueidentifier = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92'; declare @PermissionRoleTypeResponsible uniqueidentifier = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15'; declare @PermissionRoleTypeParticipantWork uniqueidentifier = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386'; declare @adminUser bigint=0; declare @adminUid uniqueidentifier='F0E949BF-4DA4-4C02-B04C-CA61964B4FE8'; declare @PermissionRoleTypeInforms uniqueidentifier = '21888C0C-8BCA-4B26-AF13-4C497EECCED6';
select @adminUser=Id from [User] where Uid=@adminUid; set @permissionContactId= CASE WHEN @permissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN @permissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN @permissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN @permissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN @permissionId= @FullContractorPermissionId THEN @FullContactPermissionId
ELSE @permissionId END set @permissionSaleId= CASE WHEN @permissionId= @CRMContractorCreateElementPermissionId THEN @CRMSaleCreateElementPermissionId WHEN @permissionId= @CRMContractorIssuancePermissionId THEN @CRMSaleIssuancePermissionId WHEN @permissionId= @ViewContractorPermissionId THEN @ViewSalePermissionId WHEN @permissionId= @EditContractorPermissionId THEN @EditSalePermissionId WHEN @permissionId= @FullContractorPermissionId THEN @FullSalePermissionId
ELSE @permissionId END set @permissionInpaymentId= CASE WHEN @permissionId= @CRMSaleCreateElementPermissionId THEN @CRMInpaymentCreateElementPermissionId WHEN @permissionId= @CRMSaleIssuancePermissionId THEN @CRMInpaymentIssuanceElementPermissionId WHEN @permissionId= @ViewSalePermissionId THEN @ViewInpaymentPermissionId WHEN @permissionId= @EditSalePermissionId THEN @EditInpaymentPermissionId WHEN @permissionId= @FullSalePermissionId THEN @CRMInpaymentFullAccessPermissionId ELSE @permissionId END set @permissionRelationshipId= CASE WHEN @permissionId= @CRMContractorCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN @permissionId= @CRMContractorIssuancePermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN @permissionId= @ViewContractorPermissionId THEN @ViewRelationshipPermissionId WHEN @permissionId= @EditContractorPermissionId THEN @EditRelationshipPermissionId WHEN @permissionId= @FullContractorPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE @permissionId END
-- Забрать привилегию из контактов
select c.Id as ContactId,c.PermissionId,c.UserSecuritySetCacheId,c.InheritedFromNumber,con.Contractor,c.id,con.id conid into #ContactPersonPermissionDel from ContactPersonPermission c inner join Contact con on con.id=c.Contact where c.InheritedFromNumber > 0 and c.PermissionId=@permissionContactId and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Contact] con where con.[Id]=c.[Contact])|@usermask) when @PermissionRoleTypeResponsible then (select (contr.Responsible|@usermask) from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact) ELSE @userSecuritySetCacheId end and c.PermissionRole=@permissionRole and con.Contractor=@ContractorId
update c set c.InheritedFromNumber=c.InheritedFromNumber-1 from ContactPersonPermission c join #ContactPersonPermissionDel ct on ct.ContactId=c.Id where ct.ContactId=c.Id
-- Грохнуть пустые контакты
delete from ContactPersonPermission where InheritedFromNumber<=0
-- Забрать привилегию из cделки select c.Id as SaleId,c.PermissionId,Sale,c.InheritedFromNumber,c.UserSecuritySetCacheId into #SalePersonPermissionDel from SalePersonPermission c inner join sale con on con.id=c.Sale where c.InheritedFromNumber > 0 and con.Contractor=@ContractorId and c.PermissionId=@permissionSaleId and c.PermissionRole=@permissionRole and c.UserSecuritySetCacheId= case c.PermissionRole when @PermissionRoleAuthor then ((select [Author] from [Sale] con where con.[Id]=c.[Sale])|@usermask) when @PermissionRoleTypeResponsible then ((select [Responsible] from [Sale] con where con.[Id]=c.[Sale])|@usermask) ELSE @userSecuritySetCacheId end
update c set InheritedFromNumber=c.InheritedFromNumber-1 from SalePersonPermission c join #SalePersonPermissionDel ct on ct.SaleId=c.Id where ct.SaleId=c.Id
-- Грохнуть пустые delete from SalePersonPermission where InheritedFromNumber=0;
-- Забрать привилегию из взаимоотношения select c.Id as RelationshipId,c.PermissionId,Relationship,c.InheritedFromNumber,c.UserSecuritySetCacheId into #RelationshipPersonPermissionDel from RelationshipPersonPermission c inner join Relationship con on con.id=c.Relationship where c.InheritedFromNumber > 0 and con.Contractor=@ContractorId and c.PermissionRole=@permissionRole and ((PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser ) or (PermissionRole !=@PermissionRoleTypeParticipantWork ))/*В случае с участниками берем только если пришел системный пользователь*/ and c.PermissionId=@permissionRelationshipId and c.UserSecuritySetCacheId= case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Relationship] con where con.[Id]=c.[Relationship])|@usermask) ELSE @userSecuritySetCacheId end
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersonPermissionDel ([RelationshipId],[PermissionId],[UserSecuritySetCacheId],[Relationship] ) select [Id],[PermissionId],[UserSecuritySetCacheId],[Relationship]
from RelationshipPersonPermission c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeParticipantWork and exists ( select [RelationshipId] from #RelationshipPersonPermissionDel t where PermissionRole =@PermissionRoleTypeParticipantWork and c.PermissionId=t.PermissionId and c.Relationship=t.Relationship )
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersonPermissionDel ([RelationshipId],[PermissionId],[UserSecuritySetCacheId],[Relationship]) select [Id],[PermissionId],[UserSecuritySetCacheId],[Relationship]
from RelationshipPersonPermission c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeInforms and exists ( select [RelationshipId] from #RelationshipPersonPermissionDel t where PermissionRole =@PermissionRoleTypeInforms and c.PermissionId=t.PermissionId and c.Relationship=t.Relationship )
update c set InheritedFromNumber=c.InheritedFromNumber-1 from RelationshipPersonPermission c join #RelationshipPersonPermissionDel ct on ct.RelationshipId=c.Id where ct.RelationshipId=c.Id
-- Грохнуть пустые delete from RelationshipPersonPermission where InheritedFromNumber<=0; drop table #SalePersonPermissionDel drop table #ContactPersonPermissionDel; drop table #RelationshipPersonPermissionDel; COMMIT TRANSACTION;
END

CREATE procedure [CheckPermWhenDelCategories] ( @CategoryId bigint , @ContractorId bigint ) AS BEGIN BEGIN TRANSACTION; declare @usermask bigint; set @usermask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55 declare @CRMContractorCreateElementPermissionId uniqueidentifier= '44ED88D4-A466-4fed-B194-B8288560CB48'; declare @CRMContractorIssuancePermissionId uniqueidentifier= '1CD25727-7CE6-443c-84BD-7975822C79E6'; declare @ViewContractorPermissionId uniqueidentifier= '9219C9AB-7E68-47B1-8939-FF6FC4439DA0'; declare @EditContractorPermissionId uniqueidentifier= '8C932B94-2F9C-488E-A36F-949A11C9741E'; declare @CRMContractorFullAccessPermissionId uniqueidentifier= 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5';
declare @CRMContactCreateElementPermissionId uniqueidentifier= 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5'; declare @CRMContactIssuancePermissionId uniqueidentifier= '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1'; declare @ViewContactPermissionId uniqueidentifier= '3626682F-B657-419E-9A8E-392C14ABE455'; declare @EditContactPermissionId uniqueidentifier= 'ABC752AD-3623-4F14-A47F-121999890D2C'; declare @CRMContactFullAccessPermissionId uniqueidentifier= '76B481D5-2E07-4417-9098-A57DE879FA56';
declare @CRMRelationshipCreateElementPermissionId uniqueidentifier= 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2'; declare @ViewRelationshipPermissionId uniqueidentifier= '186D4CC4-6924-4848-93AC-6D8DE389CB08'; declare @EditRelationshipPermissionId uniqueidentifier= '0B980531-D097-4EC1-8616-56E6AB15770E'; declare @CRMRelationshipIssuanceElementPermissionId uniqueidentifier= '679876A7-8882-43d4-8FC2-3E7C9DB58ADB'; declare @CRMRelationshipFullAccessPermissionId uniqueidentifier= '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';
declare @CRMSaleIssuancePermissionId uniqueidentifier= 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA'; declare @ViewSalePermissionId uniqueidentifier= 'AAE16346-B0E6-4949-ACAB-0914C573DE55'; declare @EditSalePermissionId uniqueidentifier= 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74'; declare @CRMSaleCreateElementPermissionId uniqueidentifier= '7DB77821-D6D3-4dd2-AD1B-798330506ADC'; declare @CRMSaleFullAccessPermissionId uniqueidentifier= 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';
declare @PermissionRoleTypeParticipantWork uniqueidentifier = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386'; declare @PermissionRoleAuthor uniqueidentifier = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92'; declare @PermissionRoleTypeInforms uniqueidentifier = '21888C0C-8BCA-4B26-AF13-4C497EECCED6'; declare @PermissionRoleTypeResponsible uniqueidentifier = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15'; declare @adminUid uniqueidentifier='F0E949BF-4DA4-4C02-B04C-CA61964B4FE8'; declare @adminUser bigint=0;
select @adminUser=Id from [User] where Uid=@adminUid;
select t.* into #TemplateContractorPermissionDel from TemplateContractorPermission t join Category c on c.ContainerContractorPermissio=t.ContainerContractor where c.Id=@CategoryId
-- Забрать привилегию из контрагента select c.Id as ContractorId,t.PermissionId,t.[User],t.[Group],c.PermissionRole,t.OrganizationItemEmployee,Contractor,
case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Contractor] con where con.[Id]=c.[Contractor])|@usermask) when @PermissionRoleTypeResponsible then ((select [Responsible] from [Contractor] con where con.[Id]=c.[Contractor])|@usermask) ELSE t.UserSecuritySetCacheId end UserSecuritySetCacheId ,t.OrganizationItemPosition ,count(1) as Child into #ContractorPersonPermissionDel from ContractorPersonPermission c left join #TemplateContractorPermissionDel t on c.PermissionId=t.permissionId and t.PermissionRole=c.PermissionRole and c.UserSecuritySetCacheId= case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Contractor] con where con.[Id]=c.[Contractor])|@usermask) when @PermissionRoleTypeResponsible then ((select [Responsible] from [Contractor] con where con.[Id]=c.[Contractor])|@usermask) ELSE t.userSecuritySetCacheId end where c.InheritedFromNumber > 0 and t.[Id] is not null and c.Contractor=@ContractorId group by c.Id ,t.PermissionId,t.[User],t.[Group],c.PermissionRole,t.OrganizationItemEmployee,Contractor,t.UserSecuritySetCacheId,t.OrganizationItemPosition,c.[Contractor]
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into #ContractorPersonPermissionDel ([ContractorId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Contractor],[Child]) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Contractor] ,(select count(1) from #TemplateContractorPermissionDel t where c.PermissionId=t.permissionId and c.PermissionRole=t.PermissionRole and [User]=@adminUser) from ContractorPersonPermission c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeParticipantWork and exists ( select [ContractorId] from #ContractorPersonPermissionDel t where PermissionRole =@PermissionRoleTypeParticipantWork and c.PermissionId=t.permissionId and c.Contractor=t.Contractor )
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into #ContractorPersonPermissionDel ([ContractorId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Contractor],[Child]) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Contractor] ,(select count(1) from #TemplateContractorPermissionDel t where c.PermissionId=t.permissionId and c.PermissionRole=t.PermissionRole and [User]=@adminUser) from ContractorPersonPermission c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeInforms and exists ( select [ContractorId] from #ContractorPersonPermissionDel t where PermissionRole =@PermissionRoleTypeInforms and c.PermissionId=t.permissionId and c.Contractor=t.Contractor )
/*Перезаписать реальных пользователей в ответственных */ update #ContractorPersonPermissionDel set [User]= (select Responsible from Contractor con where con.[Id]=Contractor), [UserSecuritySetCacheId]= (select (Responsible|@usermask) from Contractor con where con.[Id]=Contractor) where PermissionRole=@PermissionRoleTypeResponsible
update c set c.InheritedFromNumber=c.InheritedFromNumber-ct.Child from ContractorPersonPermission c join #ContractorPersonPermissionDel ct on ct.ContractorId=c.Id where ct.ContractorId=c.Id and ct.UserSecuritySetCacheId=c.UserSecuritySetCacheId
-- Забрать привилегию из контактов select c.Id as ContactId,c.PermissionId,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Contact,t.UserSecuritySetCacheId,c.InheritedFromNumber,t.OrganizationItemPosition into #ContactPersonPermissionDel from ContactPersonPermission c left join #ContractorPersonPermissionDel t on c.PermissionId=
CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMContactFullAccessPermissionId ELSE t.PermissionId END and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Contact] con where con.[Id]=c.[Contact])|@usermask) when @PermissionRoleTypeResponsible then (select (contr.Responsible|@usermask) from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact) ELSE t.userSecuritySetCacheId end and t.PermissionRole=c.PermissionRole left join Contact ca on c.Contact=ca.id and ca.InheritPermissions=1 left join ContractorPersonPermission cc on cc.Id=t.ContractorId where c.InheritedFromNumber > 0 and t.ContractorId is not null and ca.Contractor=t.[Contractor] and cc.InheritedFromNumber<=0
update c set c.InheritedFromNumber=c.InheritedFromNumber-1 from ContactPersonPermission c join #ContactPersonPermissionDel ct on ct.ContactId=c.Id where ct.ContactId=c.Id
-- Грохнуть пустые контакты delete from ContactPersonPermission where InheritedFromNumber=0
-- Забрать привилегию из Сделок select c.Id as SaleId,c.PermissionId,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Sale,t.UserSecuritySetCacheId,c.InheritedFromNumber,t.OrganizationItemPosition into #SalePersonPermissionDel from SalePersonPermission c left join #ContractorPersonPermissionDel t on CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMSaleCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMSaleIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewSalePermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditSalePermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMSaleFullAccessPermissionId ELSE t.PermissionId END = c.PermissionId and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then ((select [Author] from [Sale] con where con.[Id]=c.[Sale])|@usermask) when @PermissionRoleTypeResponsible then (select (Responsible|@usermask) from Sale con where con.[Id]=Sale) ELSE t.userSecuritySetCacheId end and t.PermissionRole=c.PermissionRole left join Sale ca on c.Sale=ca.id and ca.InheritPermissions=1 left join ContractorPersonPermission cc on cc.Id=t.ContractorId where c.InheritedFromNumber > 0 and t.ContractorId is not null and ca.Contractor=t.[Contractor] and cc.InheritedFromNumber<=0
update c set c.InheritedFromNumber=c.InheritedFromNumber-1 from SalePersonPermission c join #SalePersonPermissionDel ct on ct.SaleId=c.Id where ct.SaleId=c.Id
-- Грохнуть пустые привилегии сделок delete from SalePersonPermission where InheritedFromNumber=0
-- работаем с взаимоотношениями -- Забрать привилегию у взаимоотношения из контрагента select c.[Id] as RelationshipId,c.PermissionId,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,Relationship,c.UserSecuritySetCacheId,c.OrganizationItemPosition into #RelationshipPersonPermissionDel from RelationshipPersonPermission c where c.InheritedFromNumber > 0 and c.Relationship in (select r.Id from Relationship r where r.Contractor = @ContractorId ) and exists (select 1 from #ContractorPersonPermissionDel t left join Relationship ca on c.Relationship=ca.id and ca.InheritPermissions=1 left join ContractorPersonPermission cc on cc.Id=t.ContractorId where CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END =c.PermissionId and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Relationship] con where con.[Id]=c.[Relationship])|@usermask) when @PermissionRoleTypeResponsible then (select (Relationship|@usermask) from Relationship con where con.[Id]=Relationship) ELSE t.userSecuritySetCacheId end and c.PermissionRole=t.PermissionRole and ca.Contractor=t.[Contractor] and cc.InheritedFromNumber<=0 )
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersonPermissionDel ([RelationshipId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship] ) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship]
from RelationshipPersonPermission c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeParticipantWork and exists ( select [RelationshipId] from #RelationshipPersonPermissionDel t where PermissionRole =@PermissionRoleTypeParticipantWork and c.PermissionId=t.permissionId and c.Relationship=t.Relationship )
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersonPermissionDel ([RelationshipId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship]) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship]
from RelationshipPersonPermission c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeInforms and exists ( select [RelationshipId] from #RelationshipPersonPermissionDel t where PermissionRole =@PermissionRoleTypeInforms and c.PermissionId=t.permissionId and c.Relationship=t.Relationship )
update c set c.InheritedFromNumber=c.InheritedFromNumber-1 from RelationshipPersonPermission c join #RelationshipPersonPermissionDel ct on ct.RelationshipId=c.Id where ct.RelationshipId=c.Id and ct.UserSecuritySetCacheId=c.UserSecuritySetCacheId and ct.PermissionRole=c.PermissionRole
delete from RelationshipPersonPermission where InheritedFromNumber<=0
-- Грохнуть пустые пермишены в контрагенте delete from ContractorPersonPermission where InheritedFromNumber<=0 drop table #SalePersonPermissionDel; drop table #TemplateContractorPermissionDel; drop table #ContractorPersonPermissionDel; drop table #ContactPersonPermissionDel; drop table #RelationshipPersonPermissionDel
-- Вычислим контейнер категории. Вычислим все права в категории COMMIT TRANSACTION; END

create procedure [CheckPermWhenAddCategories] ( @CategoryId bigint , @ContractorId bigint ) AS BEGIN BEGIN TRANSACTION; declare @insCounter bigint, @insStartId bigint, @insEndId bigint; declare @usermask bigint set @usermask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55
declare @PermissionRoleTypeResponsible uniqueidentifier = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15';
declare @CRMContractorCreateElementPermissionId uniqueidentifier= '44ED88D4-A466-4fed-B194-B8288560CB48'; declare @CRMContractorIssuancePermissionId uniqueidentifier= '1CD25727-7CE6-443c-84BD-7975822C79E6'; declare @ViewContractorPermissionId uniqueidentifier= '9219C9AB-7E68-47B1-8939-FF6FC4439DA0'; declare @EditContractorPermissionId uniqueidentifier= '8C932B94-2F9C-488E-A36F-949A11C9741E'; declare @CRMContractorFullAccessPermissionId uniqueidentifier= 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5';
declare @CRMRelationshipCreateElementPermissionId uniqueidentifier= 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2'; declare @ViewRelationshipPermissionId uniqueidentifier= '186D4CC4-6924-4848-93AC-6D8DE389CB08'; declare @EditRelationshipPermissionId uniqueidentifier= '0B980531-D097-4EC1-8616-56E6AB15770E'; declare @CRMRelationshipIssuanceElementPermissionId uniqueidentifier= '679876A7-8882-43d4-8FC2-3E7C9DB58ADB'; declare @CRMRelationshipFullAccessPermissionId uniqueidentifier= '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';
declare @CRMContactCreateElementPermissionId uniqueidentifier= 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5'; declare @CRMContactIssuancePermissionId uniqueidentifier= '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1'; declare @ViewContactPermissionId uniqueidentifier= '3626682F-B657-419E-9A8E-392C14ABE455'; declare @EditContactPermissionId uniqueidentifier= 'ABC752AD-3623-4F14-A47F-121999890D2C'; declare @CRMContactFullAccessPermissionId uniqueidentifier= '76B481D5-2E07-4417-9098-A57DE879FA56';
declare @CRMSaleIssuancePermissionId uniqueidentifier= 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA'; declare @ViewSalePermissionId uniqueidentifier= 'AAE16346-B0E6-4949-ACAB-0914C573DE55'; declare @EditSalePermissionId uniqueidentifier= 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74'; declare @CRMSaleCreateElementPermissionId uniqueidentifier= '7DB77821-D6D3-4dd2-AD1B-798330506ADC'; declare @CRMSaleFullAccessPermissionId uniqueidentifier= 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';
declare @CRMInpaymentCreateElementPermissionId uniqueidentifier= 'D130BB5F-6A26-4e37-B62C-F3B443E3BF53'; declare @ViewInpaymentPermissionId uniqueidentifier = '837FF0F3-03A7-4A17-86EA-A72B3AB4886B'; declare @EditInpaymentPermissionId uniqueidentifier = 'E23802D7-F3B5-431E-A72E-7133C3C9343F'; declare @CRMInpaymentIssuanceElementPermissionId uniqueidentifier = 'ACF5606C-B566-426b-BAEC-E74061095BEB';
declare @PermissionRoleTypeParticipantWork uniqueidentifier = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386'; declare @PermissionRoleAuthor uniqueidentifier = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92'; declare @PermissionRoleTypeInforms uniqueidentifier = '21888C0C-8BCA-4B26-AF13-4C497EECCED6'; declare @adminUid uniqueidentifier='F0E949BF-4DA4-4C02-B04C-CA61964B4FE8'; declare @adminUser bigint=0; declare @NullUid uniqueidentifier = '00000000-0000-0000-0000-000000000000';
select @adminUser=Id from [User] where Uid=@adminUid;
select t.* into #TemplateContractorPermissionDel from TemplateContractorPermission t join Category c on c.ContainerContractorPermissio=t.ContainerContractor where c.Id=@CategoryId and AddPermission !=1 and DelPermission!=1
-- Добавить привилегии в контрагента
select -1 as [Id], t.PermissionId,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,ca.Id Contractor,t.UserSecuritySetCacheId,t.OrganizationItemPosition,0 Ins ,count(1) as Child into #ContractorPersonPermissionUpd from ContractorPersonPermission c left join #TemplateContractorPermissionDel t on c.PermissionId=t.permissionId and case c.PermissionRole when @PermissionRoleAuthor then (@adminUser|@usermask) when @PermissionRoleTypeResponsible then (@adminUser|@usermask) ELSE c.userSecuritySetCacheId end=t.userSecuritySetCacheId and c.PermissionRole=t.PermissionRole left join Contractor ca on c.Contractor=ca.id and ca.InheritPermissions=1 where c.InheritedFromNumber > 0 and t.id is not null and c.Contractor=@ContractorId group by t.PermissionId,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,ca.Id,t.UserSecuritySetCacheId,t.OrganizationItemPosition
select @insCounter=max([Id]) from #ContractorPersonPermissionUpd
/*Добавить пермишены реальных пользователей для исполнителей*/ insert into #ContractorPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,0 [Ins],c.[Child] from [M_Contractor_ParticipantWork] m left join #ContractorPersonPermissionUpd c on m.Parent=c.Contractor where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and Ins=0 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Contractor],c.[Child]
select @insCounter=max([Id]) from #ContractorPersonPermissionUpd
insert into #ContractorPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,0 [Ins],c.[Child] from [M_Contractor_Informs] m left join #ContractorPersonPermissionUpd c on m.Parent=c.Contractor where PermissionRole in (@PermissionRoleTypeInforms) and [User]=@adminUser and Ins=0 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Contractor],c.[Child]
/*Перезаписать реальных пользователей в ответственных */ update #ContractorPersonPermissionUpd set [User]= (select Responsible from Contractor con where con.[Id]=Contractor), [UserSecuritySetCacheId]= (select (Responsible|@usermask) from Contractor con where con.[Id]=Contractor) where PermissionRole=@PermissionRoleTypeResponsible
/*Перезаписать реальных пользователей в ответственных */ update #ContractorPersonPermissionUpd set [User]= (select [CreationAuthor] from Contractor con where con.[Id]=Contractor), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Contractor con where con.[Id]=Contractor) where PermissionRole=@PermissionRoleAuthor
update c set c.InheritedFromNumber=c.InheritedFromNumber+t.Child from ContractorPersonPermission c join #ContractorPersonPermissionUpd t on t.PermissionId=c.PermissionId and t.UserSecuritySetCacheId=c.UserSecuritySetCacheId where c.Contractor=t.Contractor
-- Добавить недостающие привилегии в контрагента
insert into #ContractorPersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contractor,UserSecuritySetCacheId,OrganizationItemPosition,Ins,Child) select (ROW_NUMBER() OVER (ORDER BY t.PermissionId))-1, t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition,1,count(1) as Child from Contractor c join #TemplateContractorPermissionDel t on 1=1 -- взяди пермишены которые надо обновить из контейнера left outer join ContractorPersonPermission cp on cp.Contractor=c.Id and cp.PermissionId=t.PermissionId and case cp.PermissionRole when @PermissionRoleAuthor then (@adminUser|@usermask) when @PermissionRoleTypeResponsible then (@adminUser|@usermask) ELSE cp.userSecuritySetCacheId end=t.userSecuritySetCacheId and cp.PermissionRole=t.PermissionRole and cp.InheritedFromNumber > 0 left join Category ca on ca.ContainerContractorPermissio=t.ContainerContractor -- выьащили категорию в которую входит пермишен из контейнера where -- соединили категории из контейнера и из контрагента c.InheritPermissions>=1 and cp.Contractor is null and c.Id=@ContractorId group by t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition
select @insCounter=max([Id]) from #ContractorPersonPermissionUpd /*Добавить пермишены реальных пользователей для исполнителей*/ insert into #ContractorPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,1 [Ins],c.[Child] from [M_Contractor_ParticipantWork] m left join #ContractorPersonPermissionUpd c on m.Parent=c.Contractor where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Contractor],c.[Child]
select @insCounter=max([Id]) from #ContractorPersonPermissionUpd
insert into #ContractorPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,1 [Ins],c.[Child] from [M_Contractor_Informs] m left join #ContractorPersonPermissionUpd c on m.Parent=c.Contractor where PermissionRole in (@PermissionRoleTypeInforms) and [User]=@adminUser and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Contractor],c.[Child]
/*Перезаписать реальных пользователей в ответственных */ update #ContractorPersonPermissionUpd set [User]= (select Responsible from Contractor con where con.[Id]=Contractor), [UserSecuritySetCacheId]= (select (Responsible|@usermask) from Contractor con where con.[Id]=Contractor) where PermissionRole=@PermissionRoleTypeResponsible
/*Перезаписать реальных пользователей в ответственных */ update #ContractorPersonPermissionUpd set [User]= (select [CreationAuthor] from Contractor con where con.[Id]=Contractor), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Contractor con where con.[Id]=Contractor) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from #ContractorPersonPermissionUpd EXECUTE [G_GenId] 'ContractorPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into ContractorPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contractor,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id, t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Contractor,t.UserSecuritySetCacheId,NEWID() as Uid,Child as InheritedFromNumber,t.OrganizationItemPosition from #ContractorPersonPermissionUpd t where Ins=1
-- Добавить привилегии к контактам
-- Добавить недостающие привилегии к контактам
select ROW_NUMBER() over (order by t.[Id]) - 1 Id, CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMContactFullAccessPermissionId ELSE t.PermissionId END PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Contact,t.UserSecuritySetCacheId,t.OrganizationItemPosition,1 Ins into #ContactPersonPermissionUpd from Contact c left join #ContractorPersonPermissionUpd t on t.Contractor=c.Contractor left outer join ContactPersonPermission cp on cp.Contact=c.Id and cp.InheritedFromNumber != 0 and CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMContactFullAccessPermissionId ELSE t.PermissionId END = cp.PermissionId and cp.UserSecuritySetCacheId=t.UserSecuritySetCacheId and cp.PermissionRole=t.PermissionRole where t.Contractor =@ContractorId and cp.Contact is null and c.InheritPermissions=1
/*Перезаписать реальных пользователей в ответственных */ update #ContactPersonPermissionUpd set [User]= (select contr.Responsible from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact), [UserSecuritySetCacheId]= (select (contr.Responsible|@usermask) from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact) where PermissionRole=@PermissionRoleTypeResponsible /*Перезаписать реальных пользователей в ответственных */ update #ContactPersonPermissionUpd set [User]= (select [CreationAuthor] from Contact con where con.[Id]=Contact), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Contact con where con.[Id]=Contact) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from #ContactPersonPermissionUpd EXECUTE [G_GenId] 'ContactPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into ContactPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contact,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id,t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Contact,t.UserSecuritySetCacheId,NEWID(),1 ,t.OrganizationItemPosition from #ContactPersonPermissionUpd t where Ins=1
-- Добавить привилегии к сделкам -- Добавить недостающие привилегии к сделкам
select ROW_NUMBER() over (order by t.[Id]) - 1 Id, CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMSaleCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMSaleIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewSalePermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditSalePermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMSaleFullAccessPermissionId ELSE t.PermissionId END PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Sale,t.UserSecuritySetCacheId,t.OrganizationItemPosition,1 Ins into #SalePersonPermissionUpd from Sale c left join #ContractorPersonPermissionUpd t on t.Contractor=c.Contractor left outer join SalePersonPermission cp on cp.Sale=c.Id and cp.InheritedFromNumber > 0 and CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMSaleCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMSaleIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewSalePermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditSalePermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMSaleFullAccessPermissionId ELSE t.PermissionId END = cp.PermissionId and cp.UserSecuritySetCacheId=t.UserSecuritySetCacheId and cp.PermissionRole=t.PermissionRole where t.Contractor =@ContractorId and c.InheritPermissions=1 and cp.Sale is null
/*Перезаписать реальных пользователей в ответственных */ update #SalePersonPermissionUpd set [User]= (select Responsible from Sale con where con.[Id]=Sale), [UserSecuritySetCacheId]= (select (Responsible|@usermask) from sale con where con.[Id]=Sale) where PermissionRole=@PermissionRoleTypeResponsible /*Перезаписать реальных пользователей в ответственных */ update #SalePersonPermissionUpd set [User]= (select [Author] from Sale con where con.[Id]=Sale), [UserSecuritySetCacheId]= (select (Author|@usermask) from Sale con where con.[Id]=Sale) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from #SalePersonPermissionUpd EXECUTE [G_GenId] 'SalePersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into SalePersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Sale,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id,t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Sale,t.UserSecuritySetCacheId,NEWID(),1 ,t.OrganizationItemPosition from #SalePersonPermissionUpd t ;
-- Добавить недостающие привилегии к взаимоотношениям
select ROW_NUMBER() over (order by t.[Id]) -1 as [Id], CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END as PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Relationship,t.UserSecuritySetCacheId,t.OrganizationItemPosition,1 Ins into #RelationshipPersonPermissionUpd from Relationship c left join #ContractorPersonPermissionUpd t on t.Contractor=c.Contractor left outer join RelationshipPersonPermission cp on cp.Relationship=c.Id and cp.InheritedFromNumber > 0 and CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END = cp.PermissionId and cp.UserSecuritySetCacheId=t.UserSecuritySetCacheId and cp.PermissionRole=t.PermissionRole where t.Contractor =@ContractorId and c.InheritPermissions=1 and cp.Relationship is null and c.Contractor =@ContractorId and t.PermissionRole= case when t.PermissionRole=@PermissionRoleTypeParticipantWork and t.[User]!=@adminUser then @NullUid when t.PermissionRole=@PermissionRoleTypeInforms and t.[User]!=@adminUser then @NullUid else t.PermissionRole end
select @insCounter=max([Id]) from #RelationshipPersonPermissionUpd /*Добавить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,[Ins]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[UserID] [User] ,[Group] ,[OrganizationItemPosition] ,m.[UserID]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,1 [Ins] from [RelationshipUser] m left join #RelationshipPersonPermissionUpd c on m.RelationshipID=c.Relationship where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and m.[Status]=0 and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]
select @insCounter=max([Id]) from #RelationshipPersonPermissionUpd
/*Добавить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,[Ins]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[UserID] [User] ,[Group] ,[OrganizationItemPosition] ,m.[UserID]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,1 [Ins] from [RelationshipUser] m left join #RelationshipPersonPermissionUpd c on m.RelationshipID=c.Relationship where PermissionRole =@PermissionRoleTypeInforms and [User]=@adminUser and m.[Status]=1 and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]
/*Перезаписать реальных пользователей в ответственных */ update #RelationshipPersonPermissionUpd set [User]= (select [CreationAuthor] from Relationship con where con.[Id]=Relationship), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Relationship con where con.[Id]=Relationship) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from #RelationshipPersonPermissionUpd EXECUTE [G_GenId] 'RelationshipPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into RelationshipPersonPermission([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id,t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Relationship,t.UserSecuritySetCacheId,NEWID(),1 ,t.OrganizationItemPosition from #RelationshipPersonPermissionUpd t where Ins=1 drop table #ContractorPersonPermissionUpd; drop table #TemplateContractorPermissionDel; drop table #SalePersonPermissionUpd; drop table #ContactPersonPermissionUpd; drop table #RelationshipPersonPermissionUpd; COMMIT TRANSACTION; END

CREATE procedure [CheckPermWhenAddLeadCategories] ( @CategoryId bigint , @LeadId bigint ) AS BEGIN BEGIN TRANSACTION; declare @insCounter bigint, @insStartId bigint, @insEndId bigint; declare @usermask bigint set @usermask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55
declare @PermissionRoleTypeResponsible uniqueidentifier = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15'; declare @CRMContractorCreateElementPermissionId uniqueidentifier= '44ED88D4-A466-4fed-B194-B8288560CB48'; declare @CRMContractorIssuancePermissionId uniqueidentifier= '1CD25727-7CE6-443c-84BD-7975822C79E6'; declare @ViewContractorPermissionId uniqueidentifier= '9219C9AB-7E68-47B1-8939-FF6FC4439DA0'; declare @EditContractorPermissionId uniqueidentifier= '8C932B94-2F9C-488E-A36F-949A11C9741E';
declare @CRMContactCreateElementPermissionId uniqueidentifier= 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5'; declare @CRMContactIssuancePermissionId uniqueidentifier= '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1'; declare @ViewContactPermissionId uniqueidentifier= '3626682F-B657-419E-9A8E-392C14ABE455'; declare @EditContactPermissionId uniqueidentifier= 'ABC752AD-3623-4F14-A47F-121999890D2C';
declare @CRMSaleIssuancePermissionId uniqueidentifier= 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA'; declare @ViewSalePermissionId uniqueidentifier= 'AAE16346-B0E6-4949-ACAB-0914C573DE55'; declare @EditSalePermissionId uniqueidentifier= 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74'; declare @CRMSaleCreateElementPermissionId uniqueidentifier= '7DB77821-D6D3-4dd2-AD1B-798330506ADC';
declare @CRMInpaymentCreateElementPermissionId uniqueidentifier= 'D130BB5F-6A26-4e37-B62C-F3B443E3BF53'; declare @ViewInpaymentPermissionId uniqueidentifier = '837FF0F3-03A7-4A17-86EA-A72B3AB4886B'; declare @EditInpaymentPermissionId uniqueidentifier = 'E23802D7-F3B5-431E-A72E-7133C3C9343F'; declare @CRMInpaymentIssuanceElementPermissionId uniqueidentifier = 'ACF5606C-B566-426b-BAEC-E74061095BEB';
declare @CRMRelationshipCreateElementPermissionId uniqueidentifier= 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2'; declare @ViewRelationshipPermissionId uniqueidentifier= '186D4CC4-6924-4848-93AC-6D8DE389CB08'; declare @EditRelationshipPermissionId uniqueidentifier= '0B980531-D097-4EC1-8616-56E6AB15770E'; declare @CRMRelationshipIssuanceElementPermissionId uniqueidentifier= '679876A7-8882-43d4-8FC2-3E7C9DB58ADB'; declare @CRMRelationshipFullAccessPermissionId uniqueidentifier= '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';
declare @ViewLeadPermissionId uniqueidentifier= 'C660E4B4-03BF-4315-9600-5086E47653B4'; declare @EditLeadPermissionId uniqueidentifier= 'AE298CD3-A16A-4B55-ACFC-545E4A0EBD48'; declare @CRMLeadCreateElementPermissionId uniqueidentifier= '643FE44B-8192-4615-B853-106CD6F09EDE'; declare @CRMLeadFullAccessPermissionId uniqueidentifier= '90BE803C-7857-4F2D-A8B4-129264504101'; declare @CRMLeadIssuanceElementPermissionId uniqueidentifier= 'E70A9AD1-80B2-4435-80E9-EF8E14B974CE';
declare @PermissionRoleTypeParticipantWork uniqueidentifier = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386'; declare @PermissionRoleAuthor uniqueidentifier = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92'; declare @PermissionRoleTypeInforms uniqueidentifier = '21888C0C-8BCA-4B26-AF13-4C497EECCED6'; declare @adminUid uniqueidentifier='F0E949BF-4DA4-4C02-B04C-CA61964B4FE8'; declare @adminUser bigint=0; declare @NullUid uniqueidentifier = '00000000-0000-0000-0000-000000000000';
select @adminUser=Id from [User] where Uid=@adminUid;
select t.* into #TemplateLeadPermissionDel from TemplateLeadPermission t join Category c on c.ContainerLeadPermission=t.ContainerLead where c.Id=@CategoryId and AddPermission !=1 and DelPermission!=1
-- Добавить привилегии в лида
select -1 as [Id], t.PermissionId,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,ca.Id Lead,t.UserSecuritySetCacheId,t.OrganizationItemPosition,0 Ins ,count(1) as Child into #LeadPersonPermissionUpd from LeadPersonPermission c left join #TemplateLeadPermissionDel t on c.PermissionId=t.permissionId and case c.PermissionRole when @PermissionRoleAuthor then (@adminUser|@usermask) when @PermissionRoleTypeResponsible then (@adminUser|@usermask) ELSE c.userSecuritySetCacheId end=t.userSecuritySetCacheId and c.PermissionRole=t.PermissionRole left join Lead ca on c.Lead=ca.id and ca.InheritPermissions=1 where c.InheritedFromNumber > 0 and t.id is not null and c.Lead=@LeadId group by t.PermissionId,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,ca.Id,t.UserSecuritySetCacheId,t.OrganizationItemPosition
select @insCounter=max([Id]) from #LeadPersonPermissionUpd /*Добавить пермишены реальных пользователей для исполнителей*/ insert into #LeadPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,0 [Ins],c.[Child] from [M_Lead_ParticipantWork] m left join #LeadPersonPermissionUpd c on m.Parent=c.Lead where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and Ins=0 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Lead],c.[Child]
select @insCounter=max([Id]) from #LeadPersonPermissionUpd
insert into #LeadPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,0 [Ins],c.[Child] from [M_Lead_Informs] m left join #LeadPersonPermissionUpd c on m.Parent=c.Lead where PermissionRole in (@PermissionRoleTypeInforms) and [User]=@adminUser and Ins=0 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Lead],c.[Child]
/*Перезаписать реальных пользователей в ответственных */ update #LeadPersonPermissionUpd set [User]= (select Responsible from Lead con where con.[Id]=Lead), [UserSecuritySetCacheId]= (select (Responsible|@usermask) from Lead con where con.[Id]=Lead) where PermissionRole=@PermissionRoleTypeResponsible
/*Перезаписать реальных пользователей в ответственных */ update #LeadPersonPermissionUpd set [User]= (select [CreationAuthor] from Lead con where con.[Id]=Lead), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Lead con where con.[Id]=Lead) where PermissionRole=@PermissionRoleAuthor;
update c set c.InheritedFromNumber=c.InheritedFromNumber+t.Child from LeadPersonPermission c join #LeadPersonPermissionUpd t on t.PermissionId=c.PermissionId and t.UserSecuritySetCacheId=c.UserSecuritySetCacheId where c.Lead=t.Lead
-- Добавить недостающие привилегии в взаимоотношение insert into #LeadPersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Lead,UserSecuritySetCacheId,OrganizationItemPosition,Ins,Child) select (ROW_NUMBER() OVER (ORDER BY t.PermissionId))-1, t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition,1,count(1) as Child from Lead c join #TemplateLeadPermissionDel t on 1=1-- взяди мермишены которые надо обновить из контейнера left outer join LeadPersonPermission cp on cp.Lead=c.Id and cp.PermissionId=t.PermissionId and case cp.PermissionRole when @PermissionRoleAuthor then (@adminUser|@usermask) when @PermissionRoleTypeResponsible then (@adminUser|@usermask) ELSE cp.userSecuritySetCacheId end=t.userSecuritySetCacheId and cp.PermissionRole=t.PermissionRole and cp.InheritedFromNumber > 0 left join Category ca on ca.ContainerLeadPermission=t.ContainerLead -- втащили категорию в которую входит пермишен из контейнера where -- соединили категории из контейнера и из контрагента c.InheritPermissions>=1 and cp.Lead is null and c.Id=@LeadId group by t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition
select @insCounter=max([Id]) from #LeadPersonPermissionUpd /*Добавить пермишены реальных пользователей для исполнителей*/ insert into #LeadPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,1 [Ins],c.[Child] from [M_Lead_ParticipantWork] m left join #LeadPersonPermissionUpd c on m.Parent=c.Lead where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Lead],c.[Child]
select @insCounter=max([Id]) from #LeadPersonPermissionUpd;
insert into #LeadPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,1 [Ins],c.[Child] from [M_Lead_Informs] m left join #LeadPersonPermissionUpd c on m.Parent=c.Lead where PermissionRole in (@PermissionRoleTypeInforms) and [User]=@adminUser and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Lead],c.[Child]
/*Перезаписать реальных пользователей в ответственных */ update #LeadPersonPermissionUpd set [User]= (select Responsible from Lead con where con.[Id]=Lead), [UserSecuritySetCacheId]= (select (Responsible|@usermask) from Lead con where con.[Id]=Lead) where PermissionRole=@PermissionRoleTypeResponsible
/*Перезаписать реальных пользователей в ответственных */ update #LeadPersonPermissionUpd set [User]= (select [CreationAuthor] from Lead con where con.[Id]=Lead), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Lead con where con.[Id]=Lead) where PermissionRole=@PermissionRoleAuthor;
set @insStartId=0;
select @insCounter=count(1) from #LeadPersonPermissionUpd EXECUTE [G_GenId] 'LeadPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into LeadPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Lead,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id, t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Lead,t.UserSecuritySetCacheId,NEWID() as Uid,Child as InheritedFromNumber,t.OrganizationItemPosition from #LeadPersonPermissionUpd t where Ins=1
-- Добавить привилегии к взаимоотношениям
select - 1 as [Id], CASE WHEN c.PermissionId= @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN c.PermissionId= @CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipFullAccessPermissionId WHEN c.PermissionId= @ViewLeadPermissionId THEN @ViewRelationshipPermissionId WHEN c.PermissionId= @EditLeadPermissionId THEN @EditRelationshipPermissionId WHEN c.PermissionId= @CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE c.PermissionId END as PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,ca.Id Relationship,t.UserSecuritySetCacheId,t.OrganizationItemPosition,0 Ins into #RelationshipPersonPermissionUpd from RelationshipPersonPermission c left join Relationship r on r.id=c.Relationship and r.Lead is not null left join #LeadPersonPermissionUpd t on CASE WHEN t.PermissionId= @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipFullAccessPermissionId WHEN t.PermissionId= @ViewLeadPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditLeadPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END =c.PermissionId and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Relationship] con where con.[Id]=c.[Relationship])|@usermask) when @PermissionRoleTypeResponsible then (select (Relationship|@usermask) from Relationship con where con.[Id]=Relationship) ELSE t.userSecuritySetCacheId end
and c.PermissionRole=t.PermissionRole left join Relationship ca on c.Relationship=ca.id and ca.InheritPermissions=1 where c.InheritedFromNumber > 0 and t.userSecuritySetCacheId is not null;
update c set c.InheritedFromNumber=c.InheritedFromNumber-1 from RelationshipPersonPermission c join #RelationshipPersonPermissionUpd ct on ct.[Id]=c.[Id] where ct.Relationship=c.Relationship
-- Добавить недостающие привилегии к взаимоотношениям
insert into #RelationshipPersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,OrganizationItemPosition,Ins) select ROW_NUMBER() over (order by t.[Id]) -1, CASE WHEN t.PermissionId= @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewLeadPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditLeadPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Relationship,t.UserSecuritySetCacheId,t.OrganizationItemPosition,1 Ins from Relationship c left join #LeadPersonPermissionUpd t on t.Lead=c.Lead left outer join RelationshipPersonPermission cp on cp.Relationship=c.Id and cp.InheritedFromNumber > 0 and CASE WHEN t.PermissionId= @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewLeadPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditLeadPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END = cp.PermissionId and cp.UserSecuritySetCacheId=t.UserSecuritySetCacheId and cp.PermissionRole=t.PermissionRole where t.Lead is not null and c.InheritPermissions=1 and cp.Relationship is null and c.Lead is not null and t.PermissionRole= case when t.PermissionRole=@PermissionRoleTypeParticipantWork and t.[User]!=@adminUser then @NullUid when t.PermissionRole=@PermissionRoleTypeInforms and t.[User]!=@adminUser then @NullUid else t.PermissionRole end;
select @insCounter=max([Id]) from #RelationshipPersonPermissionUpd /*Добавить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,[Ins]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[UserID] [User] ,[Group] ,[OrganizationItemPosition] ,m.[UserID]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,1 [Ins] from [RelationshipUser] m left join #RelationshipPersonPermissionUpd c on m.RelationshipID=c.Relationship where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and m.[Status]=0 and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]
select @insCounter=max([Id]) from #RelationshipPersonPermissionUpd /*Добавить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,[Ins]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[UserID] [User] ,[Group] ,[OrganizationItemPosition] ,m.[UserID]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,1 [Ins] from [RelationshipUser] m left join #RelationshipPersonPermissionUpd c on m.RelationshipID=c.Relationship where PermissionRole =@PermissionRoleTypeInforms and [User]=@adminUser and m.[Status]=1 and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]
/*Перезаписать реальных пользователей в ответственных */ update #RelationshipPersonPermissionUpd set [User]= (select [CreationAuthor] from Relationship con where con.[Id]=Relationship), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Relationship con where con.[Id]=Relationship) where PermissionRole=@PermissionRoleAuthor;
set @insStartId=0;
select @insCounter=count(1) from #RelationshipPersonPermissionUpd EXECUTE [G_GenId] 'RelationshipPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into RelationshipPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id,t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Relationship,t.UserSecuritySetCacheId,NEWID(),1 ,t.OrganizationItemPosition from #RelationshipPersonPermissionUpd t where Ins=1
drop table #LeadPersonPermissionUpd; drop table #RelationshipPersonPermissionUpd; drop table #TemplateLeadPermissionDel;
COMMIT TRANSACTION; END

-- действие при удалении группы из Взаимоотношения CREATE procedure [CheckPermWhenDelLeadCategories] ( @CategoryId bigint , @LeadId bigint ) AS BEGIN BEGIN TRANSACTION;
declare @usermask bigint = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55 declare @CRMContractorCreateElementPermissionId uniqueidentifier= '44ED88D4-A466-4fed-B194-B8288560CB48'; declare @CRMContractorIssuancePermissionId uniqueidentifier= '1CD25727-7CE6-443c-84BD-7975822C79E6'; declare @ViewContractorPermissionId uniqueidentifier= '9219C9AB-7E68-47B1-8939-FF6FC4439DA0'; declare @EditContractorPermissionId uniqueidentifier= '8C932B94-2F9C-488E-A36F-949A11C9741E'; declare @CRMContractorFullAccessPermissionId uniqueidentifier= 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5';
declare @CRMContactCreateElementPermissionId uniqueidentifier= 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5'; declare @CRMContactIssuancePermissionId uniqueidentifier= '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1'; declare @ViewContactPermissionId uniqueidentifier= '3626682F-B657-419E-9A8E-392C14ABE455'; declare @EditContactPermissionId uniqueidentifier= 'ABC752AD-3623-4F14-A47F-121999890D2C'; declare @CRMContactFullAccessPermissionId uniqueidentifier= '76B481D5-2E07-4417-9098-A57DE879FA56';
declare @CRMSaleIssuancePermissionId uniqueidentifier= 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA'; declare @ViewSalePermissionId uniqueidentifier= 'AAE16346-B0E6-4949-ACAB-0914C573DE55'; declare @EditSalePermissionId uniqueidentifier= 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74'; declare @CRMSaleCreateElementPermissionId uniqueidentifier= '7DB77821-D6D3-4dd2-AD1B-798330506ADC'; declare @CRMSaleFullAccessPermissionId uniqueidentifier= 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';
declare @CRMRelationshipCreateElementPermissionId uniqueidentifier= 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2'; declare @ViewRelationshipPermissionId uniqueidentifier= '186D4CC4-6924-4848-93AC-6D8DE389CB08'; declare @EditRelationshipPermissionId uniqueidentifier= '0B980531-D097-4EC1-8616-56E6AB15770E'; declare @CRMRelationshipIssuanceElementPermissionId uniqueidentifier= '679876A7-8882-43d4-8FC2-3E7C9DB58ADB'; declare @CRMRelationshipFullAccessPermissionId uniqueidentifier= '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';
declare @ViewLeadPermissionId uniqueidentifier= 'C660E4B4-03BF-4315-9600-5086E47653B4'; declare @EditLeadPermissionId uniqueidentifier= 'AE298CD3-A16A-4B55-ACFC-545E4A0EBD48'; declare @CRMLeadCreateElementPermissionId uniqueidentifier= '643FE44B-8192-4615-B853-106CD6F09EDE'; declare @CRMLeadFullAccessPermissionId uniqueidentifier= '90BE803C-7857-4F2D-A8B4-129264504101'; declare @CRMLeadIssuanceElementPermissionId uniqueidentifier= 'E70A9AD1-80B2-4435-80E9-EF8E14B974CE';
declare @PermissionRoleTypeParticipantWork uniqueidentifier = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386'; declare @PermissionRoleAuthor uniqueidentifier = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92'; declare @PermissionRoleTypeInforms uniqueidentifier = '21888C0C-8BCA-4B26-AF13-4C497EECCED6'; declare @PermissionRoleTypeResponsible uniqueidentifier = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15'; declare @adminUid uniqueidentifier='F0E949BF-4DA4-4C02-B04C-CA61964B4FE8'; declare @adminUser bigint=0;
select @adminUser=Id from [User] where Uid=@adminUid;
select t.* into #TemplateLeadPermissionDel from TemplateLeadPermission t join Category c on c.ContainerLeadPermission=t.ContainerLead where c.Id=@CategoryId
-- Забрать привилегию из лида select c.Id as LeadId,t.PermissionId,t.[User],t.[Group],c.PermissionRole,t.OrganizationItemEmployee,Lead, case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Lead] con where con.[Id]=c.[Lead])|@usermask) when @PermissionRoleTypeResponsible then ((select [Responsible] from [Lead] con where con.[Id]=c.[Lead])|@usermask) ELSE t.UserSecuritySetCacheId end UserSecuritySetCacheId ,t.OrganizationItemPosition ,count(1) as Child into #LeadPersonPermissionDel from LeadPersonPermission c left join #TemplateLeadPermissionDel t on c.PermissionId=t.permissionId and c.PermissionRole=t.PermissionRole and c.UserSecuritySetCacheId= case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Lead] con where con.[Id]=c.[Lead])|@usermask) when @PermissionRoleTypeResponsible then ((select [Responsible] from [Lead] con where con.[Id]=c.[Lead])|@usermask) ELSE t.userSecuritySetCacheId end where c.InheritedFromNumber > 0 and t.[Id] is not null and c.Lead=@LeadId group by c.Id ,t.PermissionId,t.[User],t.[Group],c.PermissionRole,t.OrganizationItemEmployee,Lead,t.UserSecuritySetCacheId,t.OrganizationItemPosition,c.[Lead]
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into #LeadPersonPermissionDel ([LeadId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Lead],[Child]) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Lead] ,(select count(1) from #TemplateLeadPermissionDel t where c.PermissionId=t.permissionId and c.PermissionRole=t.PermissionRole and [User]=@adminUser) from LeadPersonPermission c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeParticipantWork and exists ( select [LeadId] from #LeadPersonPermissionDel t where PermissionRole =@PermissionRoleTypeParticipantWork and c.PermissionId=t.permissionId and c.Lead=t.Lead )
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into #LeadPersonPermissionDel ([LeadId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Lead],[Child]) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Lead] ,(select count(1) from #TemplateLeadPermissionDel t where c.PermissionId=t.permissionId and c.PermissionRole=t.PermissionRole and [User]=@adminUser) from LeadPersonPermission c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeInforms and exists ( select [LeadId] from #LeadPersonPermissionDel t where PermissionRole =@PermissionRoleTypeInforms and c.PermissionId=t.permissionId and c.Lead=t.Lead )
/*Перезаписать реальных пользователей в ответственных */ update #LeadPersonPermissionDel set [User]= (select Responsible from Contractor con where con.[Id]=Lead), [UserSecuritySetCacheId]= (select (Responsible|@usermask) from Lead con where con.[Id]=Lead) where PermissionRole=@PermissionRoleTypeResponsible
update c set c.InheritedFromNumber=c.InheritedFromNumber-ct.Child from LeadPersonPermission c join #LeadPersonPermissionDel ct on ct.LeadId=c.Id where ct.LeadId=c.Id and ct.UserSecuritySetCacheId=c.UserSecuritySetCacheId
-- Грохнуть пустые пермишены в контрагенте
-- Забрать привилегию у взаимоотношения из лида
select c.Id as RelationshipId,c.PermissionId,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Relationship,t.UserSecuritySetCacheId,c.InheritedFromNumber,t.OrganizationItemPosition into #RelationshipPersonPermissionDel from RelationshipPersonPermission c left join Relationship r on r.Id=c.Relationship and r.Lead =@LeadId left join #LeadPersonPermissionDel t on CASE WHEN t.PermissionId= @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewLeadPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditLeadPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END = c.PermissionId and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Relationship] con where con.[Id]=c.[Relationship])|@usermask) when @PermissionRoleTypeResponsible then (select (Relationship|@usermask) from Relationship con where con.[Id]=Relationship) ELSE t.userSecuritySetCacheId end and c.PermissionRole=t.PermissionRole left join LeadPersonPermission cc on cc.Id=t.LeadId where c.InheritedFromNumber > 0 and t.LeadId is not null and r.Lead=t.[Lead] and cc.InheritedFromNumber<=0
update c set c.InheritedFromNumber=c.InheritedFromNumber-1 from RelationshipPersonPermission c join #RelationshipPersonPermissionDel ct on ct.RelationshipId=c.Id where ct.RelationshipId=c.Id
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersonPermissionDel ([RelationshipId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship] ) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship]
from RelationshipPersonPermission c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeParticipantWork and exists ( select [RelationshipId] from #RelationshipPersonPermissionDel t where PermissionRole =@PermissionRoleTypeParticipantWork and c.PermissionId=t.permissionId and c.Relationship=t.Relationship )
/*Удалить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersonPermissionDel ([RelationshipId],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship]) select [Id],[PermissionId],[User],[Group],[OrganizationItemPosition],[UserSecuritySetCacheId],[PermissionRole],[OrganizationItemEmployee],[Relationship]
from RelationshipPersonPermission c where InheritedFromNumber > 0 and [User]!=@adminUser and PermissionRole =@PermissionRoleTypeInforms and exists ( select [RelationshipId] from #RelationshipPersonPermissionDel t where PermissionRole =@PermissionRoleTypeInforms and c.PermissionId=t.permissionId and c.Relationship=t.Relationship )
update c set c.InheritedFromNumber=c.InheritedFromNumber-1 from RelationshipPersonPermission c join #RelationshipPersonPermissionDel ct on ct.RelationshipId=c.Id where ct.RelationshipId=c.Id and ct.UserSecuritySetCacheId=c.UserSecuritySetCacheId and ct.PermissionRole=c.PermissionRole
delete from RelationshipPersonPermission where InheritedFromNumber<=0 delete from LeadPersonPermission where InheritedFromNumber<=0 drop table #TemplateLeadPermissionDel; drop table #LeadPersonPermissionDel; drop table #RelationshipPersonPermissionDel;
COMMIT TRANSACTION; END




  CREATE procedure [AddUpdateLeadPermissions] (
                @Uid uniqueidentifier -- это ID пермишена в лиде
        )
-- коприрование прав  в подчиненные объекты при назначении прав в лиде
        as

        declare @insCounter bigint, @insStartId bigint, @insEndId bigint;
        declare @categoryTmp bigint;
        declare @userPermission bigint; 

        declare  @permissionId uniqueidentifier;
        declare  @userP bigint;
        declare  @groupP bigint;
        declare  @OrganizationItemPosition bigint;
        declare  @userSecuritySetCacheId bigint;
        declare  @permissionRole  uniqueidentifier;
        declare @organizationItemEmployee bigint;
        declare @Lead bigint;

		BEGIN

        BEGIN TRANSACTION;

         -- получить дополнительные параметры
        select @permissionId=PermissionId,
        @userP=[User],
        @groupP= [Group],
        @OrganizationItemPosition=OrganizationItemPosition,
        @userSecuritySetCacheId=UserSecuritySetCacheId,
        @permissionRole=PermissionRole,
        @organizationItemEmployee=OrganizationItemEmployee,
        @Lead=Lead
        from  LeadPersonPermission cp  where cp.Uid=@Uid

-- Сделать замену привилегий
       declare @permissionContactId uniqueidentifier;
        declare @permissionSaleId uniqueidentifier;
		declare @permissionRelationshipId uniqueidentifier;
    declare @CRMContractorCreateElementPermissionId uniqueidentifier= '44ED88D4-A466-4fed-B194-B8288560CB48';
	  declare @CRMContractorIssuancePermissionId uniqueidentifier= '1CD25727-7CE6-443c-84BD-7975822C79E6';
	  declare @ViewContractorPermissionId uniqueidentifier= '9219C9AB-7E68-47B1-8939-FF6FC4439DA0';
	  declare @EditContractorPermissionId uniqueidentifier= '8C932B94-2F9C-488E-A36F-949A11C9741E';
    declare @FullContractorPermissionId uniqueidentifier= 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5';

	  declare @CRMSaleIssuancePermissionId uniqueidentifier= 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA';
	  declare @ViewSalePermissionId uniqueidentifier= 'AAE16346-B0E6-4949-ACAB-0914C573DE55';
	  declare @EditSalePermissionId uniqueidentifier= 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74';
	  declare @CRMSaleCreateElementPermissionId uniqueidentifier= '7DB77821-D6D3-4dd2-AD1B-798330506ADC';
    declare @FullSalePermissionId uniqueidentifier= 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';

	  declare @CRMContactCreateElementPermissionId uniqueidentifier= 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5';
	  declare @CRMContactIssuancePermissionId uniqueidentifier= '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1';
	  declare @ViewContactPermissionId uniqueidentifier= '3626682F-B657-419E-9A8E-392C14ABE455';
	  declare @EditContactPermissionId uniqueidentifier= 'ABC752AD-3623-4F14-A47F-121999890D2C';
    declare @FullContactPermissionId uniqueidentifier= '76B481D5-2E07-4417-9098-A57DE879FA56';

	  declare @CRMInpaymentCreateElementPermissionId uniqueidentifier= 'D130BB5F-6A26-4e37-B62C-F3B443E3BF53';
		declare @ViewInpaymentPermissionId uniqueidentifier = '837FF0F3-03A7-4A17-86EA-A72B3AB4886B';
		declare @EditInpaymentPermissionId uniqueidentifier = 'E23802D7-F3B5-431E-A72E-7133C3C9343F';
		declare @CRMInpaymentIssuanceElementPermissionId uniqueidentifier = 'ACF5606C-B566-426b-BAEC-E74061095BEB';
		declare @CRMInpaymentFullAccessPermissionId uniqueidentifier = 'A27A46F9-BCD8-4e82-AE49-E58675DE52D7';

		declare @CRMRelationshipCreateElementPermissionId uniqueidentifier= 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2';
		declare @ViewRelationshipPermissionId uniqueidentifier = '186D4CC4-6924-4848-93AC-6D8DE389CB08';
		declare @EditRelationshipPermissionId uniqueidentifier = '0B980531-D097-4EC1-8616-56E6AB15770E';
		declare @CRMRelationshipIssuanceElementPermissionId uniqueidentifier = '679876A7-8882-43d4-8FC2-3E7C9DB58ADB';
		declare @CRMRelationshipFullAccessPermissionId uniqueidentifier = '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';

		declare @PermissionRoleTypeUser uniqueidentifier =            'ED43E50F-6085-47BD-9A28-E43246E476A8';
		declare @PermissionRoleTypeInforms uniqueidentifier =         '21888C0C-8BCA-4B26-AF13-4C497EECCED6';
		declare @PermissionRoleTypeParticipantWork uniqueidentifier = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386';
		declare @PermissionRoleTypeResponsible uniqueidentifier =     'CE4D6154-E36E-406b-8BE9-25266C5BDD15';

    declare @ViewLeadPermissionId  uniqueidentifier= 'C660E4B4-03BF-4315-9600-5086E47653B4';
    declare @EditLeadPermissionId  uniqueidentifier= 'AE298CD3-A16A-4B55-ACFC-545E4A0EBD48';
    declare @CRMLeadCreateElementPermissionId  uniqueidentifier= '643FE44B-8192-4615-B853-106CD6F09EDE';
    declare @CRMLeadFullAccessPermissionId  uniqueidentifier= '90BE803C-7857-4F2D-A8B4-129264504101';
    declare @CRMLeadIssuanceElementPermissionId  uniqueidentifier= 'E70A9AD1-80B2-4435-80E9-EF8E14B974CE';

	declare @PermissionRoleAuthor uniqueidentifier = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92';
	declare @usermask bigint = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55
	declare @NullUid uniqueidentifier = '00000000-0000-0000-0000-000000000000';
    declare @adminUser bigint=0;
	declare @adminUid uniqueidentifier='F0E949BF-4DA4-4C02-B04C-CA61964B4FE8';

    select @adminUser=Id from [User] where Uid=@adminUid;		 	

 set @permissionRelationshipId= CASE 
      WHEN @permissionId= @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId 
	  WHEN @permissionId= @CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipIssuanceElementPermissionId 
	  WHEN @permissionId= @ViewLeadPermissionId THEN @ViewRelationshipPermissionId 
	  WHEN @permissionId= @EditLeadPermissionId THEN @EditRelationshipPermissionId 
    WHEN @permissionId= @CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId 

      ELSE @permissionId
   END  

   -- Добавить привилегию 

        update c set InheritedFromNumber=InheritedFromNumber+1  
		from RelationshipPersonPermission c
		left join Relationship cp on cp.Id=c.Relationship 
		where
        PermissionId=@permissionRelationshipId 
        and c.UserSecuritySetCacheId=
						 case c.PermissionRole 
				when @PermissionRoleAuthor then  ((select [CreationAuthor] from [Relationship] con where con.[Id]=c.[Relationship])|@usermask)

			 ELSE @userSecuritySetCacheId
        end
        and InheritedFromNumber  > 0
        and PermissionRole=@permissionRole 
		 and cp.Lead=@Lead
		 and cp.Contractor is null;
        -- Добавить недостающие привилегии 

select (ROW_NUMBER() OVER (ORDER BY t.PermissionId))-1 as [Id],@permissionRelationshipId as PermissionId,@userP [User],@groupP [Group],@permissionRole as PermissionRole,@organizationItemEmployee as OrganizationItemEmployee,c.Id as Relationship,@userSecuritySetCacheId as UserSecuritySetCacheId,NEWID() as Uid,count(1) as InheritedFromNumber  ,@OrganizationItemPosition as OrganizationItemPosition
into #RelationshipPersonPermissionTmp
from Relationship c
 left join LeadPersonPermission t on t.Lead=c.Lead 
 left outer join RelationshipPersonPermission cp on cp.Relationship=c.Id and cp.PermissionId=@permissionRelationshipId and cp.UserSecuritySetCacheId=@userSecuritySetCacheId and cp.InheritedFromNumber  > 0 and cp.PermissionRole=@permissionRole
where  t.Lead is not null 
  and cp.Relationship is null 
  and t.PermissionId=@permissionId 
  and t.UserSecuritySetCacheId=@userSecuritySetCacheId
  and t.PermissionRole=@permissionRole 
  and c.InheritPermissions=1
  and c.Lead=@Lead
  and c.Contractor is null
       and t.PermissionRole=
		case 
	 when t.PermissionRole=@PermissionRoleTypeParticipantWork and t.[User]!=@adminUser then  @NullUid
	 when t.PermissionRole=@PermissionRoleTypeInforms and t.[User]!=@adminUser then  @NullUid
	 else 
	 t.PermissionRole
	 end
  group by t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition

	 select @insCounter=max([Id]) from RelationshipPersonPermissionUpd
/*Добавить пермишены реальных пользователей для исполнителей*/
insert into RelationshipPersonPermissionUpd ([Id],[PermissionId],[User]
      ,[Group]
      ,[OrganizationItemPosition]
      ,[UserSecuritySetCacheId]
      ,[PermissionRole]
      ,[OrganizationItemEmployee]
      ,[Relationship]
      ,[Ins])
select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter  [Id],[PermissionId]
      ,m.[UserID] [User]
      ,[Group]
      ,[OrganizationItemPosition]
      ,m.[UserID]|@usermask as  [UserSecuritySetCacheId]
      ,[PermissionRole]
      ,[OrganizationItemEmployee]
      ,[Relationship]
      ,1 [Ins]
	   from [RelationshipUser] m
left join RelationshipPersonPermissionUpd c on m.RelationshipID=c.Relationship
where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and m.[Status]=0 and Ins=1
group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]

select @insCounter=max([Id]) from RelationshipPersonPermissionUpd

/*Добавить пермишены реальных пользователей для исполнителей*/
insert into RelationshipPersonPermissionUpd ([Id],[PermissionId],[User]
      ,[Group]
      ,[OrganizationItemPosition]
      ,[UserSecuritySetCacheId]
      ,[PermissionRole]
      ,[OrganizationItemEmployee]
      ,[Relationship]
      ,[Ins])
select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter  [Id],[PermissionId]
      ,m.[UserID] [User]
      ,[Group]
      ,[OrganizationItemPosition]
      ,m.[UserID]|@usermask as  [UserSecuritySetCacheId]
      ,[PermissionRole]
      ,[OrganizationItemEmployee]
      ,[Relationship]
      ,1 [Ins]
	   from [RelationshipUser] m
left join RelationshipPersonPermissionUpd c on m.RelationshipID=c.Relationship
where PermissionRole =@PermissionRoleTypeInforms and [User]=@adminUser and m.[Status]=1 and Ins=1
group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]


 /*Перезаписать реальных пользователей в ответственных */
      update #RelationshipPersonPermissionTmp
      set 
          [User]= (select [CreationAuthor] from Relationship con where con.[Id]=Contact),
          [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Relationship con where con.[Id]=Contact)
      where PermissionRole=@PermissionRoleAuthor


  set @insStartId=0;
select @insCounter=count(1) from #RelationshipPersonPermissionTmp
		EXECUTE [G_GenId] 'RelationshipPersonPermission', @insCounter, @insStartId out, @insEndId out;

    insert into RelationshipPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition)
 select @insStartId+[Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition from #RelationshipPersonPermissionTmp

 drop table #RelationshipPersonPermissionTmp;
 COMMIT TRANSACTION;
 END


          create procedure DelUpdateLeadPermissions (
        @permissionId uniqueidentifier,
        @userSecuritySetCacheId bigint, -- это ID перпишена в контейнере
        @LeadId bigint, 
        @permissionRole uniqueidentifier
        )
        as
        begin
        BEGIN TRANSACTION;
        declare @permissionContactId uniqueidentifier;
        declare @permissionSaleId uniqueidentifier;
   		declare @permissionInpaymentId uniqueidentifier;
	    declare @permissionRelationshipId uniqueidentifier;

  			declare @ViewLeadPermissionId  uniqueidentifier= 'C660E4B4-03BF-4315-9600-5086E47653B4';
        declare @EditLeadPermissionId  uniqueidentifier= 'AE298CD3-A16A-4B55-ACFC-545E4A0EBD48';
        declare @CRMLeadCreateElementPermissionId  uniqueidentifier= '643FE44B-8192-4615-B853-106CD6F09EDE';
        declare @CRMLeadFullAccessPermissionId  uniqueidentifier= '90BE803C-7857-4F2D-A8B4-129264504101';
        declare @CRMLeadIssuanceElementPermissionId  uniqueidentifier= 'E70A9AD1-80B2-4435-80E9-EF8E14B974CE';

		    declare @CRMRelationshipCreateElementPermissionId uniqueidentifier= 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2';
		    declare @ViewRelationshipPermissionId uniqueidentifier = '186D4CC4-6924-4848-93AC-6D8DE389CB08';
		    declare @EditRelationshipPermissionId uniqueidentifier = '0B980531-D097-4EC1-8616-56E6AB15770E';
		    declare @CRMRelationshipIssuanceElementPermissionId uniqueidentifier = '679876A7-8882-43d4-8FC2-3E7C9DB58ADB';
		    declare @CRMRelationshipFullAccessPermissionId uniqueidentifier = '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';

	declare @PermissionRoleAuthor uniqueidentifier = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92';
	declare @usermask bigint = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55
    declare @adminUser bigint=0;
	declare @adminUid uniqueidentifier='F0E949BF-4DA4-4C02-B04C-CA61964B4FE8';
	declare @PermissionRoleTypeInforms uniqueidentifier = '21888C0C-8BCA-4B26-AF13-4C497EECCED6';
	declare @PermissionRoleTypeParticipantWork uniqueidentifier = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386';

   select @adminUser=Id from [User] where Uid=@adminUid;

        set @permissionRelationshipId= CASE 
           WHEN @permissionId= @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId 
	         WHEN @permissionId= @CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipIssuanceElementPermissionId 
	         WHEN @permissionId= @ViewLeadPermissionId THEN @ViewRelationshipPermissionId 
	         WHEN @permissionId= @EditLeadPermissionId THEN @EditRelationshipPermissionId 
           WHEN @permissionId= @CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId 
	     ELSE @permissionId
   END 

-- Забрать привилегию из контактов 

        select c.Id as RelationshipId,c.PermissionId,c.UserSecuritySetCacheId,c.InheritedFromNumber,con.Lead,c.id,c.[Relationship]
        into #RelationshipPersonPermissionDel
        from RelationshipPersonPermission c
		inner join Relationship con on con.id=c.Relationship
        where  c.InheritedFromNumber  > 0 and 
		c.PermissionId=@permissionRelationshipId 
    		and c.UserSecuritySetCacheId=
						 case c.PermissionRole 
				when @PermissionRoleAuthor then  ((select [CreationAuthor] from [Relationship] con where con.[Id]=c.[Relationship])|@usermask)
			 ELSE @userSecuritySetCacheId
			end
    and c.PermissionRole=@permissionRole
		and con.Lead=@LeadId
    and con.Contractor is null



				/*Удалить пермишены реальных пользователей для исполнителей*/
	insert into #RelationshipPersonPermissionDel ([RelationshipId],[PermissionId],[UserSecuritySetCacheId],[Relationship],[Id])
	select  [Id],[PermissionId],[UserSecuritySetCacheId],[Relationship],c.[Id]
	from RelationshipPersonPermission c
	where 
		InheritedFromNumber  > 0
		and [User]!=@adminUser and
		PermissionRole =@PermissionRoleTypeParticipantWork
		and exists (
			select [RelationshipId] from #RelationshipPersonPermissionDel t where 
				PermissionRole =@PermissionRoleTypeParticipantWork
				and c.PermissionId=t.permissionId
				and c.Relationship=t.Relationship )

/*Удалить пермишены реальных пользователей для исполнителей*/
	insert into #RelationshipPersonPermissionDel ([RelationshipId],[PermissionId],[UserSecuritySetCacheId],[Relationship],[Id])
	select [Id],[PermissionId],[UserSecuritySetCacheId],[Relationship],c.[Id]

	from RelationshipPersonPermission c
	where 
		InheritedFromNumber  > 0
		and [User]!=@adminUser 
		and PermissionRole =@PermissionRoleTypeInforms
		and exists (
			select [RelationshipId] from #RelationshipPersonPermissionDel t where 
				PermissionRole =@PermissionRoleTypeInforms
				and c.PermissionId=t.permissionId
				and c.Relationship=t.Relationship )



        update c set c.InheritedFromNumber=c.InheritedFromNumber-1
        from RelationshipPersonPermission c
        join #RelationshipPersonPermissionDel ct on ct.RelationshipId=c.Id
        where ct.RelationshipId=c.Id

        -- Грохнуть пустые контакты

        delete  from RelationshipPersonPermission where InheritedFromNumber<=0

        COMMIT TRANSACTION;
        END



