        declare @CRMLeadIssuanceElementPermissionId  uniqueidentifier= 'E70A9AD1-80B2-4435-80E9-EF8E14B974CE';

		    declare @CRMSaleIssuancePermissionId uniqueidentifier= 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA';
	      declare @ViewSalePermissionId uniqueidentifier= 'AAE16346-B0E6-4949-ACAB-0914C573DE55';
