create procedure [CheckInheritedPermission] AS
BEGIN
declare @PermissionRoleTypeUser uniqueidentifier = 'ED43E50F-6085-47BD-9A28-E43246E476A8'; declare @PermissionRoleTypeInforms uniqueidentifier = '21888C0C-8BCA-4B26-AF13-4C497EECCED6'; declare @PermissionRoleTypeParticipantWork uniqueidentifier = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386'; declare @PermissionRoleTypeResponsible uniqueidentifier = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15';
declare @CRMContractorCreateElementPermissionId uniqueidentifier= '44ED88D4-A466-4fed-B194-B8288560CB48'; declare @CRMContractorIssuancePermissionId uniqueidentifier= '1CD25727-7CE6-443c-84BD-7975822C79E6'; declare @ViewContractorPermissionId uniqueidentifier= '9219C9AB-7E68-47B1-8939-FF6FC4439DA0'; declare @EditContractorPermissionId uniqueidentifier= '8C932B94-2F9C-488E-A36F-949A11C9741E'; declare @FullContractorPermissionId uniqueidentifier= 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5';
declare @CRMContactCreateElementPermissionId uniqueidentifier= 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5'; declare @CRMContactIssuancePermissionId uniqueidentifier= '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1'; declare @ViewContactPermissionId uniqueidentifier= '3626682F-B657-419E-9A8E-392C14ABE455'; declare @EditContactPermissionId uniqueidentifier= 'ABC752AD-3623-4F14-A47F-121999890D2C'; declare @CRMContactFullAccessPermissionId uniqueidentifier= '76B481D5-2E07-4417-9098-A57DE879FA56';
declare @CRMSaleIssuancePermissionId uniqueidentifier= 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA'; declare @ViewSalePermissionId uniqueidentifier= 'AAE16346-B0E6-4949-ACAB-0914C573DE55'; declare @EditSalePermissionId uniqueidentifier= 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74'; declare @CRMSaleCreateElementPermissionId uniqueidentifier= '7DB77821-D6D3-4dd2-AD1B-798330506ADC'; declare @CRMSaleFullAccessPermissionId uniqueidentifier= 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';
declare @CRMInpaymentCreateElementPermissionId uniqueidentifier= 'D130BB5F-6A26-4e37-B62C-F3B443E3BF53'; declare @ViewInpaymentPermissionId uniqueidentifier= '837FF0F3-03A7-4A17-86EA-A72B3AB4886B'; declare @EditInpaymentPermissionId uniqueidentifier= 'E23802D7-F3B5-431E-A72E-7133C3C9343F'; declare @CRMInpaymentIssuanceElementPermissionId uniqueidentifier= 'ACF5606C-B566-426b-BAEC-E74061095BEB'; declare @CRMInpaymentFullAccessPermissionId uniqueidentifier= 'A27A46F9-BCD8-4e82-AE49-E58675DE52D7';
declare @CRMRelationshipCreateElementPermissionId uniqueidentifier= 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2'; declare @ViewRelationshipPermissionId uniqueidentifier= '186D4CC4-6924-4848-93AC-6D8DE389CB08'; declare @EditRelationshipPermissionId uniqueidentifier= '0B980531-D097-4EC1-8616-56E6AB15770E'; declare @CRMRelationshipIssuancePermissionId uniqueidentifier= '679876A7-8882-43d4-8FC2-3E7C9DB58ADB'; declare @CRMRelationshipFullAccessPermissionId uniqueidentifier= '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';
declare @ViewLeadPermissionId uniqueidentifier= 'C660E4B4-03BF-4315-9600-5086E47653B4'; declare @EditLeadPermissionId uniqueidentifier= 'AE298CD3-A16A-4B55-ACFC-545E4A0EBD48'; declare @CRMLeadCreateElementPermissionId uniqueidentifier= '643FE44B-8192-4615-B853-106CD6F09EDE'; declare @CRMLeadFullAccessPermissionId uniqueidentifier= '90BE803C-7857-4F2D-A8B4-129264504101'; declare @CRMLeadIssuanceElementPermissionId uniqueidentifier= 'E70A9AD1-80B2-4435-80E9-EF8E14B974CE'; declare @PermissionRoleAuthor uniqueidentifier = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92'; declare @insCounter bigint, @insStartId bigint, @insEndId bigint;
declare @adminUser bigint=0; declare @adminUid uniqueidentifier='F0E949BF-4DA4-4C02-B04C-CA61964B4FE8'; declare @UserSecuritySetCache bigint , @usermask bigint declare @NullUid uniqueidentifier = '00000000-0000-0000-0000-000000000000'; declare @defaultCategory bigint=0; declare @defaultTemplLeadCategory bigint=0; declare @defaultTemplCategory bigint=0; -- маска начальников пользователя
set @usermask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55 select @adminUser=Id from [User] where Uid=@adminUid; select @defaultCategory=Id, @defaultTemplCategory=CONTAINERCONTRACTORPERMISSIO, @defaultTemplLeadCategory=CONTAINERLEADPERMISSION from Category where Uid='B53287AB-211B-4498-A054-2776C4D270AD' set @UserSecuritySetCache= @adminUser|@usermask; /*Удаляем все наследуемые права*/ delete from ContractorPersonPermission where InheritedFromNumber is not null; delete from RelationshipPersonPermission where InheritedFromNumber is not null; delete from SalePersonPermission where InheritedFromNumber is not null; delete from LeadPersonPermission where InheritedFromNumber is not null; delete from ContactPersonPermission where InheritedFromNumber is not null;
/*Добавить недостающие разрешения к контрагентам*/ select ROW_NUMBER() over (order by c.[Id]) -1 [Id],t.PermissionId [PermissionId],t.[User] [User],t.[Group] [Group],t.PermissionRole [PermissionRole],t.OrganizationItemEmployee [OrganizationItemEmployee],c.Id Contractor,t.UserSecuritySetCacheId [UserSecuritySetCacheId],t.OrganizationItemPosition [OrganizationItemPosition],count(1) InheritedFromNumber into #TempContractorCheckPermission from Contractor c left join M_Contractor_Categories cc on c.Id=ContractorId -- вытащили категорию в которые входит контрагент left join TemplateContractorPermission t on AddPermission = 0 and DelPermission=0 -- взяди мермишены которые надо обновить из контейнера left outer join ContractorPersonPermission cp on cp.Contractor=c.Id and cp.PermissionId=t.PermissionId and case cp.PermissionRole when @PermissionRoleAuthor then (@adminUser|@usermask) when @PermissionRoleTypeResponsible then (@adminUser|@usermask) ELSE cp.userSecuritySetCacheId end=t.userSecuritySetCacheId and cp.PermissionRole=t.PermissionRole and cp.InheritedFromNumber > 0 left join Category ca on ca.ContainerContractorPermissio=t.ContainerContractor -- выьащили категорию в которую входит пермишен из контейнера where (cc.CategoryId =ca.Id or (cc.CategoryId is null and t.containercontractor=@defaultTemplCategory )) -- соединили категории из контейнера и из контрагента and c.InheritPermissions=1 and cp.Contractor is null group by t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition
select @insCounter=max([Id]) from #TempContractorCheckPermission
/*Добавить пермишены реальных пользователей для исполнителей*/ insert into #TempContractorCheckPermission ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[InheritedFromNumber]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,c.[InheritedFromNumber] from [M_Contractor_ParticipantWork] m left join #TempContractorCheckPermission c on m.Parent=c.Contractor where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Contractor],c.[InheritedFromNumber]
select @insCounter=max([Id]) from #TempContractorCheckPermission
insert into #TempContractorCheckPermission ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[InheritedFromNumber]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,c.[InheritedFromNumber] from [M_Contractor_Informs] m left join #TempContractorCheckPermission c on m.Parent=c.Contractor where PermissionRole in (@PermissionRoleTypeInforms) and [User]=@adminUser group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Contractor],c.[InheritedFromNumber]
select @insCounter=max([Id]) from ( select max([Id]) [Id] from #TempContractorCheckPermission union select max([Id]) [Id] from ContractorPersonPermission ) d
/*Добавляем реальных информируемых пользователей при наличии фейковых*/ insert into #TempContractorCheckPermission ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[InheritedFromNumber]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],c.[PermissionId] ,m.[Child] [User] ,c.[Group] ,c.[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,c.[PermissionRole] ,c.[OrganizationItemEmployee] ,c.[Contractor] ,c.[InheritedFromNumber] from [M_Contractor_ParticipantWork] m left join [ContractorPersonPermission] c on m.Parent=c.Contractor left join [ContractorPersonPermission] c1 on m.[Child]=c1.[user] and c1.[PermissionId]=c.[PermissionId] and c1.[User] is not null and c1.[PermissionRole]=c.[PermissionRole] where c.PermissionRole in (@PermissionRoleTypeParticipantWork) and c.[User]=@adminUser and c1.[Id] is null group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],c.[Contractor],c.[InheritedFromNumber]
select @insCounter=max([Id]) from ( select max([Id]) [Id] from #TempContractorCheckPermission union select max([Id]) [Id] from ContractorPersonPermission ) d
/*Добавляем реальных информируемых пользователей при наличии фейковых*/ insert into #TempContractorCheckPermission ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[InheritedFromNumber]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],c.[PermissionId] ,m.[Child] [User] ,c.[Group] ,c.[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,c.[PermissionRole] ,c.[OrganizationItemEmployee] ,c.[Contractor] ,c.[InheritedFromNumber] from [M_Contractor_Informs] m left join [ContractorPersonPermission] c on m.Parent=c.Contractor left join [ContractorPersonPermission] c1 on m.[Child]=c1.[user] and c1.[PermissionId]=c.[PermissionId] and c1.[User] is not null and c1.[PermissionRole]=c.[PermissionRole] where c.PermissionRole in (@PermissionRoleTypeInforms) and c.[User]=@adminUser and c1.[Id] is null group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],c.[Contractor],c.[InheritedFromNumber]
/*Перезаписать реальных пользователей в ответственных */ update #TempContractorCheckPermission set [User]= (select (case when Responsible is not null then Responsible else @adminUser end) from Contractor con where con.[Id]=Contractor), [UserSecuritySetCacheId]= (select ((case when Responsible is not null then Responsible else @adminUser end)|@usermask) from Contractor con where con.[Id]=Contractor) where PermissionRole=@PermissionRoleTypeResponsible
/*Перезаписать реальных пользователей в ответственных */ update #TempContractorCheckPermission set [User]= (select [CreationAuthor] from Contractor con where con.[Id]=Contractor), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Contractor con where con.[Id]=Contractor) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0;
select @insCounter=count(1) from #TempContractorCheckPermission
EXECUTE [G_GenId] 'ContractorPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into ContractorPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contractor,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id, t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Contractor,t.UserSecuritySetCacheId,NEWID() as Uid,InheritedFromNumber,t.OrganizationItemPosition from #TempContractorCheckPermission t ;
drop table #TempContractorCheckPermission;
select ROW_NUMBER() over (order by c.[Id]) -1 [Id],t.PermissionId [PermissionId],t.[User] [User],t.[Group] [Group],t.PermissionRole [PermissionRole],t.OrganizationItemEmployee [OrganizationItemEmployee],c.Id Lead,t.UserSecuritySetCacheId [UserSecuritySetCacheId],t.OrganizationItemPosition [OrganizationItemPosition],count(1) InheritedFromNumber into #TempLeadCheckPermission from Lead c left join M_Lead_Categories cc on c.Id=LeadId -- вытащили категорию в которые входит контрагент left join TemplateLeadPermission t on AddPermission = 0 and DelPermission=0 -- взяди мермишены которые надо обновить из контейнера left outer join LeadPersonPermission cp on cp.Lead=c.Id and cp.PermissionId=t.PermissionId and t.UserSecuritySetCacheId= case cp.PermissionRole when @PermissionRoleAuthor then (@adminUser|@usermask) when @PermissionRoleTypeResponsible then (@adminUser|@usermask) ELSE cp.userSecuritySetCacheId end and cp.PermissionRole=t.PermissionRole and cp.InheritedFromNumber > 0 left join Category ca on ca.ContainerLeadPermission=t.ContainerLead -- выьащили категорию в которую входит пермишен из контейнера where (cc.CategoryId =ca.Id or (cc.CategoryId is null and t.CONTAINERLEAD=@defaultTemplLeadCategory )) -- соединили категории из контейнера и из контрагента and c.InheritPermissions=1 and cp.Lead is null group by t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition
select @insCounter=max([Id]) from #TempLeadCheckPermission
/*Добавить пермишены реальных пользователей для исполнителей при отсутствии фейковых*/ insert into #TempLeadCheckPermission ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[InheritedFromNumber]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,c.[InheritedFromNumber] from [M_Lead_ParticipantWork] m left join #TempLeadCheckPermission c on m.Parent=c.Lead where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Lead],c.[InheritedFromNumber]
select @insCounter=max([Id]) from #TempLeadCheckPermission
insert into #TempLeadCheckPermission ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[InheritedFromNumber]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,c.[InheritedFromNumber] from [M_Lead_Informs] m left join #TempLeadCheckPermission c on m.Parent=c.Lead where PermissionRole in (@PermissionRoleTypeInforms) and [User]=@adminUser group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Lead],c.[InheritedFromNumber]
select @insCounter=max([Id]) from ( select max([Id]) [Id] from #TempLeadCheckPermission union select max([Id]) [Id] from LeadPersonPermission ) d
/*Добавляем реальных информируемых пользователей при наличии фейковых*/ insert into #TempLeadCheckPermission ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[InheritedFromNumber]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],c.[PermissionId] ,m.[Child] [User] ,c.[Group] ,c.[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,c.[PermissionRole] ,c.[OrganizationItemEmployee] ,c.[Lead] ,c.[InheritedFromNumber] from [M_Lead_ParticipantWork] m left join [LeadPersonPermission] c on m.Parent=c.Lead left join [LeadPersonPermission] c1 on m.[Child]=c1.[user] and c1.[PermissionId]=c.[PermissionId] and c1.[User] is not null and c1.[PermissionRole]=c.[PermissionRole] where c.PermissionRole in (@PermissionRoleTypeParticipantWork) and c.[User]=@adminUser and c1.[Id] is null group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],c.[Lead],c.[InheritedFromNumber]
select @insCounter=max([Id]) from ( select max([Id]) [Id] from #TempLeadCheckPermission union select max([Id]) [Id] from LeadPersonPermission ) d
/*Добавляем реальных информируемых пользователей при наличии фейковых*/ insert into #TempLeadCheckPermission ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[InheritedFromNumber]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],c.[PermissionId] ,m.[Child] [User] ,c.[Group] ,c.[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,c.[PermissionRole] ,c.[OrganizationItemEmployee] ,c.[Lead] ,c.[InheritedFromNumber] from [M_Lead_Informs] m left join [LeadPersonPermission] c on m.Parent=c.Lead left join [LeadPersonPermission] c1 on m.[Child]=c1.[user] and c1.[PermissionId]=c.[PermissionId] and c1.[User] is not null and c1.[PermissionRole]=c.[PermissionRole] where c.PermissionRole in (@PermissionRoleTypeInforms) and c.[User]=@adminUser and c1.[Id] is null group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],c.[Lead],c.[InheritedFromNumber]
/*Перезаписать реальных пользователей в ответственных */
update #TempLeadCheckPermission set [User]= (select (case when Responsible is not null then Responsible else @adminUser end) from Lead con where con.[Id]=Lead), [UserSecuritySetCacheId]= (select ((case when Responsible is not null then Responsible else @adminUser end)|@usermask) from Lead con where con.[Id]=Lead) where PermissionRole=@PermissionRoleTypeResponsible
/*Перезаписать реальных пользователей в ответственных */ update #TempLeadCheckPermission set [User]= (select [CreationAuthor] from Lead con where con.[Id]=Lead), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Lead con where con.[Id]=Lead) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0;
select @insCounter=count(1) from #TempLeadCheckPermission
EXECUTE [G_GenId] 'LeadPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into LeadPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Lead,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id, t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Lead,t.UserSecuritySetCacheId,NEWID() as Uid,InheritedFromNumber,t.OrganizationItemPosition from #TempLeadCheckPermission t
drop table #TempLeadCheckPermission; /*Добавить недостающие разрешения для контактов*/ select ROW_NUMBER() over (order by t.[Id]) - 1 [Id], CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @CRMContactFullAccessPermissionId ELSE t.PermissionId END [PermissionId], t.[User] [User],t.[Group] [Group],t.PermissionRole [PermissionRole],t.OrganizationItemEmployee [OrganizationItemEmployee],c.Id [Contact],t.UserSecuritySetCacheId [UserSecuritySetCacheId],t.OrganizationItemPosition [OrganizationItemPosition] into #TempContactCheckPermission from Contact c left join ContractorPersonPermission t on t.Contractor=c.Contractor where t.Contractor is not null and c.InheritPermissions=1
set @insStartId=0;
select @insCounter=count(1) from #TempContactCheckPermission
EXECUTE [G_GenId] 'ContactPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into ContactPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contact,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id, t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Contact,t.UserSecuritySetCacheId,NEWID() as Uid,1,t.OrganizationItemPosition from #TempContactCheckPermission t ;
drop table #TempContactCheckPermission;
/* Добавить недостающие привилегии в сделки */ select ROW_NUMBER() over (order by t.[Id]) -1 [Id], CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMSaleCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMSaleIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewSalePermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditSalePermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @CRMSaleFullAccessPermissionId ELSE t.PermissionId END [PermissionId], t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Sale,t.UserSecuritySetCacheId,t.OrganizationItemPosition into #TempSaleCheckPermission from Sale c left join ContractorPersonPermission t on t.Contractor=c.Contractor where t.Contractor is not null and c.InheritPermissions=1
set @insStartId=0;
select @insCounter=count(1) from #TempSaleCheckPermission
EXECUTE [G_GenId] 'SalePersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into SalePersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Sale,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id, t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Sale,t.UserSecuritySetCacheId,NEWID() as Uid,1,t.OrganizationItemPosition from #TempSaleCheckPermission t ;
drop table #TempSaleCheckPermission;
/* Добавить недостающие привилегии из контрагента в взаимоотношение */ select CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMRelationshipIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @FullContractorPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END [PermissionId],t.[User] [User],t.[Group] [Group],t.PermissionRole [PermissionRole],t.OrganizationItemEmployee [OrganizationItemEmployee],c.Id [Relationship],t.UserSecuritySetCacheId [UserSecuritySetCacheId],t.OrganizationItemPosition [OrganizationItemPosition] into #TempRelationshipCheckPermission from Relationship c left join ContractorPersonPermission t on t.Contractor=c.Contractor where t.Contractor is not null and c.InheritPermissions=1 and c.Contractor is not null and t.PermissionRole= case when t.PermissionRole=@PermissionRoleTypeParticipantWork and t.[User]!=@adminUser then @NullUid when t.PermissionRole=@PermissionRoleTypeInforms and t.[User]!=@adminUser then @NullUid else t.PermissionRole end and c.Lead is null
/*Добавить недостающие привилегии к взаимоотношениям из контактов*/ insert into #TempRelationshipCheckPermission ([PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ) select CASE WHEN t.PermissionId= @CRMContactCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContactIssuancePermissionId THEN @CRMRelationshipIssuancePermissionId WHEN t.PermissionId= @ViewContactPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContactPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMContactFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END [PermissionId] ,t.[User] [User] ,t.[Group] [Group] ,t.OrganizationItemPosition [OrganizationItemPosition] ,t.UserSecuritySetCacheId [UserSecuritySetCacheId] ,t.PermissionRole [PermissionRole] ,t.OrganizationItemEmployee [OrganizationItemEmployee] ,c.Id [Relationship] from Relationship c left join ContactPersonPermission t on t.Contact=c.Contact where t.Contact is not null and c.InheritPermissions=1
/*Добавить недостающие разрешени во взаимоотношения из сделки*/ INSERT INTO #TempRelationshipCheckPermission ([PermissionId] ,[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ) select CASE WHEN t.PermissionId= @CRMSaleCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMSaleIssuancePermissionId THEN @CRMRelationshipIssuancePermissionId WHEN t.PermissionId= @ViewSalePermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditSalePermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMSaleFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END [PermissionId] ,t.[User] [User] ,t.[Group] [Group] ,t.OrganizationItemPosition [OrganizationItemPosition] ,t.UserSecuritySetCacheId [UserSecuritySetCacheId] ,t.PermissionRole [PermissionRole] ,t.OrganizationItemEmployee [OrganizationItemEmployee] ,c.Id [Relationship] from Relationship c left join SalePersonPermission t on t.Sale=c.Sale where t.Sale is not null and c.InheritPermissions=1
/*Добавить недостающие разрешени во взаимоотношения из лида*/ INSERT INTO #TempRelationshipCheckPermission ([PermissionId] ,[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ) select CASE WHEN t.PermissionId= @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipIssuancePermissionId WHEN t.PermissionId= @ViewLeadPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditLeadPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END [PermissionId] ,t.[User] [User] ,t.[Group] [Group] ,t.OrganizationItemPosition [OrganizationItemPosition] ,t.UserSecuritySetCacheId [UserSecuritySetCacheId] ,t.PermissionRole [PermissionRole] ,t.OrganizationItemEmployee [OrganizationItemEmployee] ,c.Id [Relationship] from Relationship c left join LeadPersonPermission t on t.Lead=c.Lead where t.Lead is not null and c.Contractor is null and c.InheritPermissions=1
/*Перезаписать реальных пользователей в ответственных */ update #TempRelationshipCheckPermission set [User]= (select [CreationAuthor] from Relationship con where con.[Id]=[Relationship]), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Relationship con where con.[Id]=[Relationship]) where PermissionRole=@PermissionRoleAuthor
/*Добавить пермишены реальных пользователей для исполнителей*/ insert into #TempRelationshipCheckPermission ([PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship]) select [PermissionId] ,m.[UserID] [User] ,[Group] ,[OrganizationItemPosition] ,m.[UserID]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] from [RelationshipUser] m left join #TempRelationshipCheckPermission c on m.RelationshipID=c.Relationship where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and m.[Status]=0 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]
/*Добавить пермишены реальных пользователей для исполнителей*/ insert into #TempRelationshipCheckPermission ([PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ) select [PermissionId] ,m.[UserID] [User] ,[Group] ,[OrganizationItemPosition] ,m.[UserID]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] from [RelationshipUser] m left join #TempRelationshipCheckPermission c on m.RelationshipID=c.Relationship where PermissionRole =@PermissionRoleTypeInforms and [User]=@adminUser and m.[Status]=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]
set @insStartId=0;
select @insCounter=count(1) from #TempRelationshipCheckPermission; print 'ins=' print @insCounter EXECUTE [G_GenId] 'RelationshipPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into RelationshipPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + (ROW_NUMBER() over (order by [Relationship]) ) as Id,t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Relationship,t.UserSecuritySetCacheId,NEWID(),1 ,t.OrganizationItemPosition from #TempRelationshipCheckPermission t ;
delete from TemplateContractorPermission where [User] is null and [Group] is null and OrganizationItemPosition is null and OrganizationItemEmployee is null; delete from TemplateLeadPermission where [User] is null and [Group] is null and OrganizationItemPosition is null and OrganizationItemEmployee is null; delete from ContactPersonPermission where [User] is null and [Group] is null and OrganizationItemPosition is null and OrganizationItemEmployee is null; delete from ContractorPersonPermission where [User] is null and [Group] is null and OrganizationItemPosition is null and OrganizationItemEmployee is null; delete from LeadPersonPermission where [User] is null and [Group] is null and OrganizationItemPosition is null and OrganizationItemEmployee is null; delete from SalePersonPermission where [User] is null and [Group] is null and OrganizationItemPosition is null and OrganizationItemEmployee is null; delete from RelationshipPersonPermission where [User] is null and [Group] is null and OrganizationItemPosition is null and OrganizationItemEmployee is null; drop table #TempRelationshipCheckPermission;
END

/*Добавление пермишенов категрии "Без категрии" всем контрагентам у котороых нет категориии*/ CREATE procedure [AddDefaultCategoriesContractor]
AS BEGIN
BEGIN TRANSACTION; declare @insCounter bigint, @insStartId bigint, @insEndId bigint; declare @usermask bigint set @usermask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55 declare @PermissionRoleTypeResponsible uniqueidentifier = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15'; declare @CRMContractorCreateElementPermissionId uniqueidentifier= '44ED88D4-A466-4fed-B194-B8288560CB48'; declare @CRMContractorIssuancePermissionId uniqueidentifier= '1CD25727-7CE6-443c-84BD-7975822C79E6'; declare @ViewContractorPermissionId uniqueidentifier= '9219C9AB-7E68-47B1-8939-FF6FC4439DA0'; declare @EditContractorPermissionId uniqueidentifier= '8C932B94-2F9C-488E-A36F-949A11C9741E'; declare @CRMContractorFullAccessPermissionId uniqueidentifier= 'E612615C-D5E2-4c4b-9DF0-B4D9EEB983A5'; declare @CRMRelationshipCreateElementPermissionId uniqueidentifier= 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2'; declare @ViewRelationshipPermissionId uniqueidentifier= '186D4CC4-6924-4848-93AC-6D8DE389CB08'; declare @EditRelationshipPermissionId uniqueidentifier= '0B980531-D097-4EC1-8616-56E6AB15770E'; declare @CRMRelationshipIssuanceElementPermissionId uniqueidentifier= '679876A7-8882-43d4-8FC2-3E7C9DB58ADB'; declare @CRMRelationshipFullAccessPermissionId uniqueidentifier= '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';
declare @CRMContactCreateElementPermissionId uniqueidentifier= 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5'; declare @CRMContactIssuancePermissionId uniqueidentifier= '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1'; declare @ViewContactPermissionId uniqueidentifier= '3626682F-B657-419E-9A8E-392C14ABE455'; declare @EditContactPermissionId uniqueidentifier= 'ABC752AD-3623-4F14-A47F-121999890D2C'; declare @CRMContactFullAccessPermissionId uniqueidentifier= '76B481D5-2E07-4417-9098-A57DE879FA56';
declare @CRMSaleIssuancePermissionId uniqueidentifier= 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA'; declare @ViewSalePermissionId uniqueidentifier= 'AAE16346-B0E6-4949-ACAB-0914C573DE55'; declare @EditSalePermissionId uniqueidentifier= 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74'; declare @CRMSaleCreateElementPermissionId uniqueidentifier= '7DB77821-D6D3-4dd2-AD1B-798330506ADC'; declare @CRMSaleFullAccessPermissionId uniqueidentifier= 'DB60BB49-0DE1-46ee-8CE8-DCD59DB93351';
declare @CRMInpaymentCreateElementPermissionId uniqueidentifier= 'D130BB5F-6A26-4e37-B62C-F3B443E3BF53'; declare @ViewInpaymentPermissionId uniqueidentifier = '837FF0F3-03A7-4A17-86EA-A72B3AB4886B'; declare @EditInpaymentPermissionId uniqueidentifier = 'E23802D7-F3B5-431E-A72E-7133C3C9343F'; declare @CRMInpaymentIssuanceElementPermissionId uniqueidentifier = 'ACF5606C-B566-426b-BAEC-E74061095BEB';
declare @PermissionRoleTypeParticipantWork uniqueidentifier = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386'; declare @PermissionRoleAuthor uniqueidentifier = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92'; declare @PermissionRoleTypeInforms uniqueidentifier = '21888C0C-8BCA-4B26-AF13-4C497EECCED6'; declare @adminUid uniqueidentifier='F0E949BF-4DA4-4C02-B04C-CA61964B4FE8'; declare @adminUser bigint=0; declare @NullUid uniqueidentifier = '00000000-0000-0000-0000-000000000000';
declare @defaultCategory bigint=0; declare @defaultTemplLeadCategory bigint=0; declare @defaultTemplCategory bigint=0;
select @defaultCategory=Id, @defaultTemplCategory=CONTAINERCONTRACTORPERMISSIO, @defaultTemplLeadCategory=CONTAINERLEADPERMISSION from Category where Uid='B53287AB-211B-4498-A054-2776C4D270AD'
select @adminUser=Id from [User] where Uid=@adminUid;
select t.* into #TemplateContractorPermissionDel from TemplateContractorPermission t join Category c on c.ContainerContractorPermissio=t.ContainerContractor where c.Id=@defaultCategory and AddPermission !=1 and DelPermission!=1
create table #ContractorPersonPermissionUpd( [Uid] [uniqueidentifier] NULL, [PermissionId] [uniqueidentifier] NULL, [User] [bigint] NULL, [Group] [bigint] NULL, [OrganizationItemPosition] [bigint] NULL, [UserSecuritySetCacheId] [bigint] NULL, [PermissionRole] [uniqueidentifier] NULL, [OrganizationItemEmployee] [bigint] NULL, [Contractor] [bigint] NULL, [Ins] [int], [Child] [bigint], [Iteration] [int] NULL DEFAULT ((0)), [Id] [bigint] NOT NULL DEFAULT ((0)));
-- Добавить недостающие привилегии в контрагента
insert into #ContractorPersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contractor,UserSecuritySetCacheId,OrganizationItemPosition,Ins,Child) select (ROW_NUMBER() OVER (ORDER BY t.PermissionId))-1, t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition,1,count(1) as Child from Contractor c join #TemplateContractorPermissionDel t on 1=1 -- взяди пермишены которые надо обновить из контейнера left outer join ContractorPersonPermission cp on cp.Contractor=c.Id and cp.PermissionId=t.PermissionId and case cp.PermissionRole when @PermissionRoleAuthor then (@adminUser|@usermask) when @PermissionRoleTypeResponsible then (@adminUser|@usermask) ELSE cp.UserSecuritySetCacheId end=t.UserSecuritySetCacheId and cp.PermissionRole=t.PermissionRole and cp.InheritedFromNumber > 0 left join Category ca on ca.ContainerContractorPermissio=t.ContainerContractor -- выьащили категорию в которую входит пермишен из контейнера where -- соединили категории из контейнера и из контрагента c.InheritPermissions>=1 and cp.Contractor is null and c.Id in (select distinct c.Id from contractor c left join M_Contractor_Categories cc on cc.ContractorId=c.Id where cc.CategoryId is null) group by t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition
select @insCounter=max([Id]) from #ContractorPersonPermissionUpd /*Добавить пермишены реальных пользователей для исполнителей*/ insert into #ContractorPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,1 [Ins],c.[Child] from [M_Contractor_ParticipantWork] m left join #ContractorPersonPermissionUpd c on m.Parent=c.Contractor where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Contractor],c.[Child]
insert into CheckContractorCategTmp (Id) select Contractor from #ContractorPersonPermissionUpd select @insCounter=max([Id]) from #ContractorPersonPermissionUpd
insert into #ContractorPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Contractor] ,1 [Ins],c.[Child] from [M_Contractor_Informs] m left join #ContractorPersonPermissionUpd c on m.Parent=c.Contractor where PermissionRole in (@PermissionRoleTypeInforms) and [User]=@adminUser and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Contractor],c.[Child]
/*Перезаписать реальных пользователей в ответственных */ update #ContractorPersonPermissionUpd set [User]= (select Responsible from Contractor con where con.[Id]=Contractor), [UserSecuritySetCacheId]= (select (Responsible|@usermask) from Contractor con where con.[Id]=Contractor) where PermissionRole=@PermissionRoleTypeResponsible
/*Перезаписать реальных пользователей в ответственных */ update #ContractorPersonPermissionUpd set [User]= (select [CreationAuthor] from Contractor con where con.[Id]=Contractor), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Contractor con where con.[Id]=Contractor) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from #ContractorPersonPermissionUpd EXECUTE [G_GenId] 'ContractorPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into ContractorPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contractor,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id, t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Contractor,t.UserSecuritySetCacheId,NEWID() as Uid,Child as InheritedFromNumber,t.OrganizationItemPosition from #ContractorPersonPermissionUpd t where Ins=1
-- Добавить привилегии к контактам
select -1 as [Id], c.PermissionId,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,ca.Id Contact,t.UserSecuritySetCacheId,t.OrganizationItemPosition,0 Ins into #ContactPersonPermissionUpd from ContactPersonPermission c left join #ContractorPersonPermissionUpd t on CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMContactFullAccessPermissionId ELSE t.PermissionId END = c.PermissionId and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Contact] con where con.[Id]=c.[Contact])|@usermask) when @PermissionRoleTypeResponsible then (select (contr.Responsible|@usermask) from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact) ELSE t.UserSecuritySetCacheId end and c.PermissionRole=t.PermissionRole left join Contact ca on c.Contact=ca.id and ca.InheritPermissions=1 where c.InheritedFromNumber > 0 and t.UserSecuritySetCacheId is not null
update c set c.InheritedFromNumber=c.InheritedFromNumber+1 from ContactPersonPermission c join #ContactPersonPermissionUpd ct on ct.Contact=c.Id where ct.Contact=c.Id
-- Добавить недостающие привилегии к контактам
insert into #ContactPersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contact,UserSecuritySetCacheId,OrganizationItemPosition,Ins) select ROW_NUMBER() over (order by t.[Id]) - 1, CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMContactFullAccessPermissionId ELSE t.PermissionId END ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Contact,t.UserSecuritySetCacheId,t.OrganizationItemPosition,1 Ins from Contact c left join #ContractorPersonPermissionUpd t on t.Contractor=c.Contractor left outer join ContactPersonPermission cp on cp.Contact=c.Id and cp.InheritedFromNumber > 0 and CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMContactCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMContactIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewContactPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditContactPermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMContactFullAccessPermissionId ELSE t.PermissionId END = cp.PermissionId and cp.UserSecuritySetCacheId=t.UserSecuritySetCacheId and cp.PermissionRole=t.PermissionRole where t.Contractor is not null and cp.Contact is null and c.InheritPermissions=1
/*Перезаписать реальных пользователей в ответственных */ update ContactPersonPermissionUpd set [User]= (select contr.Responsible from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact), [UserSecuritySetCacheId]= (select (contr.Responsible|@usermask) from Contact con left join Contractor contr on contr.[Id]=con.[Contractor] where con.[Id]=Contact) where PermissionRole=@PermissionRoleTypeResponsible /*Перезаписать реальных пользователей в ответственных */ update ContactPersonPermissionUpd set [User]= (select [CreationAuthor] from Contact con where con.[Id]=Contact), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Contact con where con.[Id]=Contact) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from #ContactPersonPermissionUpd EXECUTE [G_GenId] 'ContactPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into ContactPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Contact,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id,t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Contact,t.UserSecuritySetCacheId,NEWID(),1 ,t.OrganizationItemPosition from #ContactPersonPermissionUpd t where Ins=1
-- Добавить привилегии к сделкам insert into log_cont( dt,comm)values(GETDATE ( ),'-- Добавить привилегии к сделкам') select -1 as [Id],c.PermissionId,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,ca.Id Sale,t.UserSecuritySetCacheId,t.OrganizationItemPosition,0 Ins into #SalePersonPermissionUpd from SalePersonPermission c left join #ContractorPersonPermissionUpd t on CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMSaleCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMSaleIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewSalePermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditSalePermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMSaleFullAccessPermissionId ELSE t.PermissionId END =c.PermissionId and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then ((select [Author] from [Sale] con where con.[Id]=c.[Sale])|@usermask) when @PermissionRoleTypeResponsible then (select (Responsible|@usermask) from Sale con where con.[Id]=Sale) ELSE t.UserSecuritySetCacheId end and c.PermissionRole=t.PermissionRole left join Sale ca on c.Sale=ca.id and ca.InheritPermissions=1 where c.InheritedFromNumber > 0 and t.UserSecuritySetCacheId is not null
update c set c.InheritedFromNumber=c.InheritedFromNumber+1 from SalePersonPermission c join #SalePersonPermissionUpd ct on ct.Sale=c.Id where ct.Sale=c.Id
-- Добавить недостающие привилегии к сделкам
insert into #SalePersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Sale,UserSecuritySetCacheId,OrganizationItemPosition,Ins) select ROW_NUMBER() over (order by t.[Id]) - 1, CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMSaleCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMSaleIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewSalePermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditSalePermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMSaleFullAccessPermissionId ELSE t.PermissionId END ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Sale,t.UserSecuritySetCacheId,t.OrganizationItemPosition,1 Ins from Sale c left join #ContractorPersonPermissionUpd t on t.Contractor=c.Contractor left outer join SalePersonPermission cp on cp.Sale=c.Id and cp.InheritedFromNumber > 0 and CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMSaleCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMSaleIssuancePermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewSalePermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditSalePermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMSaleFullAccessPermissionId ELSE t.PermissionId END = cp.PermissionId and cp.UserSecuritySetCacheId=t.UserSecuritySetCacheId and cp.PermissionRole=t.PermissionRole where t.Contractor is not null and c.InheritPermissions=1 and cp.Sale is null
/*Перезаписать реальных пользователей в ответственных */ update #SalePersonPermissionUpd set [User]= (select Responsible from Sale con where con.[Id]=Sale), [UserSecuritySetCacheId]= (select (Responsible|@usermask) from sale con where con.[Id]=Sale) where PermissionRole=@PermissionRoleTypeResponsible /*Перезаписать реальных пользователей в ответственных */ update #SalePersonPermissionUpd set [User]= (select [Author] from Sale con where con.[Id]=Sale), [UserSecuritySetCacheId]= (select (Author|@usermask) from Sale con where con.[Id]=Sale) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from #SalePersonPermissionUpd EXECUTE [G_GenId] 'SalePersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into SalePersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Sale,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id,t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Sale,t.UserSecuritySetCacheId,NEWID(),1 ,t.OrganizationItemPosition from #SalePersonPermissionUpd t where Ins=1;
update c set c.InheritedFromNumber=c.InheritedFromNumber+1 from RelationshipPersonPermission c where exists ( select 1 from ContractorPersonPermissionUpd t where CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMRelationshipFullAccessPermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END =c.PermissionId and c.UserSecuritySetCacheId= case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Contractor] con where con.[Id]=t.[Contractor])|@usermask) when @PermissionRoleTypeResponsible then ((select [Responsible] from [Contractor] con where con.[Id]=t.[Contractor])|@usermask) ELSE t.UserSecuritySetCacheId end and c.PermissionRole=t.PermissionRole) and c.Relationship in (select ca.id from Relationship ca where ca.InheritPermissions=1 and ca.Contractor is not null) and c.InheritedFromNumber > 0
-- Добавить недостающие привилегии к взаимоотношениям
select ROW_NUMBER() over (order by t.[Id]) -1 as [Id], CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END as PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Relationship,t.UserSecuritySetCacheId,t.OrganizationItemPosition,1 Ins into #RelationshipPersonPermissionUpd from Relationship c left join ContractorPersonPermission t on t.Contractor=c.Contractor --and t.Contractor is not null left outer join RelationshipPersonPermission cp on cp.Relationship=c.Id and cp.InheritedFromNumber > 0 and CASE WHEN t.PermissionId= @CRMContractorCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMContractorIssuancePermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewContractorPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditContractorPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMContractorFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END = cp.PermissionId and cp.UserSecuritySetCacheId=t.UserSecuritySetCacheId and cp.PermissionRole=t.PermissionRole where t.Contractor is not null and c.InheritPermissions=1 and cp.Relationship is null and c.Contractor is not null and t.PermissionRole= case when t.PermissionRole=@PermissionRoleTypeParticipantWork and t.[User]!=@adminUser then @NullUid when t.PermissionRole=@PermissionRoleTypeInforms and t.[User]!=@adminUser then @NullUid else t.PermissionRole end
select @insCounter=max([Id]) from #RelationshipPersonPermissionUpd /*Добавить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,[Ins]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[UserID] [User] ,[Group] ,[OrganizationItemPosition] ,m.[UserID]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,1 [Ins] from [RelationshipUser] m left join #RelationshipPersonPermissionUpd c on m.RelationshipID=c.Relationship where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and m.[Status]=0 and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]
select @insCounter=max([Id]) from #RelationshipPersonPermissionUpd
/*Добавить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,[Ins]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[UserID] [User] ,[Group] ,[OrganizationItemPosition] ,m.[UserID]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,1 [Ins] from [RelationshipUser] m left join #RelationshipPersonPermissionUpd c on m.RelationshipID=c.Relationship where PermissionRole =@PermissionRoleTypeInforms and [User]=@adminUser and m.[Status]=1 and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]
/*Перезаписать реальных пользователей в ответственных */ update #RelationshipPersonPermissionUpd set [User]= (select [CreationAuthor] from Relationship con where con.[Id]=Relationship), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Relationship con where con.[Id]=Relationship) where PermissionRole=@PermissionRoleAuthor
set @insStartId=0; select @insCounter=count(1) from #RelationshipPersonPermissionUpd EXECUTE [G_GenId] 'RelationshipPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into RelationshipPersonPermission([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id,t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Relationship,t.UserSecuritySetCacheId,NEWID(),1 ,t.OrganizationItemPosition from #RelationshipPersonPermissionUpd t where Ins=1 drop table #ContractorPersonPermissionUpd; drop table #TemplateContractorPermissionDel; drop table #SalePersonPermissionUpd; drop table #ContactPersonPermissionUpd; drop table #RelationshipPersonPermissionUpd; COMMIT TRANSACTION; END

/*Добавление пермишенов категрии "Без категрии" всем лидам у котороых нет категориии*/ CREATE procedure [AddDefaultCategoriesLead] AS BEGIN
declare @insCounter bigint, @insStartId bigint, @insEndId bigint; declare @usermask bigint set @usermask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55
declare @PermissionRoleTypeResponsible uniqueidentifier = 'CE4D6154-E36E-406b-8BE9-25266C5BDD15'; declare @CRMContractorCreateElementPermissionId uniqueidentifier= '44ED88D4-A466-4fed-B194-B8288560CB48'; declare @CRMContractorIssuancePermissionId uniqueidentifier= '1CD25727-7CE6-443c-84BD-7975822C79E6'; declare @ViewContractorPermissionId uniqueidentifier= '9219C9AB-7E68-47B1-8939-FF6FC4439DA0'; declare @EditContractorPermissionId uniqueidentifier= '8C932B94-2F9C-488E-A36F-949A11C9741E';
declare @CRMContactCreateElementPermissionId uniqueidentifier= 'BCE45C2C-CAE1-41df-8A0A-C54E0409E8B5'; declare @CRMContactIssuancePermissionId uniqueidentifier= '05D9000F-0600-49a6-8AE8-DA1DA72BFCF1'; declare @ViewContactPermissionId uniqueidentifier= '3626682F-B657-419E-9A8E-392C14ABE455'; declare @EditContactPermissionId uniqueidentifier= 'ABC752AD-3623-4F14-A47F-121999890D2C';
declare @CRMSaleIssuancePermissionId uniqueidentifier= 'F2141650-BB6D-4e3a-BB62-C0F071CF8EEA'; declare @ViewSalePermissionId uniqueidentifier= 'AAE16346-B0E6-4949-ACAB-0914C573DE55'; declare @EditSalePermissionId uniqueidentifier= 'AF2CEF4B-F639-49B4-BD88-363F20BD5A74'; declare @CRMSaleCreateElementPermissionId uniqueidentifier= '7DB77821-D6D3-4dd2-AD1B-798330506ADC';
declare @CRMInpaymentCreateElementPermissionId uniqueidentifier= 'D130BB5F-6A26-4e37-B62C-F3B443E3BF53'; declare @ViewInpaymentPermissionId uniqueidentifier = '837FF0F3-03A7-4A17-86EA-A72B3AB4886B'; declare @EditInpaymentPermissionId uniqueidentifier = 'E23802D7-F3B5-431E-A72E-7133C3C9343F'; declare @CRMInpaymentIssuanceElementPermissionId uniqueidentifier = 'ACF5606C-B566-426b-BAEC-E74061095BEB';
declare @CRMRelationshipCreateElementPermissionId uniqueidentifier= 'BA5E9414-B347-4eaa-A019-14D4FA02F5E2'; declare @ViewRelationshipPermissionId uniqueidentifier= '186D4CC4-6924-4848-93AC-6D8DE389CB08'; declare @EditRelationshipPermissionId uniqueidentifier= '0B980531-D097-4EC1-8616-56E6AB15770E'; declare @CRMRelationshipIssuanceElementPermissionId uniqueidentifier= '679876A7-8882-43d4-8FC2-3E7C9DB58ADB'; declare @CRMRelationshipFullAccessPermissionId uniqueidentifier= '38A0AC5D-8D9C-4BB5-BDBA-A0E6CFD43C30';
declare @ViewLeadPermissionId uniqueidentifier= 'C660E4B4-03BF-4315-9600-5086E47653B4'; declare @EditLeadPermissionId uniqueidentifier= 'AE298CD3-A16A-4B55-ACFC-545E4A0EBD48'; declare @CRMLeadCreateElementPermissionId uniqueidentifier= '643FE44B-8192-4615-B853-106CD6F09EDE'; declare @CRMLeadFullAccessPermissionId uniqueidentifier= '90BE803C-7857-4F2D-A8B4-129264504101'; declare @CRMLeadIssuanceElementPermissionId uniqueidentifier= 'E70A9AD1-80B2-4435-80E9-EF8E14B974CE';
declare @PermissionRoleTypeParticipantWork uniqueidentifier = '9A945D2E-BCFA-4AF4-8653-9A67A5ED6386'; declare @PermissionRoleAuthor uniqueidentifier = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92'; declare @PermissionRoleTypeInforms uniqueidentifier = '21888C0C-8BCA-4B26-AF13-4C497EECCED6'; declare @adminUid uniqueidentifier='F0E949BF-4DA4-4C02-B04C-CA61964B4FE8'; declare @adminUser bigint=0; declare @NullUid uniqueidentifier = '00000000-0000-0000-0000-000000000000';
declare @defaultCategory bigint=0; declare @defaultTemplLeadCategory bigint=0; declare @defaultTemplCategory bigint=0;
select @defaultCategory=Id, @defaultTemplCategory=CONTAINERCONTRACTORPERMISSIO, @defaultTemplLeadCategory=CONTAINERLEADPERMISSION from Category where Uid='B53287AB-211B-4498-A054-2776C4D270AD'
select @adminUser=Id from [User] where Uid=@adminUid;
select t.* into #TemplateLeadPermissionDel from TemplateLeadPermission t join Category c on c.ContainerLeadPermission=t.ContainerLead where c.Id=@defaultCategory and AddPermission !=1 and DelPermission!=1
select Id into #templateLeadCount from Lead while (select count(1) from #templateLeadCount)>0 begin select top 100 Id into #templateLeadCountOne from #templateLeadCount
-- Добавить привилегии в лида create table #LeadPersonPermissionUpd( [Uid] [uniqueidentifier] NULL, [PermissionId] [uniqueidentifier] NULL, [User] [bigint] NULL, [Group] [bigint] NULL, [OrganizationItemPosition] [bigint] NULL, [UserSecuritySetCacheId] [bigint] NULL, [PermissionRole] [uniqueidentifier] NULL, [OrganizationItemEmployee] [bigint] NULL, [Lead] [bigint] NULL, [Ins] [int], [Child] [bigint], [Iteration] [int] NULL DEFAULT ((0)), [Id] [bigint] NOT NULL DEFAULT ((0)));
-- Добавить недостающие привилегии в взаимоотношение insert into #LeadPersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Lead,UserSecuritySetCacheId,OrganizationItemPosition,Ins,Child) select (ROW_NUMBER() OVER (ORDER BY t.PermissionId))-1, t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition,1,count(1) as Child from Lead c join #TemplateLeadPermissionDel t on 1=1-- взяди мермишены которые надо обновить из контейнера left outer join LeadPersonPermission cp on cp.Lead=c.Id and cp.PermissionId=t.PermissionId and case cp.PermissionRole when @PermissionRoleAuthor then (@adminUser|@usermask) when @PermissionRoleTypeResponsible then (@adminUser|@usermask) ELSE cp.userSecuritySetCacheId end=t.userSecuritySetCacheId and cp.PermissionRole=t.PermissionRole and cp.InheritedFromNumber > 0 left join Category ca on ca.ContainerLeadPermission=t.ContainerLead -- втащили категорию в которую входит пермишен из контейнера where c.Id in (select Id from #templateLeadCountOne) -- соединили категории из контейнера и из контрагента and c.InheritPermissions>=1 and cp.Lead is null and c.Id in (select distinct c.[Id] from [Lead] c left join [M_Lead_Categories] cc on cc.[LeadId]=c.[Id] where cc.[CategoryId] is null) group by t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id,t.UserSecuritySetCacheId ,t.OrganizationItemPosition
select @insCounter=max([Id]) from #LeadPersonPermissionUpd /*Добавить пермишены реальных пользователей для исполнителей*/ insert into #LeadPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,1 [Ins],c.[Child] from [M_Lead_ParticipantWork] m left join #LeadPersonPermissionUpd c on m.Parent=c.Lead where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Lead],c.[Child]
select @insCounter=max([Id]) from #LeadPersonPermissionUpd;
insert into #LeadPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,[Ins],[Child]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[Child] [User] ,[Group] ,[OrganizationItemPosition] ,m.[Child]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Lead] ,1 [Ins],c.[Child] from [M_Lead_Informs] m left join #LeadPersonPermissionUpd c on m.Parent=c.Lead where PermissionRole in (@PermissionRoleTypeInforms) and [User]=@adminUser and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[Child],[Lead],c.[Child]
/*Перезаписать реальных пользователей в ответственных */ update #LeadPersonPermissionUpd set [User]= (select Responsible from Lead con where con.[Id]=Lead), [UserSecuritySetCacheId]= (select (Responsible|@usermask) from Lead con where con.[Id]=Lead) where PermissionRole=@PermissionRoleTypeResponsible
/*Перезаписать реальных пользователей в ответственных */ update #LeadPersonPermissionUpd set [User]= (select [CreationAuthor] from Lead con where con.[Id]=Lead), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Lead con where con.[Id]=Lead) where PermissionRole=@PermissionRoleAuthor;
set @insStartId=0;
select @insCounter=count(1) from #LeadPersonPermissionUpd EXECUTE [G_GenId] 'LeadPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into LeadPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Lead,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + [Id] as Id, t.PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Lead,t.UserSecuritySetCacheId,NEWID() as Uid,Child as InheritedFromNumber,t.OrganizationItemPosition from #LeadPersonPermissionUpd t where Ins=1
-- Добавить привилегии к взаимоотношениям
select - 1 as [Id], CASE WHEN c.PermissionId= @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN c.PermissionId= @CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipFullAccessPermissionId WHEN c.PermissionId= @ViewLeadPermissionId THEN @ViewRelationshipPermissionId WHEN c.PermissionId= @EditLeadPermissionId THEN @EditRelationshipPermissionId WHEN c.PermissionId= @CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE c.PermissionId END as PermissionId ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,ca.Id Relationship,t.UserSecuritySetCacheId,t.OrganizationItemPosition,0 Ins into #RelationshipPersonPermissionUpd from RelationshipPersonPermission c left join Relationship r on r.id=c.Relationship and r.Lead is not null left join #LeadPersonPermissionUpd t on CASE WHEN t.PermissionId= @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipFullAccessPermissionId WHEN t.PermissionId= @ViewLeadPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditLeadPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END =c.PermissionId and c.UserSecuritySetCacheId=case c.PermissionRole when @PermissionRoleAuthor then ((select [CreationAuthor] from [Relationship] con where con.[Id]=c.[Relationship])|@usermask) when @PermissionRoleTypeResponsible then (select (Relationship|@usermask) from Relationship con where con.[Id]=Relationship) ELSE t.userSecuritySetCacheId end and c.PermissionRole=t.PermissionRole left join Relationship ca on c.Relationship=ca.id and ca.InheritPermissions=1 where c.InheritedFromNumber > 0 and t.userSecuritySetCacheId is not null and r.Lead in (select Id from #templateLeadCountOne);
update c set c.InheritedFromNumber=c.InheritedFromNumber-1 from RelationshipPersonPermission c join #RelationshipPersonPermissionUpd ct on ct.Relationship=c.Id where ct.Relationship=c.Id
-- Добавить недостающие привилегии к взаимоотношениям
insert into #RelationshipPersonPermissionUpd ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,OrganizationItemPosition,Ins) select ROW_NUMBER() over (order by t.[Id]) -1, CASE WHEN t.PermissionId= @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewLeadPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditLeadPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END ,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,c.Id Relationship,t.UserSecuritySetCacheId,t.OrganizationItemPosition,1 Ins from Relationship c left join #LeadPersonPermissionUpd t on t.Lead=c.Lead left outer join RelationshipPersonPermission cp on cp.Relationship=c.Id and cp.InheritedFromNumber > 0 and CASE WHEN t.PermissionId= @CRMLeadCreateElementPermissionId THEN @CRMRelationshipCreateElementPermissionId WHEN t.PermissionId= @CRMLeadIssuanceElementPermissionId THEN @CRMRelationshipIssuanceElementPermissionId WHEN t.PermissionId= @ViewLeadPermissionId THEN @ViewRelationshipPermissionId WHEN t.PermissionId= @EditLeadPermissionId THEN @EditRelationshipPermissionId WHEN t.PermissionId= @CRMLeadFullAccessPermissionId THEN @CRMRelationshipFullAccessPermissionId ELSE t.PermissionId END = cp.PermissionId and cp.UserSecuritySetCacheId=t.UserSecuritySetCacheId and cp.PermissionRole=t.PermissionRole where t.Lead is not null and c.InheritPermissions=1 and cp.Relationship is null and c.Lead is not null and t.PermissionRole= case when t.PermissionRole=@PermissionRoleTypeParticipantWork and t.[User]!=@adminUser then @NullUid when t.PermissionRole=@PermissionRoleTypeInforms and t.[User]!=@adminUser then @NullUid else t.PermissionRole end;
select @insCounter=max([Id]) from #RelationshipPersonPermissionUpd /*Добавить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,[Ins]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[UserID] [User] ,[Group] ,[OrganizationItemPosition] ,m.[UserID]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,1 [Ins] from [RelationshipUser] m left join #RelationshipPersonPermissionUpd c on m.RelationshipID=c.Relationship where PermissionRole =@PermissionRoleTypeParticipantWork and [User]=@adminUser and m.[Status]=0 and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]
select @insCounter=max([Id]) from #RelationshipPersonPermissionUpd
/*Добавить пермишены реальных пользователей для исполнителей*/ insert into #RelationshipPersonPermissionUpd ([Id],[PermissionId],[User] ,[Group] ,[OrganizationItemPosition] ,[UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,[Ins]) select (ROW_NUMBER() over (order by c.[Id]) )+@insCounter [Id],[PermissionId] ,m.[UserID] [User] ,[Group] ,[OrganizationItemPosition] ,m.[UserID]|@usermask as [UserSecuritySetCacheId] ,[PermissionRole] ,[OrganizationItemEmployee] ,[Relationship] ,1 [Ins] from [RelationshipUser] m left join #RelationshipPersonPermissionUpd c on m.RelationshipID=c.Relationship where PermissionRole =@PermissionRoleTypeInforms and [User]=@adminUser and m.[Status]=1 and Ins=1 group by c.PermissionId ,c.[User],c.[Group],c.PermissionRole,c.OrganizationItemEmployee,c.Id,c.UserSecuritySetCacheId ,c.OrganizationItemPosition,m.[UserID],[Relationship]
/*Перезаписать реальных пользователей в ответственных */ update #RelationshipPersonPermissionUpd set [User]= (select [CreationAuthor] from Relationship con where con.[Id]=Relationship), [UserSecuritySetCacheId]= (select (CreationAuthor|@usermask) from Relationship con where con.[Id]=Relationship) where PermissionRole=@PermissionRoleAuthor;
delete from #RelationshipPersonPermissionUpd from #RelationshipPersonPermissionUpd c where Ins=1 and exists (select 1 from RelationshipPersonPermission k where k.PermissionRole =c.PermissionRole and k.[User]=c.[User] and c.Relationship=k.Relationship and c.PermissionId=k.PermissionId)
set @insStartId=0;
select @insCounter=count(1) from #RelationshipPersonPermissionUpd EXECUTE [G_GenId] 'RelationshipPersonPermission', @insCounter, @insStartId out, @insEndId out;
insert into RelationshipPersonPermission ([Id],PermissionId,[User],[Group],PermissionRole,OrganizationItemEmployee,Relationship,UserSecuritySetCacheId,Uid,InheritedFromNumber,OrganizationItemPosition) select @insStartId + (ROW_NUMBER() over (order by t.[Id]) ) as Id,t.PermissionId,t.[User],t.[Group],t.PermissionRole,t.OrganizationItemEmployee,Relationship,t.UserSecuritySetCacheId,NEWID(),1 ,t.OrganizationItemPosition from #RelationshipPersonPermissionUpd t where Ins=1
drop table #LeadPersonPermissionUpd; drop table #RelationshipPersonPermissionUpd;
delete from #templateLeadCount where Id in (select Id from #templateLeadCountOne)
drop table #templateLeadCountOne end drop table #TemplateLeadPermissionDel; drop table #templateLeadCount;
END
